window.trendingPapers = {
    "today": [{"paper": {"id": "2606.28322", "authors": [{"_id": "6a4268220dbbc53604b66c30", "name": "Yana Wei", "hidden": false}, {"_id": "6a4268220dbbc53604b66c31", "name": "Hongbo Peng", "hidden": false}, {"_id": "6a4268220dbbc53604b66c32", "name": "Yanlin Lai", "hidden": false}, {"_id": "6a4268220dbbc53604b66c33", "name": "Liang Zhao", "hidden": false}, {"_id": "6a4268220dbbc53604b66c34", "name": "Kangheng Lin", "hidden": false}, {"_id": "6a4268220dbbc53604b66c35", "name": "En Yu", "hidden": false}, {"_id": "6a4268220dbbc53604b66c36", "name": "Keyu Lv", "hidden": false}, {"_id": "6a4268220dbbc53604b66c37", "name": "Han Zhou", "hidden": false}, {"_id": "6a4268220dbbc53604b66c38", "name": "Yin Tang", "hidden": false}, {"_id": "6a4268220dbbc53604b66c39", "name": "Haodong Li", "hidden": false}, {"_id": "6a4268220dbbc53604b66c3a", "name": "Mitt Huang", "hidden": false}, {"_id": "6a4268220dbbc53604b66c3b", "name": "Hangyu Guo", "hidden": false}, {"_id": "6a4268220dbbc53604b66c3c", "name": "Jianjian Sun", "hidden": false}, {"_id": "6a4268220dbbc53604b66c3d", "name": "Zheng Ge", "hidden": false}, {"_id": "6a4268220dbbc53604b66c3e", "name": "Xiangyu Zhang", "hidden": false}, {"_id": "6a4268220dbbc53604b66c3f", "name": "Daxin Jiang", "hidden": false}, {"_id": "6a4268220dbbc53604b66c40", "name": "Vishal M. Patel", "hidden": false}], "publishedAt": "2026-06-26T00:00:00.000Z", "submittedOnDailyAt": "2026-07-02T00:00:00.000Z", "title": "PerceptionRubrics: Calibrating Multimodal Evaluation to Human Perception", "submittedOnDailyBy": {"_id": "64ae4d62179421d320b67c26", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64ae4d62179421d320b67c26/nz-tY6hX7mcDzhdtBmG8K.jpeg", "isPro": false, "fullname": "Yana Wei", "user": "llwswyn", "type": "user", "name": "llwswyn"}, "summary": "We introduce PerceptionRubrics, a rubric-based evaluation framework that addresses the gap between saturated benchmark scores and real-world brittleness. Shifting evaluation from holistic semantic matching to rigorous atomic auditing, PerceptionRubrics pairs 1,038 information-dense images with over 12,000 instance-specific rubrics. These criteria are derived from golden captions constructed via a novel Circular Peer-Review consensus pipeline and then distilled into a dual-stream system of Must-Right (essential facts) and Easy-Wrong (fine-grained details) rubrics. Crucially, PerceptionRubrics implements a Gated Scoring mechanism: unlike linear averages, failure on mandatory visual facts triggers sharp binary penalties. Extensive evaluation yields critical insights: (1) The Reliability Gap: models often verify fragmented elements correctly yet fail strict conjunctive constraints, exposing brittleness in dense domains; (2) Open-Closed Stratification: contrary to reasoning trends, we reveal a persistent 8% perception deficit between open-source and proprietary frontiers; and (3) Human-Aligned Rigor: our gated metrics substantially out-align conventional benchmarks, validating that strict perceptual fidelity is the prerequisite for reliable generation.", "upvotes": 34, "discussionId": "6a4268230dbbc53604b66c41", "projectPage": "https://weiyana.github.io/PerceptionRubrics/", "githubRepo": "https://github.com/M1chaelPeng/PerceptionRubrics", "githubRepoAddedBy": "user", "ai_summary": "PerceptionRubrics presents a rubric-based evaluation framework that identifies gaps between benchmark scores and real-world performance through atomic auditing and gated scoring mechanisms.", "ai_keywords": ["rubric-based evaluation", "atomic auditing", "golden captions", "Circular Peer-Review consensus", "dual-stream system", "Must-Right", "Easy-Wrong", "gated scoring mechanism", "Reliability Gap", "Open-Closed Stratification", "human-aligned rigor"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 9, "organization": {"_id": "653945b47ba797097a7b4eab", "name": "JohnsHopkins", "fullname": "Johns Hopkins University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/653944e58e687a41625a4694/qqHzBOarppVrUuZbbjqwh.png"}, "summary_zh": "<ul>\n    <li>PerceptionRubrics\u662f\u4e00\u4e2a\u57fa\u4e8e\u8bc4\u4f30\u6807\u51c6\u7684\u6846\u67b6\uff0c\u65e8\u5728\u89e3\u51b3\u57fa\u51c6\u5206\u6570\u8fc7\u9ad8\u4e0e\u73b0\u5b9e\u4e16\u754c\u8868\u73b0\u4e0d\u4f73\u4e4b\u95f4\u7684\u5dee\u8ddd\u3002</li>\n    <li>\u8be5\u6846\u67b6\u4f7f\u75281,038\u5f20\u4fe1\u606f\u4e30\u5bcc\u7684\u56fe\u50cf\u548c\u8d85\u8fc712,000\u4e2a\u7279\u5b9a\u5b9e\u4f8b\u7684\u8bc4\u4f30\u6807\u51c6\u8fdb\u884c\u8bc4\u4f30\u3002</li>\n    <li>\u8bc4\u4f30\u6807\u51c6\u5206\u4e3a\u201c\u5fc5\u987b\u6b63\u786e\u201d\uff08\u91cd\u8981\u4e8b\u5b9e\uff09\u548c\u201c\u5bb9\u6613\u9519\u8bef\u201d\uff08\u7ec6\u8282\uff09\u4e24\u90e8\u5206\uff0c\u901a\u8fc7\u65b0\u7684\u5faa\u73af\u540c\u884c\u8bc4\u5ba1\u65b9\u6cd5\u751f\u6210\u3002</li>\n    <li>PerceptionRubrics\u91c7\u7528\u4e00\u79cd\u65b0\u7684\u8bc4\u5206\u673a\u5236\uff0c\u5bf9\u4e8e\u5fc5\u9700\u7684\u89c6\u89c9\u4e8b\u5b9e\uff0c\u5982\u679c\u5224\u65ad\u9519\u8bef\u4f1a\u53d7\u5230\u4e25\u5389\u7684\u60e9\u7f5a\u3002</li>\n    <li>\u8bc4\u4f30\u7ed3\u679c\u663e\u793a\uff0c\u6a21\u578b\u5728\u590d\u6742\u9886\u57df\u4e2d\u5b58\u5728\u53ef\u9760\u6027\u7f3a\u53e3\uff0c\u5f00\u6e90\u4e0e\u4e13\u6709\u6a21\u578b\u4e4b\u95f4\u5b58\u57288%\u7684\u611f\u77e5\u5dee\u8ddd\uff0c\u4e14\u4e25\u683c\u7684\u611f\u77e5\u51c6\u786e\u6027\u662f\u53ef\u9760\u751f\u6210\u7684\u524d\u63d0\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>PerceptionRubrics is a new evaluation system designed to better assess how models perform in real-world situations, rather than just on standard tests.</li>\n    <li>It uses 1,038 detailed images and over 12,000 specific criteria to evaluate performance, focusing on both essential facts and finer details.</li>\n    <li>The scoring system is strict; if a model misses key visual facts, it receives significant penalties instead of just a small deduction.</li>\n    <li>Findings show that models can recognize parts correctly but struggle with complete tasks, highlighting weaknesses in complex scenarios.</li>\n    <li>PerceptionRubrics shows that open-source models lag behind proprietary ones by 8% and that strict evaluation criteria lead to better alignment with human expectations.</li>\n</ul>"}, "publishedAt": "2026-06-25T20:00:00.000Z", "title": "PerceptionRubrics: Calibrating Multimodal Evaluation to Human Perception", "summary": "We introduce PerceptionRubrics, a rubric-based evaluation framework that addresses the gap between saturated benchmark scores and real-world brittleness. Shifting evaluation from holistic semantic matching to rigorous atomic auditing, PerceptionRubrics pairs 1,038 information-dense images with over 12,000 instance-specific rubrics. These criteria are derived from golden captions constructed via a novel Circular Peer-Review consensus pipeline and then distilled into a dual-stream system of Must-Right (essential facts) and Easy-Wrong (fine-grained details) rubrics. Crucially, PerceptionRubrics implements a Gated Scoring mechanism: unlike linear averages, failure on mandatory visual facts triggers sharp binary penalties. Extensive evaluation yields critical insights: (1) The Reliability Gap: models often verify fragmented elements correctly yet fail strict conjunctive constraints, exposing brittleness in dense domains; (2) Open-Closed Stratification: contrary to reasoning trends, we reveal a persistent 8% perception deficit between open-source and proprietary frontiers; and (3) Human-Aligned Rigor: our gated metrics substantially out-align conventional benchmarks, validating that strict perceptual fidelity is the prerequisite for reliable generation.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.28322.png", "numComments": 2, "submittedBy": {"_id": "64ae4d62179421d320b67c26", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64ae4d62179421d320b67c26/nz-tY6hX7mcDzhdtBmG8K.jpeg", "fullname": "Yana Wei", "name": "llwswyn", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 8, "isUserFollowing": false}, "organization": {"_id": "653945b47ba797097a7b4eab", "name": "JohnsHopkins", "fullname": "Johns Hopkins University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/653944e58e687a41625a4694/qqHzBOarppVrUuZbbjqwh.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2607.00466", "authors": [{"_id": "6a45c7664f1dd35e48fb8eb0", "name": "Sangjin Choi", "hidden": false}, {"_id": "6a45c7664f1dd35e48fb8eb1", "name": "Sukmin Cho", "hidden": false}, {"_id": "6a45c7664f1dd35e48fb8eb2", "name": "Yifan Xiong", "hidden": false}, {"_id": "6a45c7664f1dd35e48fb8eb3", "name": "Ziyue Yang", "hidden": false}, {"_id": "6a45c7664f1dd35e48fb8eb4", "name": "Youngjin Kwon", "hidden": false}, {"_id": "6a45c7664f1dd35e48fb8eb5", "name": "Peng Cheng", "hidden": false}], "publishedAt": "2026-07-01T00:00:00.000Z", "submittedOnDailyAt": "2026-07-02T00:00:00.000Z", "title": "ELDR: Expert-Locality-Aware Decode Routing for PD-Disaggregated MoE Serving", "submittedOnDailyBy": {"_id": "64ec4c04c782d648d28d70fc", "avatarUrl": "/avatars/6975526fcf4b513cc934b5bc45370a48.svg", "isPro": false, "fullname": "Sukmin Cho", "user": "zomss", "type": "user", "name": "zomss"}, "summary": "In prefill-decode (PD) disaggregated LLM serving, each request is assigned to a decode worker after prefill. Existing decode routers balance only load; for mixture-of-experts (MoE) models this is incomplete: equally loaded workers can differ in latency, since each decode step loads the weights of every distinct expert its batch activates. We present ELDR, an expert-locality-aware decode router for PD-disaggregated MoE serving. From a request's prefill expert activations, ELDR builds an expert signature predicting the experts it will activate during generation. Offline, balanced K-means partitions signature space across decode workers; online, locality-band routing sends each request to the least-loaded worker among those best matching its signature. A signature cache, co-indexed with the KV cache at KV-block granularity, keeps signatures exact under prefix caching. Implemented in vLLM and evaluated on deployments of up to 40 GPUs, ELDR reduces median TPOT by 5.9-13.9% over the strongest of four load-balancing baselines across three MoE models and two workloads, with model outputs unchanged.", "upvotes": 19, "discussionId": "6a45c7664f1dd35e48fb8eb6", "ai_summary": "ELDR is an expert-locality-aware decode router for prefill-decode disaggregated Mixture-of-Experts serving that improves performance by predicting expert activations and routing requests accordingly.", "ai_keywords": ["prefill-decode", "disaggregated LLM serving", "mixture-of-experts", "decode router", "expert-locality-aware", "K-means", "locality-band routing", "signature cache", "KV cache", "vLLM", "TPOT"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "68151d0f51add3813f3f7d1b", "name": "MicrosoftResearch", "fullname": "Microsoft Research", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6529a4f2f1205983224fa513/PeuVr7jSuJflmDBBGxoDX.png"}, "summary_zh": "<ul>\n    <li>\u4ecb\u7ecd\u4e86\u4e00\u79cd\u540d\u4e3aELDR\u7684\u89e3\u7801\u8def\u7531\u5668\uff0c\u65e8\u5728\u4f18\u5316\u9884\u586b\u5145-\u89e3\u7801\uff08PD\uff09\u5206\u79bb\u5f0f\u5927\u8bed\u8a00\u6a21\u578b\uff08LLM\uff09\u7684\u670d\u52a1\u3002</li>\n    <li>\u73b0\u6709\u7684\u89e3\u7801\u8def\u7531\u5668\u53ea\u5173\u6ce8\u8d1f\u8f7d\u5747\u8861\uff0c\u4f46\u5bf9\u4e8e\u6df7\u5408\u4e13\u5bb6\uff08MoE\uff09\u6a21\u578b\u6765\u8bf4\uff0c\u8fd9\u79cd\u65b9\u6cd5\u4e0d\u591f\u5168\u9762\uff0c\u56e0\u4e3a\u4e0d\u540c\u7684\u5de5\u4f5c\u8005\u5728\u5ef6\u8fdf\u4e0a\u53ef\u80fd\u5b58\u5728\u5dee\u5f02\u3002</li>\n    <li>ELDR\u901a\u8fc7\u5206\u6790\u8bf7\u6c42\u7684\u9884\u586b\u5145\u4e13\u5bb6\u6fc0\u6d3b\u60c5\u51b5\u6765\u9884\u6d4b\u751f\u6210\u8fc7\u7a0b\u4e2d\u5c06\u6fc0\u6d3b\u7684\u4e13\u5bb6\uff0c\u5e76\u636e\u6b64\u8fdb\u884c\u8def\u7531\u3002</li>\n    <li>\u4f7f\u7528K\u5747\u503c\u7b97\u6cd5\u4e3a\u89e3\u7801\u5de5\u4f5c\u8005\u5212\u5206\u4e13\u5bb6\u7b7e\u540d\u7a7a\u95f4\uff0c\u5e76\u6839\u636e\u8bf7\u6c42\u7684\u7b7e\u540d\u9009\u62e9\u8d1f\u8f7d\u6700\u8f7b\u7684\u5de5\u4f5c\u8005\u8fdb\u884c\u5904\u7406\u3002</li>\n    <li>\u5728\u6700\u591a40\u4e2aGPU\u7684\u90e8\u7f72\u4e2d\uff0cELDR\u7684\u4e2d\u4f4d\u6570TPOT\uff08\u6bcf\u79d2\u751f\u6210\u7684\u4ee4\u724c\u6570\uff09\u6bd4\u56db\u79cd\u8d1f\u8f7d\u5747\u8861\u57fa\u51c6\u51cf\u5c11\u4e865.9%-13.9%\uff0c\u540c\u65f6\u6a21\u578b\u8f93\u51fa\u4fdd\u6301\u4e0d\u53d8\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>In a system for serving large language models (LLMs), each request is handled by a specific worker after some initial processing.</li>\n    <li>Current methods only focus on balancing the workload among workers, but this doesn't account for differences in how long each worker takes to respond.</li>\n    <li>ELDR is a new method that considers which experts (specialized parts of the model) will be used for each request, aiming to send requests to the fastest workers.</li>\n    <li>It creates a profile for each request based on expected expert usage and uses this to route requests more efficiently.</li>\n    <li>Tests show that ELDR can reduce response times significantly while keeping the results the same as before.</li>\n</ul>"}, "publishedAt": "2026-06-30T20:00:00.000Z", "title": "ELDR: Expert-Locality-Aware Decode Routing for PD-Disaggregated MoE Serving", "summary": "In prefill-decode (PD) disaggregated LLM serving, each request is assigned to a decode worker after prefill. Existing decode routers balance only load; for mixture-of-experts (MoE) models this is incomplete: equally loaded workers can differ in latency, since each decode step loads the weights of every distinct expert its batch activates. We present ELDR, an expert-locality-aware decode router for PD-disaggregated MoE serving. From a request's prefill expert activations, ELDR builds an expert signature predicting the experts it will activate during generation. Offline, balanced K-means partitions signature space across decode workers; online, locality-band routing sends each request to the least-loaded worker among those best matching its signature. A signature cache, co-indexed with the KV cache at KV-block granularity, keeps signatures exact under prefix caching. Implemented in vLLM and evaluated on deployments of up to 40 GPUs, ELDR reduces median TPOT by 5.9-13.9% over the strongest of four load-balancing baselines across three MoE models and two workloads, with model outputs unchanged.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.00466.png", "numComments": 2, "submittedBy": {"_id": "64ec4c04c782d648d28d70fc", "avatarUrl": "/avatars/6975526fcf4b513cc934b5bc45370a48.svg", "fullname": "Sukmin Cho", "name": "zomss", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2, "isUserFollowing": false}, "organization": {"_id": "68151d0f51add3813f3f7d1b", "name": "MicrosoftResearch", "fullname": "Microsoft Research", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6529a4f2f1205983224fa513/PeuVr7jSuJflmDBBGxoDX.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.19271", "authors": [{"_id": "6a45d65f4f1dd35e48fb8f3a", "name": "Youhe Jiang", "hidden": false}, {"_id": "6a45d65f4f1dd35e48fb8f3b", "name": "Haoxu Wang", "hidden": false}, {"_id": "6a45d65f4f1dd35e48fb8f3c", "name": "Haotong Bao", "hidden": false}, {"_id": "6a45d65f4f1dd35e48fb8f3d", "name": "Kai Jiang", "hidden": false}, {"_id": "6a45d65f4f1dd35e48fb8f3e", "name": "Jianfei Chen", "hidden": false}, {"_id": "6a45d65f4f1dd35e48fb8f3f", "name": "Jun Zhu", "hidden": false}, {"_id": "6a45d65f4f1dd35e48fb8f40", "name": "Fangcheng Fu", "hidden": false}, {"_id": "6a45d65f4f1dd35e48fb8f41", "name": "Jintao Zhang", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/66c0a08bac74db25de8427ec/KHBp7rjcUIsLCgUSwHGJ6.png"], "publishedAt": "2026-06-17T00:00:00.000Z", "submittedOnDailyAt": "2026-07-02T00:00:00.000Z", "title": "TurboServe: Serving Streaming Video Generation Efficiently and Economically", "submittedOnDailyBy": {"_id": "66c0a08bac74db25de8427ec", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/66c0a08bac74db25de8427ec/9D-piDBZqSt6KNkHImmkv.jpeg", "isPro": false, "fullname": "Jintao Zhang", "user": "jt-zhang", "type": "user", "name": "jt-zhang"}, "summary": "Streaming video generation is emerging as a new serving workload in which users interact with long-lived sessions that generate video progressively, chunk by chunk. Unlike offline video generation or typical LLM serving, streaming video generation must preserve session state across active and idle periods, repeatedly schedule ongoing sessions, and deliver each chunk under a tight latency target. This creates two key serving challenges in multi-user, multi-GPU environments: session duration heterogeneity, where long-running sessions make placement decisions suboptimal over time, and temporal user-demand heterogeneity, where the number of active sessions fluctuates sharply across bursts and idle periods.\n  We present TurboServe, the first serving system designed specifically for streaming video generation workloads. TurboServe formulates serving as an online scheduling problem that jointly coordinates session placement and GPU provisioning. Its closed-loop scheduling algorithm combines a migration-aware placement controller, which rebalances sessions across GPUs to reduce the maximum per-chunk latency, with a load-driven autoscaling controller, which adapts the GPU budget to workload variation for improved cost efficiency. To support these decisions at runtime, TurboServe implements coalesced chunk processing for batching concurrent active sessions on the same GPU, GPU-CPU offloading for session suspension and resumption, and NCCL-based GPU-GPU migration for online rebalancing. We evaluate TurboServe on real-world production traces from Shengshu Technology across multiple model sizes and GPU clusters with up to 64 NVIDIA B300 GPUs. Compared with baseline serving configurations, TurboServe reduces worst-case per-chunk latency by 37.5% and total GPU operating cost by 37.2% on average. Our code is publicly available at https://github.com/shengshu-ai/TurboServe.", "upvotes": 19, "discussionId": "6a45d6604f1dd35e48fb8f42", "projectPage": "https://github.com/shengshu-ai/TurboServe", "githubRepo": "https://github.com/shengshu-ai/TurboServe", "githubRepoAddedBy": "user", "ai_summary": "TurboServe is a specialized serving system for streaming video generation that addresses session state management and dynamic resource allocation challenges through integrated scheduling, autoscaling, and migration mechanisms.", "ai_keywords": ["streaming video generation", "session state preservation", "online scheduling", "GPU provisioning", "closed-loop scheduling", "migration-aware placement", "load-driven autoscaling", "coalesced chunk processing", "GPU-CPU offloading", "NCCL-based GPU-GPU migration"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 14, "organization": {"_id": "628735cbc83a2d6ab8d14a66", "name": "Tsinghua", "fullname": "Tsinghua University", "avatar": "https://www.gravatar.com/avatar/6c5c1441e3283e7543342e59277ea219?d=retro&size=100"}, "summary_zh": "<ul>\n    <li>\u6d41\u5a92\u4f53\u89c6\u9891\u751f\u6210\u662f\u7528\u6237\u901a\u8fc7\u957f\u671f\u4f1a\u8bdd\u9010\u6b65\u751f\u6210\u89c6\u9891\u7684\u65b0\u5de5\u4f5c\u8d1f\u8f7d\u3002</li>\n    <li>TurboServe\u662f\u4e13\u4e3a\u6d41\u5a92\u4f53\u89c6\u9891\u751f\u6210\u8bbe\u8ba1\u7684\u7b2c\u4e00\u4e2a\u670d\u52a1\u7cfb\u7edf\uff0c\u89e3\u51b3\u4f1a\u8bdd\u72b6\u6001\u7ba1\u7406\u548c\u5ef6\u8fdf\u95ee\u9898\u3002</li>\n    <li>\u5b83\u91c7\u7528\u5728\u7ebf\u8c03\u5ea6\u7b97\u6cd5\uff0c\u534f\u8c03\u4f1a\u8bdd\u5206\u914d\u548cGPU\u8d44\u6e90\u914d\u7f6e\uff0c\u4ee5\u964d\u4f4e\u5ef6\u8fdf\u548c\u6210\u672c\u3002</li>\n    <li>TurboServe\u7684\u8bc4\u4f30\u7ed3\u679c\u663e\u793a\uff0c\u4e0e\u57fa\u7ebf\u914d\u7f6e\u76f8\u6bd4\uff0c\u6700\u574f\u60c5\u51b5\u6bcf\u6bb5\u89c6\u9891\u7684\u5ef6\u8fdf\u51cf\u5c11\u4e8637.5%\uff0c\u603bGPU\u8fd0\u8425\u6210\u672c\u964d\u4f4e\u4e8637.2%\u3002</li>\n    <li>TurboServe\u7684\u6e90\u4ee3\u7801\u53ef\u4ee5\u5728GitHub\u4e0a\u516c\u5f00\u83b7\u53d6\u3002</li>\n</ul>", "summary_simple": "<ul>\n  <li>TurboServe is a new system designed for streaming video generation, where videos are created in small parts during user sessions.</li>\n  <li>The system addresses challenges like varying session lengths and fluctuating user demand in multi-user, multi-GPU environments.</li>\n  <li>It uses a special scheduling method that optimizes how sessions are placed on GPUs and manages GPU resources to improve efficiency and reduce delays.</li>\n  <li>TurboServe includes features for processing video chunks together, managing session pauses, and transferring sessions between GPUs to keep performance steady.</li>\n  <li>In tests, TurboServe significantly reduced video delay and GPU costs compared to other setups, making it more efficient for streaming applications.</li>\n</ul>"}, "publishedAt": "2026-06-16T20:00:00.000Z", "title": "TurboServe: Serving Streaming Video Generation Efficiently and Economically", "summary": "Streaming video generation is emerging as a new serving workload in which users interact with long-lived sessions that generate video progressively, chunk by chunk. Unlike offline video generation or typical LLM serving, streaming video generation must preserve session state across active and idle periods, repeatedly schedule ongoing sessions, and deliver each chunk under a tight latency target. This creates two key serving challenges in multi-user, multi-GPU environments: session duration heterogeneity, where long-running sessions make placement decisions suboptimal over time, and temporal user-demand heterogeneity, where the number of active sessions fluctuates sharply across bursts and idle periods.\n  We present TurboServe, the first serving system designed specifically for streaming video generation workloads. TurboServe formulates serving as an online scheduling problem that jointly coordinates session placement and GPU provisioning. Its closed-loop scheduling algorithm combines a migration-aware placement controller, which rebalances sessions across GPUs to reduce the maximum per-chunk latency, with a load-driven autoscaling controller, which adapts the GPU budget to workload variation for improved cost efficiency. To support these decisions at runtime, TurboServe implements coalesced chunk processing for batching concurrent active sessions on the same GPU, GPU-CPU offloading for session suspension and resumption, and NCCL-based GPU-GPU migration for online rebalancing. We evaluate TurboServe on real-world production traces from Shengshu Technology across multiple model sizes and GPU clusters with up to 64 NVIDIA B300 GPUs. Compared with baseline serving configurations, TurboServe reduces worst-case per-chunk latency by 37.5% and total GPU operating cost by 37.2% on average. Our code is publicly available at https://github.com/shengshu-ai/TurboServe.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/66c0a08bac74db25de8427ec/KHBp7rjcUIsLCgUSwHGJ6.png"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.19271.png", "numComments": 1, "submittedBy": {"_id": "66c0a08bac74db25de8427ec", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/66c0a08bac74db25de8427ec/9D-piDBZqSt6KNkHImmkv.jpeg", "fullname": "Jintao Zhang", "name": "jt-zhang", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 53, "isUserFollowing": false}, "organization": {"_id": "628735cbc83a2d6ab8d14a66", "name": "Tsinghua", "fullname": "Tsinghua University", "avatar": "https://www.gravatar.com/avatar/6c5c1441e3283e7543342e59277ea219?d=retro&size=100"}, "isAuthorParticipating": false}, {"paper": {"id": "2607.01071", "authors": [{"_id": "6a45cc034f1dd35e48fb8ee2", "name": "Zhishang Xiang", "hidden": false}, {"_id": "6a45cc034f1dd35e48fb8ee3", "name": "Zerui Chen", "hidden": false}, {"_id": "6a45cc034f1dd35e48fb8ee4", "name": "Yunbo Tang", "hidden": false}, {"_id": "6a45cc034f1dd35e48fb8ee5", "name": "Zhimin Wei", "hidden": false}, {"_id": "6a45cc034f1dd35e48fb8ee6", "name": "Ruqin Ning", "hidden": false}, {"_id": "6a45cc034f1dd35e48fb8ee7", "name": "Yujie Lin", "hidden": false}, {"_id": "6a45cc034f1dd35e48fb8ee8", "name": "Qinggang Zhang", "hidden": false}, {"_id": "6a45cc034f1dd35e48fb8ee9", "name": "Jinsong Su", "hidden": false}], "publishedAt": "2026-07-01T00:00:00.000Z", "submittedOnDailyAt": "2026-07-02T00:00:00.000Z", "title": "MemSyco-Bench: Benchmarking Sycophancy in Agent Memory", "submittedOnDailyBy": {"_id": "6a1d4ae0e587e00929561155", "avatarUrl": "/avatars/61111db08e710af83f96772f1493dbe9.svg", "isPro": false, "fullname": "tangyunbo", "user": "tangyunbo", "type": "user", "name": "tangyunbo"}, "summary": "Memory has emerged as a cornerstone of modern LLM-based agents, supporting their evolution from single-turn assistants to long-term collaborators. However, memory is not always beneficial: retrieved memories often induce a critical issue of sycophancy, causing agents to over-align with the user at the cost of factual accuracy or objective reasoning. Despite this emerging risk, existing memory benchmarks primarily evaluate whether memories are correctly stored, retrieved, or updated, while overlooking how retrieved memories influence downstream reasoning and decision-making. To bridge this gap, we propose MemSyco-Bench, a comprehensive benchmark for evaluating memory-induced sycophancy in agent systems. MemSyco-Bench measures when memory should influence a decision and how valid memory should be used. Specifically, it covers five tasks that assess whether agents can reject memory as factual evidence, respect its applicable scope, resolve conflicts between memory and objective evidence, track memory updates, and use valid memory for personalization. All related resources are collected for the community at https://github.com/XMUDeepLIT/MemSyco-Bench.", "upvotes": 18, "discussionId": "6a45cc034f1dd35e48fb8eea", "githubRepo": "https://github.com/XMUDeepLIT/MemSyco-Bench", "githubRepoAddedBy": "user", "ai_summary": "Memory plays a crucial role in LLM-based agents, but retrieved memories can cause sycophancy issues where agents over-align with users at the expense of factual accuracy, necessitating new evaluation benchmarks that assess memory's impact on reasoning and decision-making rather than just storage and retrieval.", "ai_keywords": ["memory", "LLM-based agents", "sycophancy", "downstream reasoning", "decision-making", "MemSyco-Bench", "memory-induced sycophancy", "factual accuracy", "objective reasoning", "memory evaluation"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 12, "summary_zh": "<ul>\n    <li>\u8bb0\u5fc6\u5728\u73b0\u4ee3\u57fa\u4e8e\u5927\u578b\u8bed\u8a00\u6a21\u578b\u7684\u4ee3\u7406\u4e2d\u975e\u5e38\u91cd\u8981\uff0c\u5e2e\u52a9\u5b83\u4eec\u4ece\u5355\u4e00\u52a9\u624b\u53d1\u5c55\u4e3a\u957f\u671f\u5408\u4f5c\u4f19\u4f34\u3002</li>\n    <li>\u4f46\u8bb0\u5fc6\u6709\u65f6\u4f1a\u5bfc\u81f4\u95ee\u9898\uff0c\u5982\u8fc7\u5ea6\u8fce\u5408\u7528\u6237\uff0c\u5f71\u54cd\u4e8b\u5b9e\u51c6\u786e\u6027\u548c\u5ba2\u89c2\u63a8\u7406\u3002</li>\n    <li>\u73b0\u6709\u7684\u8bb0\u5fc6\u8bc4\u4f30\u6807\u51c6\u4e3b\u8981\u5173\u6ce8\u8bb0\u5fc6\u7684\u5b58\u50a8\u3001\u68c0\u7d22\u548c\u66f4\u65b0\uff0c\u800c\u5ffd\u89c6\u4e86\u8bb0\u5fc6\u5bf9\u63a8\u7406\u548c\u51b3\u7b56\u7684\u5f71\u54cd\u3002</li>\n    <li>\u4e3a\u4e86\u89e3\u51b3\u8fd9\u4e2a\u95ee\u9898\uff0c\u63d0\u51fa\u4e86MemSyco-Bench\uff0c\u8bc4\u4f30\u4ee3\u7406\u7cfb\u7edf\u4e2d\u7684\u8bb0\u5fc6\u8bf1\u53d1\u7684\u8fce\u5408\u95ee\u9898\u3002</li>\n    <li>MemSyco-Bench\u5305\u62ec\u4e94\u4e2a\u4efb\u52a1\uff0c\u8bc4\u4f30\u4ee3\u7406\u662f\u5426\u80fd\u62d2\u7edd\u4e0d\u51c6\u786e\u7684\u8bb0\u5fc6\u3001\u5904\u7406\u8bb0\u5fc6\u4e0e\u5ba2\u89c2\u8bc1\u636e\u7684\u51b2\u7a81\u7b49\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Memory is important for LLM-based agents, helping them become better collaborators.</li>\n    <li>Sometimes, using memory can lead to sycophancy, where agents overly agree with users and may sacrifice accuracy.</li>\n    <li>Current benchmarks mainly check if memories are stored and retrieved correctly, not how they affect reasoning and decisions.</li>\n    <li>MemSyco-Bench is a new benchmark designed to evaluate memory-induced sycophancy in agent systems.</li>\n    <li>It includes five tasks to test how agents handle memory, including rejecting false memories and using valid ones for personalization.</li>\n</ul>"}, "publishedAt": "2026-06-30T20:00:00.000Z", "title": "MemSyco-Bench: Benchmarking Sycophancy in Agent Memory", "summary": "Memory has emerged as a cornerstone of modern LLM-based agents, supporting their evolution from single-turn assistants to long-term collaborators. However, memory is not always beneficial: retrieved memories often induce a critical issue of sycophancy, causing agents to over-align with the user at the cost of factual accuracy or objective reasoning. Despite this emerging risk, existing memory benchmarks primarily evaluate whether memories are correctly stored, retrieved, or updated, while overlooking how retrieved memories influence downstream reasoning and decision-making. To bridge this gap, we propose MemSyco-Bench, a comprehensive benchmark for evaluating memory-induced sycophancy in agent systems. MemSyco-Bench measures when memory should influence a decision and how valid memory should be used. Specifically, it covers five tasks that assess whether agents can reject memory as factual evidence, respect its applicable scope, resolve conflicts between memory and objective evidence, track memory updates, and use valid memory for personalization. All related resources are collected for the community at https://github.com/XMUDeepLIT/MemSyco-Bench.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.01071.png", "numComments": 1, "submittedBy": {"_id": "6a1d4ae0e587e00929561155", "avatarUrl": "/avatars/61111db08e710af83f96772f1493dbe9.svg", "fullname": "tangyunbo", "name": "tangyunbo", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "isUserFollowing": false}, "isAuthorParticipating": false}, {"paper": {"id": "2607.00461", "authors": [{"_id": "6a460b464f1dd35e48fb9094", "name": "Shijie Li", "hidden": false}, {"_id": "6a460b464f1dd35e48fb9095", "name": "Yilin Gao", "hidden": false}, {"_id": "6a460b464f1dd35e48fb9096", "name": "Siyuan Yang", "hidden": false}, {"_id": "6a460b464f1dd35e48fb9097", "name": "Tieyuan Chen", "hidden": false}, {"_id": "6a460b464f1dd35e48fb9098", "name": "Chaofan Gan", "hidden": false}, {"_id": "6a460b464f1dd35e48fb9099", "name": "Zhihao He", "hidden": false}, {"_id": "6a460b464f1dd35e48fb909a", "name": "Zicheng Zhao", "hidden": false}, {"_id": "6a460b464f1dd35e48fb909b", "name": "Yuyu Guo", "hidden": false}, {"_id": "6a460b464f1dd35e48fb909c", "name": "Weiyao Lin", "hidden": false}, {"_id": "6a460b464f1dd35e48fb909d", "name": "Hang Yu", "hidden": false}], "publishedAt": "2026-07-01T00:00:00.000Z", "submittedOnDailyAt": "2026-07-02T00:00:00.000Z", "title": "Multimodal Continuous Reasoning via Asymmetric Mutual Variational Learning", "submittedOnDailyBy": {"_id": "6837243353739ee0d588d04c", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/no-auth/CYU8xxEHxxGkwNVCpua6X.png", "isPro": false, "fullname": "Hang Yu", "user": "fhlyhv", "type": "user", "name": "fhlyhv"}, "summary": "Multimodal Large Language Models (MLLMs) are often constrained by a language-space bottleneck, forcing complex visual reasoning into discrete tokens which can lose perceptual nuance. A promising alternative is continuous latent reasoning, where the goal is to discover implicit reasoning pathways that bridge the multimodal query and the final answer. However, this introduces a severe train-inference mismatch: a training-time posterior, conditioned on the ground-truth answer, can exploit answer-dependent shortcuts. Standard variational training then forces the inference-time prior to mimic a posterior that has access to information unavailable at test time, leading to poor performance. To address this, we propose Asymmetric Mutual Variational Learning (AMVL), a framework that resolves this mismatch via a bidirectional calibration objective. A forward KL divergence trains the target-agnostic prior to match the posterior, while a novel reverse KL divergence simultaneously regularizes the posterior, preventing it from collapsing into inference-incompatible regions and mitigating this ``answer leakage''. We provide theoretical analysis formalizing this leakage as prior contamination and prove that our dual-KL objective reduces it. We instantiate AMVL in a latent-integrated MLLM and show that it consistently outperforms strong discrete and latent-reasoning baselines, improving the average score on the complex BLINK benchmark by +10.83 and achieving gains of up to +32.00 on individual reasoning tasks, with analyses confirming improved latent-space stability.", "upvotes": 16, "discussionId": "6a460b464f1dd35e48fb909e", "ai_summary": "Asymmetric Mutual Variational Learning addresses train-inference mismatch in multimodal reasoning by using bidirectional calibration to prevent answer leakage and improve latent-space stability.", "ai_keywords": ["Multimodal Large Language Models", "language-space bottleneck", "continuous latent reasoning", "train-inference mismatch", "variational training", "posterior", "prior", "bidirectional calibration", "forward KL divergence", "reverse KL divergence", "answer leakage", "latent-integrated MLLM", "BLINK benchmark"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "summary_zh": "<ul>\n    <li>\u591a\u6a21\u6001\u5927\u8bed\u8a00\u6a21\u578b\uff08MLLMs\uff09\u5728\u5904\u7406\u590d\u6742\u89c6\u89c9\u63a8\u7406\u65f6\u53d7\u5230\u8bed\u8a00\u7a7a\u95f4\u74f6\u9888\u7684\u9650\u5236\uff0c\u53ef\u80fd\u5bfc\u81f4\u611f\u77e5\u7ec6\u8282\u7684\u4e22\u5931\u3002</li>\n    <li>\u8fde\u7eed\u6f5c\u5728\u63a8\u7406\u662f\u4e00\u79cd\u65b0\u65b9\u6cd5\uff0c\u65e8\u5728\u53d1\u73b0\u8fde\u63a5\u591a\u6a21\u6001\u67e5\u8be2\u548c\u6700\u7ec8\u7b54\u6848\u7684\u9690\u542b\u63a8\u7406\u8def\u5f84\u3002</li>\n    <li>\u8bad\u7ec3\u4e0e\u63a8\u7406\u4e4b\u95f4\u5b58\u5728\u4e25\u91cd\u4e0d\u5339\u914d\uff0c\u6807\u51c6\u53d8\u5206\u8bad\u7ec3\u53ef\u80fd\u5bfc\u81f4\u63a8\u7406\u6027\u80fd\u5dee\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u4e0d\u5bf9\u79f0\u4e92\u53d8\u5206\u5b66\u4e60\uff08AMVL\uff09\uff0c\u901a\u8fc7\u53cc\u5411\u6821\u51c6\u76ee\u6807\u89e3\u51b3\u4e86\u8fd9\u4e00\u4e0d\u5339\u914d\u95ee\u9898\u3002</li>\n    <li>AMVL\u5728\u4e00\u4e2a\u6f5c\u5728\u96c6\u6210\u7684MLLM\u4e2d\u5e94\u7528\uff0c\u7ed3\u679c\u5728\u590d\u6742\u7684BLINK\u57fa\u51c6\u4e0a\u5e73\u5747\u5f97\u5206\u63d0\u9ad8\u4e8610.83\uff0c\u4e2a\u522b\u63a8\u7406\u4efb\u52a1\u6700\u9ad8\u63d0\u534732.00\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Multimodal Large Language Models (MLLMs) face challenges in visual reasoning due to limitations in processing language. </li>\n    <li>Continuous latent reasoning is a method that aims to find better reasoning pathways between questions and answers but can create issues when training and testing models.</li>\n    <li>The proposed solution, Asymmetric Mutual Variational Learning (AMVL), addresses these issues by using a special training method to align model behavior during training and testing.</li>\n    <li>AMVL includes techniques to ensure the model does not rely on shortcuts that are only valid during training, which improves its performance.</li>\n    <li>Tests show that AMVL significantly enhances performance on reasoning tasks, achieving notable score improvements on the BLINK benchmark compared to other methods.</li>\n</ul>"}, "publishedAt": "2026-06-30T20:00:00.000Z", "title": "Multimodal Continuous Reasoning via Asymmetric Mutual Variational Learning", "summary": "Multimodal Large Language Models (MLLMs) are often constrained by a language-space bottleneck, forcing complex visual reasoning into discrete tokens which can lose perceptual nuance. A promising alternative is continuous latent reasoning, where the goal is to discover implicit reasoning pathways that bridge the multimodal query and the final answer. However, this introduces a severe train-inference mismatch: a training-time posterior, conditioned on the ground-truth answer, can exploit answer-dependent shortcuts. Standard variational training then forces the inference-time prior to mimic a posterior that has access to information unavailable at test time, leading to poor performance. To address this, we propose Asymmetric Mutual Variational Learning (AMVL), a framework that resolves this mismatch via a bidirectional calibration objective. A forward KL divergence trains the target-agnostic prior to match the posterior, while a novel reverse KL divergence simultaneously regularizes the posterior, preventing it from collapsing into inference-incompatible regions and mitigating this ``answer leakage''. We provide theoretical analysis formalizing this leakage as prior contamination and prove that our dual-KL objective reduces it. We instantiate AMVL in a latent-integrated MLLM and show that it consistently outperforms strong discrete and latent-reasoning baselines, improving the average score on the complex BLINK benchmark by +10.83 and achieving gains of up to +32.00 on individual reasoning tasks, with analyses confirming improved latent-space stability.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.00461.png", "numComments": 3, "submittedBy": {"_id": "6837243353739ee0d588d04c", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/no-auth/CYU8xxEHxxGkwNVCpua6X.png", "fullname": "Hang Yu", "name": "fhlyhv", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 4, "isUserFollowing": false}, "isAuthorParticipating": false}, {"paper": {"id": "2607.00666", "authors": [{"_id": "6a45cccc4f1dd35e48fb8eed", "name": "Taewook Kang", "hidden": false}, {"_id": "6a45cccc4f1dd35e48fb8eee", "name": "Taeheon Kim", "hidden": false}, {"_id": "6a45cccc4f1dd35e48fb8eef", "name": "Donghyun Shin", "hidden": false}, {"_id": "6a45cccc4f1dd35e48fb8ef0", "name": "Jonghyun Choi", "hidden": false}], "publishedAt": "2026-07-01T00:00:00.000Z", "submittedOnDailyAt": "2026-07-02T00:00:00.000Z", "title": "Domain Arithmetic: One-Shot VLA Adaptation under Environmental Shifts", "submittedOnDailyBy": {"_id": "654e14776337c78f3c72e680", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/654e14776337c78f3c72e680/As2L8hOQjUzgjFaMxDcKo.jpeg", "isPro": false, "fullname": "Taewook Kang", "user": "twkang43", "type": "user", "name": "twkang43"}, "summary": "Vision-Language-Action (VLA) models often fail to perform the same learned tasks under environmental shifts, such as changes in camera pose and shifts to a different but similar robot (e.g., from Panda to UR5e). Adapting these models to the shifted environment (i.e., target domain) often requires training on multiple demonstrations for each task, which are costly to collect. To reduce the burden of data curation and training, we propose an analogy-based method that adapts VLA models under environmental shifts through weight vector arithmetic with domain-specific information addition, named Domain ARiThmetic (DART). Unlike prior approaches, DART requires collecting only a single demonstration, enabling efficient adaptation. To accurately isolate domain-specific information for addition, DART performs subspace alignment between singular components in weight vectors to filter out noisy components. In both simulated and real-world experiments, DART outperforms existing VLA adaptation methods in one-shot scenarios across diverse visual and embodiment shifts. Code is available at https://github.com/snumprlab/dart.", "upvotes": 16, "discussionId": "6a45cccc4f1dd35e48fb8ef1", "projectPage": "https://twkang43.github.io/projects/dart/", "githubRepo": "https://github.com/snumprlab/dart", "githubRepoAddedBy": "user", "ai_summary": "Vision-Language-Action models can be efficiently adapted to new environments using a single demonstration through weight vector arithmetic that isolates domain-specific information via subspace alignment.", "ai_keywords": ["Vision-Language-Action models", "domain-specific information", "weight vector arithmetic", "subspace alignment", "one-shot adaptation", "environmental shifts", "embodiment shifts"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 10, "organization": {"_id": "66d54dc8033492801db2bf5a", "name": "SeoulNatlUniv", "fullname": "Seoul National University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/659ccc9d18897eb6594e897f/_-0BM-1UyM-d-lRiahFnf.png"}, "summary_zh": "<ul>\n    <li>\u89c6\u89c9-\u8bed\u8a00-\u52a8\u4f5c\uff08VLA\uff09\u6a21\u578b\u5728\u73af\u5883\u53d8\u5316\u65f6\u8868\u73b0\u4e0d\u4f73\uff0c\u4f8b\u5982\u76f8\u673a\u4f4d\u7f6e\u53d8\u5316\u6216\u4f7f\u7528\u4e0d\u540c\u673a\u5668\u4eba\u3002</li>\n    <li>\u9002\u5e94\u8fd9\u4e9b\u6a21\u578b\u901a\u5e38\u9700\u8981\u591a\u6b21\u793a\u8303\uff0c\u6536\u96c6\u6210\u672c\u9ad8\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u4e00\u79cd\u540d\u4e3aDART\u7684\u65b9\u6cd5\uff0c\u53ea\u9700\u4e00\u4e2a\u793a\u8303\u5373\u53ef\u5728\u73af\u5883\u53d8\u5316\u4e0b\u6709\u6548\u9002\u5e94VLA\u6a21\u578b\u3002</li>\n    <li>DART\u901a\u8fc7\u6743\u91cd\u5411\u91cf\u7b97\u672f\u548c\u9886\u57df\u7279\u5b9a\u4fe1\u606f\u6dfb\u52a0\u6765\u5b9e\u73b0\u9002\u5e94\uff0c\u5e76\u8fc7\u6ee4\u566a\u58f0\u6210\u5206\u3002</li>\n    <li>\u5728\u6a21\u62df\u548c\u771f\u5b9e\u4e16\u754c\u5b9e\u9a8c\u4e2d\uff0cDART\u5728\u5355\u6b21\u793a\u8303\u573a\u666f\u4e0b\u8d85\u8d8a\u4e86\u73b0\u6709\u7684VLA\u9002\u5e94\u65b9\u6cd5\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Vision-Language-Action (VLA) models struggle when the environment changes, like different camera angles or using different robots.</li>\n    <li>Adapting these models usually needs many examples for each task, which can be expensive to gather.</li>\n    <li>The new method called Domain ARiThmetic (DART) allows adaptation with just one example by using weight vector math and adding specific information about the new environment.</li>\n    <li>DART filters out unnecessary noise to focus on important details when adjusting the model.</li>\n    <li>In tests, DART performed better than traditional methods when adapting to new conditions with only one demonstration.</li>\n</ul>"}, "publishedAt": "2026-06-30T20:00:00.000Z", "title": "Domain Arithmetic: One-Shot VLA Adaptation under Environmental Shifts", "summary": "Vision-Language-Action (VLA) models often fail to perform the same learned tasks under environmental shifts, such as changes in camera pose and shifts to a different but similar robot (e.g., from Panda to UR5e). Adapting these models to the shifted environment (i.e., target domain) often requires training on multiple demonstrations for each task, which are costly to collect. To reduce the burden of data curation and training, we propose an analogy-based method that adapts VLA models under environmental shifts through weight vector arithmetic with domain-specific information addition, named Domain ARiThmetic (DART). Unlike prior approaches, DART requires collecting only a single demonstration, enabling efficient adaptation. To accurately isolate domain-specific information for addition, DART performs subspace alignment between singular components in weight vectors to filter out noisy components. In both simulated and real-world experiments, DART outperforms existing VLA adaptation methods in one-shot scenarios across diverse visual and embodiment shifts. Code is available at https://github.com/snumprlab/dart.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.00666.png", "numComments": 1, "submittedBy": {"_id": "654e14776337c78f3c72e680", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/654e14776337c78f3c72e680/As2L8hOQjUzgjFaMxDcKo.jpeg", "fullname": "Taewook Kang", "name": "twkang43", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "isUserFollowing": false}, "organization": {"_id": "66d54dc8033492801db2bf5a", "name": "SeoulNatlUniv", "fullname": "Seoul National University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/659ccc9d18897eb6594e897f/_-0BM-1UyM-d-lRiahFnf.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2607.00248", "authors": [{"_id": "6a45f2e94f1dd35e48fb903d", "name": "Bytedance Seed", "hidden": false}], "publishedAt": "2026-06-30T00:00:00.000Z", "submittedOnDailyAt": "2026-07-02T00:00:00.000Z", "title": "Seed2.0 Model Card: Towards Intelligence Frontier for Real-World Complexity", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "We present Seed2.0, a model series that takes a meaningful step toward solving complex, real-world tasks. Our approach begins with identifying users' genuine needs and constructing a reliable, forward-looking evaluation system by selecting and abstracting benchmarks grounded in these needs and in realistic, complex scenarios. Guided by this evaluation system, Seed2.0 targets two persistent challenges, long-tail knowledge and complex instruction following, substantially improving the model's reliability on intricate, long-horizon tasks. Beyond these, Seed2.0 delivers world-leading reasoning intelligence, visual understanding, and search capabilities that address the most common needs of a broad user base. Through extensive real-world use cases documented in this model card, we demonstrate that Seed2.0 begins to exhibit the ability to handle initial complex real-world tasks, delivering greater value to hundreds of millions of users.", "upvotes": 16, "discussionId": "6a45f2ea4f1dd35e48fb903e", "ai_summary": "Seed2.0 addresses complex real-world tasks by tackling long-tail knowledge and complex instruction following challenges while enhancing reasoning, visual understanding, and search capabilities through a robust evaluation framework grounded in user needs.", "ai_keywords": [""], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "67d1140985ea0644e2f14b99", "name": "ByteDance-Seed", "fullname": "ByteDance Seed", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6535c9e88bde2fae19b6fb25/flkDUqd_YEuFsjeNET3r-.png"}, "summary_zh": "<ul>\n    <li>Seed2.0\u662f\u4e00\u4e2a\u65b0\u6a21\u578b\u7cfb\u5217\uff0c\u65e8\u5728\u89e3\u51b3\u590d\u6742\u7684\u73b0\u5b9e\u4efb\u52a1\u3002</li>\n    <li>\u8be5\u6a21\u578b\u5173\u6ce8\u7528\u6237\u7684\u771f\u5b9e\u9700\u6c42\uff0c\u5e76\u5efa\u7acb\u4e86\u53ef\u9760\u7684\u8bc4\u4f30\u7cfb\u7edf\u3002</li>\n    <li>Seed2.0\u89e3\u51b3\u4e86\u957f\u5c3e\u77e5\u8bc6\u548c\u590d\u6742\u6307\u4ee4\u6267\u884c\u7684\u6311\u6218\uff0c\u63d0\u9ad8\u4e86\u5728\u590d\u6742\u4efb\u52a1\u4e0a\u7684\u53ef\u9760\u6027\u3002</li>\n    <li>\u8be5\u6a21\u578b\u5177\u5907\u9886\u5148\u7684\u63a8\u7406\u80fd\u529b\u3001\u89c6\u89c9\u7406\u89e3\u548c\u641c\u7d22\u80fd\u529b\uff0c\u6ee1\u8db3\u5e7f\u6cdb\u7528\u6237\u7684\u9700\u6c42\u3002</li>\n    <li>\u901a\u8fc7\u771f\u5b9e\u6848\u4f8b\uff0cSeed2.0\u5c55\u793a\u4e86\u5904\u7406\u590d\u6742\u73b0\u5b9e\u4efb\u52a1\u7684\u80fd\u529b\uff0c\u4e3a\u6570\u4ebf\u7528\u6237\u63d0\u4f9b\u4e86\u66f4\u5927\u4ef7\u503c\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Seed2.0 is a new model designed to tackle complex real-world tasks effectively.</li>\n    <li>The development focuses on understanding users' real needs and creating a solid evaluation system based on these needs.</li>\n    <li>It aims to improve two main challenges: handling long-tail knowledge and following complex instructions.</li>\n    <li>Seed2.0 offers advanced reasoning, visual understanding, and search abilities that meet the needs of many users.</li>\n    <li>Real-world examples show that Seed2.0 can manage complex tasks, benefiting a wide range of users.</li>\n</ul>"}, "publishedAt": "2026-06-29T20:00:00.000Z", "title": "Seed2.0 Model Card: Towards Intelligence Frontier for Real-World Complexity", "summary": "We present Seed2.0, a model series that takes a meaningful step toward solving complex, real-world tasks. Our approach begins with identifying users' genuine needs and constructing a reliable, forward-looking evaluation system by selecting and abstracting benchmarks grounded in these needs and in realistic, complex scenarios. Guided by this evaluation system, Seed2.0 targets two persistent challenges, long-tail knowledge and complex instruction following, substantially improving the model's reliability on intricate, long-horizon tasks. Beyond these, Seed2.0 delivers world-leading reasoning intelligence, visual understanding, and search capabilities that address the most common needs of a broad user base. Through extensive real-world use cases documented in this model card, we demonstrate that Seed2.0 begins to exhibit the ability to handle initial complex real-world tasks, delivering greater value to hundreds of millions of users.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.00248.png", "numComments": 0, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 329, "isUserFollowing": false}, "organization": {"_id": "67d1140985ea0644e2f14b99", "name": "ByteDance-Seed", "fullname": "ByteDance Seed", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6535c9e88bde2fae19b6fb25/flkDUqd_YEuFsjeNET3r-.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2607.01104", "authors": [{"_id": "6a45d3594f1dd35e48fb8f10", "name": "Zinan Tang", "hidden": false}, {"_id": "6a45d3594f1dd35e48fb8f11", "name": "Yukun Zhang", "hidden": false}, {"_id": "6a45d3594f1dd35e48fb8f12", "name": "Shaomian Zheng", "hidden": false}, {"_id": "6a45d3594f1dd35e48fb8f13", "name": "Zhuoshi Pan", "hidden": false}, {"_id": "6a45d3594f1dd35e48fb8f14", "name": "Qizhi Pei", "hidden": false}, {"_id": "6a45d3594f1dd35e48fb8f15", "name": "Dingnan Jin", "hidden": false}, {"_id": "6a45d3594f1dd35e48fb8f16", "name": "Jun Zhou", "hidden": false}, {"_id": "6a45d3594f1dd35e48fb8f17", "name": "Yujun Wang", "hidden": false}, {"_id": "6a45d3594f1dd35e48fb8f18", "name": "Biqing Huang", "hidden": false}], "publishedAt": "2026-07-01T00:00:00.000Z", "submittedOnDailyAt": "2026-07-02T00:00:00.000Z", "title": "CausalMix: Data Mixture as Causal Inference for Language Model Training", "submittedOnDailyBy": {"_id": "66580d3d80ee5b1e11a94e57", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/66580d3d80ee5b1e11a94e57/aHaPqrV5vNefFktYRsiGf.jpeg", "isPro": false, "fullname": "Zinan Tang", "user": "Word2Li", "type": "user", "name": "Word2Li"}, "summary": "In Large Language Model (LLM) training, data mixing plays a pivotal role in determining model performance. Recent methods optimize mixture weights via proxy models, but they rely on the assumption of static data distributions. As a result, when the underlying data pool shifts, these methods require costly retraining from scratch. This limitation restricts their ability to scale seamlessly from small settings to larger data pools and model sizes. In this paper, we propose CausalMix to address this limitation by casting data mixture optimization as a causal inference problem. We formulate the statistical features of the data pool as covariates and the domain mixture as the treatment. After fitting a causal model on 512 runs of Qwen2.5-0.5B to estimate the Conditional Average Treatment Effect (CATE), we extrapolate the optimal mixture for an 800K data pool and apply it to train a 7B model. Furthermore, we successfully generalize the framework to long chain-of-thought data on Qwen3-4B-Base. By leveraging causal modeling to isolate confounding biases, CausalMix dynamically infers state-dependent optimal data mixtures. Extensive experiments show that the mixture guided by CausalMix consistently improves performance across multiple downstream tasks, outperforming RegMix and other baselines. In addition, we use the CATE Interpreter to provide visual analysis of the learned mixing strategy. Overall, CausalMix offers a causal and interpretable framework for optimizing LLM data mixtures.", "upvotes": 14, "discussionId": "6a45d35a4f1dd35e48fb8f19", "ai_summary": "CausalMix addresses limitations in LLM data mixing by formulating mixture optimization as a causal inference problem, enabling dynamic adaptation to shifting data distributions without costly retraining.", "ai_keywords": ["data mixing", "causal inference", "conditional average treatment effect", "causal modeling", "confounding biases", "data pool", "treatment", "covariates", "Qwen2.5-0.5B", "Qwen3-4B-Base", "RegMix", "CATE Interpreter"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "628735cbc83a2d6ab8d14a66", "name": "Tsinghua", "fullname": "Tsinghua University", "avatar": "https://www.gravatar.com/avatar/6c5c1441e3283e7543342e59277ea219?d=retro&size=100"}, "summary_zh": "<ul>\n    <li>\u5728\u5927\u578b\u8bed\u8a00\u6a21\u578b\uff08LLM\uff09\u8bad\u7ec3\u4e2d\uff0c\u6570\u636e\u6df7\u5408\u5bf9\u6a21\u578b\u6027\u80fd\u81f3\u5173\u91cd\u8981\u3002</li>\n    <li>\u73b0\u6709\u65b9\u6cd5\u4f9d\u8d56\u4e8e\u9759\u6001\u6570\u636e\u5206\u5e03\uff0c\u5bfc\u81f4\u5728\u6570\u636e\u53d8\u5316\u65f6\u9700\u8981\u4ece\u5934\u5f00\u59cb\u6602\u8d35\u7684\u91cd\u65b0\u8bad\u7ec3\u3002</li>\n    <li>\u672c\u6587\u63d0\u51faCausalMix\uff0c\u5c06\u6570\u636e\u6df7\u5408\u4f18\u5316\u89c6\u4e3a\u56e0\u679c\u63a8\u65ad\u95ee\u9898\u3002</li>\n    <li>CausalMix\u901a\u8fc7\u56e0\u679c\u5efa\u6a21\u52a8\u6001\u63a8\u65ad\u72b6\u6001\u4f9d\u8d56\u7684\u6700\u4f73\u6570\u636e\u6df7\u5408\uff0c\u663e\u8457\u63d0\u5347\u591a\u4e2a\u4e0b\u6e38\u4efb\u52a1\u7684\u6027\u80fd\u3002</li>\n    <li>\u7814\u7a76\u8fd8\u4f7f\u7528CATE\u89e3\u91ca\u5668\u63d0\u4f9b\u4e86\u5b66\u4e60\u6df7\u5408\u7b56\u7565\u7684\u53ef\u89c6\u5316\u5206\u6790\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Data mixing is important for training Large Language Models (LLMs) effectively.</li>\n    <li>Current methods for optimizing data mixtures struggle when data changes and need to be retrained from scratch.</li>\n    <li>CausalMix is a new approach that uses causal inference to optimize data mixtures based on changing data pools.</li>\n    <li>After testing on different models, CausalMix showed better performance than existing methods across various tasks.</li>\n    <li>The framework also provides visual insights into how the data mixing strategy works.</li>\n</ul>"}, "publishedAt": "2026-06-30T20:00:00.000Z", "title": "CausalMix: Data Mixture as Causal Inference for Language Model Training", "summary": "In Large Language Model (LLM) training, data mixing plays a pivotal role in determining model performance. Recent methods optimize mixture weights via proxy models, but they rely on the assumption of static data distributions. As a result, when the underlying data pool shifts, these methods require costly retraining from scratch. This limitation restricts their ability to scale seamlessly from small settings to larger data pools and model sizes. In this paper, we propose CausalMix to address this limitation by casting data mixture optimization as a causal inference problem. We formulate the statistical features of the data pool as covariates and the domain mixture as the treatment. After fitting a causal model on 512 runs of Qwen2.5-0.5B to estimate the Conditional Average Treatment Effect (CATE), we extrapolate the optimal mixture for an 800K data pool and apply it to train a 7B model. Furthermore, we successfully generalize the framework to long chain-of-thought data on Qwen3-4B-Base. By leveraging causal modeling to isolate confounding biases, CausalMix dynamically infers state-dependent optimal data mixtures. Extensive experiments show that the mixture guided by CausalMix consistently improves performance across multiple downstream tasks, outperforming RegMix and other baselines. In addition, we use the CATE Interpreter to provide visual analysis of the learned mixing strategy. Overall, CausalMix offers a causal and interpretable framework for optimizing LLM data mixtures.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.01104.png", "numComments": 1, "submittedBy": {"_id": "66580d3d80ee5b1e11a94e57", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/66580d3d80ee5b1e11a94e57/aHaPqrV5vNefFktYRsiGf.jpeg", "fullname": "Zinan Tang", "name": "Word2Li", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 5, "isUserFollowing": false}, "organization": {"_id": "628735cbc83a2d6ab8d14a66", "name": "Tsinghua", "fullname": "Tsinghua University", "avatar": "https://www.gravatar.com/avatar/6c5c1441e3283e7543342e59277ea219?d=retro&size=100"}, "isAuthorParticipating": false}, {"paper": {"id": "2607.00272", "authors": [{"_id": "6a45f1f54f1dd35e48fb902c", "name": "Runyu Lu", "hidden": false}, {"_id": "6a45f1f54f1dd35e48fb902d", "name": "Yubo Wu", "hidden": false}, {"_id": "6a45f1f54f1dd35e48fb902e", "name": "Ethan Kou", "hidden": false}, {"_id": "6a45f1f54f1dd35e48fb902f", "name": "Letian Fu", "hidden": false}, {"_id": "6a45f1f54f1dd35e48fb9030", "name": "Wenli Xiao", "hidden": false}, {"_id": "6a45f1f54f1dd35e48fb9031", "name": "Ajay Mandlekar", "hidden": false}, {"_id": "6a45f1f54f1dd35e48fb9032", "name": "Yinzhen Xu", "hidden": false}, {"_id": "6a45f1f54f1dd35e48fb9033", "name": "Guanya Shi", "hidden": false}, {"_id": "6a45f1f54f1dd35e48fb9034", "name": "Ken Goldberg", "hidden": false}, {"_id": "6a45f1f54f1dd35e48fb9035", "name": "Ang Chen", "hidden": false}, {"_id": "6a45f1f54f1dd35e48fb9036", "name": "Mosharaf Chowdhury", "hidden": false}, {"_id": "6a45f1f54f1dd35e48fb9037", "name": "Yuke Zhu", "hidden": false}, {"_id": "6a45f1f54f1dd35e48fb9038", "name": "Linxi \"Jim\" Fan", "hidden": false}, {"_id": "6a45f1f54f1dd35e48fb9039", "name": "Guanzhi Wang", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6039478ab3ecf716b1a5fd4d/HQijwc3rdfDcgZZRY727-.mp4"], "publishedAt": "2026-06-30T00:00:00.000Z", "submittedOnDailyAt": "2026-07-02T00:00:00.000Z", "title": "ASPIRE: Agentic /Skills Discovery for Robotics", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "Traditional robot programming is challenging: it requires orchestrating multimodal perception, managing physical contact dynamics, and handling diverse configurations and execution failures. We introduce ASPIRE (Agentic Skill Programming through Iterative Robot Exploration), a continual learning system that autonomously writes and refines robot control programs in a code-as-policy paradigm while compounding experience into a reusable skill library. ASPIRE discovers skills that persist across tasks, simulation and real-world settings, and embodiments. It operates in an open-ended loop with three components: (1) a closed-loop robot execution engine that exposes fine-grained multimodal traces, enabling autonomous failure diagnosis, repair synthesis, and validation; (2) a continually expanding skill library that distills validated fixes into reusable, transferable knowledge; and (3) evolutionary search that generates diverse task sequences and control programs to explore beyond single-trajectory refinement. ASPIRE surpasses prior methods by up to 77% on LIBERO-Pro manipulation under perturbation, 72% on Robosuite bimanual handover, and 32% on BEHAVIOR-1K long-horizon household tasks. Its accumulated library also enables zero-shot generalization to unseen long-horizon tasks: on LIBERO-Pro Long, ASPIRE achieves 31% success versus 4% for prior methods despite their use of test-time reasoning and retries. Finally, simulation-discovered skills provide initial evidence of sim-to-real transfer, substantially reducing real-robot programming effort across different embodiments and robot APIs.", "upvotes": 12, "discussionId": "6a45f1f54f1dd35e48fb903a", "projectPage": "https://research.nvidia.com/labs/gear/aspire/", "ai_summary": "ASPIRE is a continual learning system that autonomously develops and refines robot control programs through iterative exploration, achieving superior performance and zero-shot generalization in manipulation and household tasks while enabling sim-to-real transfer.", "ai_keywords": ["continual learning", "code-as-policy paradigm", "skill library", "closed-loop robot execution engine", "multimodal traces", "failure diagnosis", "repair synthesis", "evolutionary search", "sim-to-real transfer"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "60262b67268c201cdc8b7d43", "name": "nvidia", "fullname": "NVIDIA", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/65df9200dc3292a8983e5017/Vs5FPVCH-VZBipV3qKTuy.png"}, "summary_zh": "<ul>\n    <li>\u4f20\u7edf\u673a\u5668\u4eba\u7f16\u7a0b\u975e\u5e38\u590d\u6742\uff0c\u9700\u8981\u534f\u8c03\u591a\u79cd\u611f\u77e5\u3001\u7ba1\u7406\u7269\u7406\u63a5\u89e6\u52a8\u6001\u548c\u5904\u7406\u5404\u79cd\u914d\u7f6e\u53ca\u6267\u884c\u5931\u8d25\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86ASPIRE\u7cfb\u7edf\uff0c\u5b83\u53ef\u4ee5\u81ea\u4e3b\u7f16\u5199\u548c\u6539\u8fdb\u673a\u5668\u4eba\u63a7\u5236\u7a0b\u5e8f\uff0c\u5e76\u5efa\u7acb\u4e00\u4e2a\u53ef\u91cd\u590d\u4f7f\u7528\u7684\u6280\u80fd\u5e93\u3002</li>\n    <li>ASPIRE\u80fd\u591f\u53d1\u73b0\u8de8\u4efb\u52a1\u3001\u6a21\u62df\u548c\u73b0\u5b9e\u4e16\u754c\u73af\u5883\u4e2d\u6301\u4e45\u7684\u6280\u80fd\uff0c\u5e76\u901a\u8fc7\u4e09\u4e2a\u7ec4\u4ef6\u4e0d\u65ad\u8fd0\u4f5c\uff1a\u95ed\u73af\u6267\u884c\u5f15\u64ce\u3001\u4e0d\u65ad\u6269\u5c55\u7684\u6280\u80fd\u5e93\u548c\u8fdb\u5316\u641c\u7d22\u3002</li>\n    <li>ASPIRE\u5728\u591a\u4e2a\u4efb\u52a1\u4e0a\u8d85\u8d8a\u4e86\u4ee5\u5f80\u65b9\u6cd5\uff0c\u8868\u73b0\u663e\u8457\u63d0\u5347\uff0c\u5982\u5728LIBERO-Pro\u4e0a\u63d0\u9ad8\u4e8677%\u7684\u6210\u529f\u7387\u3002</li>\n    <li>ASPIRE\u7684\u6280\u80fd\u5e93\u53ef\u4ee5\u5b9e\u73b0\u96f6\u6837\u672c\u6cdb\u5316\uff0c\u5bf9\u4e8e\u672a\u89c1\u8fc7\u7684\u957f\u671f\u4efb\u52a1\u6210\u529f\u7387\u8fbe\u523031%\uff0c\u800c\u4ee5\u5f80\u65b9\u6cd5\u4ec5\u4e3a4%\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>ASPIRE is a new system that helps robots learn and improve their programming on their own.</li>\n    <li>It creates a library of useful skills that can be used in different tasks and environments.</li>\n    <li>ASPIRE has three main parts: a robot execution engine for diagnosing and fixing problems, a skill library for storing validated methods, and an evolutionary search for exploring new tasks.</li>\n    <li>The system outperforms previous methods in various robot manipulation tasks, achieving significantly higher success rates.</li>\n    <li>ASPIRE can apply its learned skills to new tasks without additional training, making it easier to program robots in real-world situations.</li>\n</ul>"}, "publishedAt": "2026-06-29T20:00:00.000Z", "title": "ASPIRE: Agentic /Skills Discovery for Robotics", "summary": "Traditional robot programming is challenging: it requires orchestrating multimodal perception, managing physical contact dynamics, and handling diverse configurations and execution failures. We introduce ASPIRE (Agentic Skill Programming through Iterative Robot Exploration), a continual learning system that autonomously writes and refines robot control programs in a code-as-policy paradigm while compounding experience into a reusable skill library. ASPIRE discovers skills that persist across tasks, simulation and real-world settings, and embodiments. It operates in an open-ended loop with three components: (1) a closed-loop robot execution engine that exposes fine-grained multimodal traces, enabling autonomous failure diagnosis, repair synthesis, and validation; (2) a continually expanding skill library that distills validated fixes into reusable, transferable knowledge; and (3) evolutionary search that generates diverse task sequences and control programs to explore beyond single-trajectory refinement. ASPIRE surpasses prior methods by up to 77% on LIBERO-Pro manipulation under perturbation, 72% on Robosuite bimanual handover, and 32% on BEHAVIOR-1K long-horizon household tasks. Its accumulated library also enables zero-shot generalization to unseen long-horizon tasks: on LIBERO-Pro Long, ASPIRE achieves 31% success versus 4% for prior methods despite their use of test-time reasoning and retries. Finally, simulation-discovered skills provide initial evidence of sim-to-real transfer, substantially reducing real-robot programming effort across different embodiments and robot APIs.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6039478ab3ecf716b1a5fd4d/HQijwc3rdfDcgZZRY727-.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.00272.png", "numComments": 0, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 329, "isUserFollowing": false}, "organization": {"_id": "60262b67268c201cdc8b7d43", "name": "nvidia", "fullname": "NVIDIA", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/65df9200dc3292a8983e5017/Vs5FPVCH-VZBipV3qKTuy.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2607.01191", "authors": [{"_id": "6a45d4a94f1dd35e48fb8f1c", "name": "Hongxing Li", "hidden": false}, {"_id": "6a45d4a94f1dd35e48fb8f1d", "name": "Xiufeng Huang", "hidden": false}, {"_id": "6a45d4a94f1dd35e48fb8f1e", "name": "Dingming Li", "hidden": false}, {"_id": "6a45d4a94f1dd35e48fb8f1f", "name": "Wenjing Jiang", "hidden": false}, {"_id": "6a45d4a94f1dd35e48fb8f20", "name": "Zixuan Wang", "hidden": false}, {"_id": "6a45d4a94f1dd35e48fb8f21", "name": "Haolei Xu", "hidden": false}, {"_id": "6a45d4a94f1dd35e48fb8f22", "name": "Hanrong Zhang", "hidden": false}, {"_id": "6a45d4a94f1dd35e48fb8f23", "name": "Haiwen Hong", "hidden": false}, {"_id": "6a45d4a94f1dd35e48fb8f24", "name": "Longtao Huang", "hidden": false}, {"_id": "6a45d4a94f1dd35e48fb8f25", "name": "Hui Xue", "hidden": false}, {"_id": "6a45d4a94f1dd35e48fb8f26", "name": "Weiming Lu", "hidden": false}, {"_id": "6a45d4a94f1dd35e48fb8f27", "name": "Jun Xiao", "hidden": false}, {"_id": "6a45d4a94f1dd35e48fb8f28", "name": "Yueting Zhuang", "hidden": false}, {"_id": "6a45d4a94f1dd35e48fb8f29", "name": "Yongliang Shen", "hidden": false}], "publishedAt": "2026-07-01T00:00:00.000Z", "submittedOnDailyAt": "2026-07-02T00:00:00.000Z", "title": "Perceive-to-Reason: Decoupling Perception and Reasoning for Fine-Grained Visual Reasoning", "submittedOnDailyBy": {"_id": "67505c291372c3446d0a1f5d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/rOVvWED4Fm6e8aWJDP5pj.jpeg", "isPro": false, "fullname": "Hongxing Li", "user": "hongxingli", "type": "user", "name": "hongxingli"}, "summary": "Fine-grained visual reasoning remains challenging for vision-language models, especially when small but critical visual cues are buried in high-resolution images. Existing approaches rely on repeated cropping or test-time visual search to introduce local evidence, but they typically do not explicitly distinguish perception from reasoning. In this paper, we propose Perceive-to-Reason (P2R), a unified framework that formulates fine-grained visual reasoning as a two-stage process: the model first localizes question-relevant evidence as a Perceiver, and then answers the question as a Reasoner based on the annotated image and cropped regions. To better align training with this decoupled formulation, we further introduce Perception-Reasoning Alternating GRPO (PRA-GRPO), a role-aware reinforcement learning strategy that alternates between perception-focused and reasoning-focused updates using only final-answer supervision. Built on top of Qwen3-VL-Instruct-2B/4B/8B, P2R consistently improves performance across model scales. In particular, P2R-4B achieves 93.2% on V-Star, 81.9% on HR-Bench-4K, and 80.5% on HR-Bench-8K, substantially outperforming its corresponding backbone. Further experiments show that the benefits of P2R extend beyond high-resolution benchmarks to broader multimodal reasoning tasks. These results suggest that explicitly decoupling perception from reasoning provides an effective framework for fine-grained visual reasoning.", "upvotes": 11, "discussionId": "6a45d4a94f1dd35e48fb8f2a", "githubRepo": "https://github.com/ZJU-REAL/Perceive-to-Reason", "githubRepoAddedBy": "user", "ai_summary": "A unified framework named Perceive-to-Reason (P2R) is introduced that separates visual perception from reasoning in vision-language models through a two-stage process, improving fine-grained visual reasoning performance on high-resolution images.", "ai_keywords": ["vision-language models", "fine-grained visual reasoning", "Perceiver", "Reasoner", "Perception-Reasoning Alternating GRPO", "reinforcement learning", "visual perception", "multimodal reasoning"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 14, "organization": {"_id": "61bac2af530e5c78d7b99667", "name": "zju", "fullname": "Zhejiang University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/5e1058e9fcf41d740b69966d/7G1xjlxwCdMEmKcxNR0n5.png"}, "summary_zh": "<ul>\n    <li>\u7ec6\u7c92\u5ea6\u89c6\u89c9\u63a8\u7406\u5bf9\u89c6\u89c9\u8bed\u8a00\u6a21\u578b\u4ecd\u7136\u5177\u6709\u6311\u6218\uff0c\u5c24\u5176\u662f\u5728\u9ad8\u5206\u8fa8\u7387\u56fe\u50cf\u4e2d\u9690\u85cf\u7684\u5c0f\u800c\u5173\u952e\u7684\u89c6\u89c9\u7ebf\u7d22\u3002</li>\n    <li>\u73b0\u6709\u65b9\u6cd5\u4f9d\u8d56\u4e8e\u91cd\u590d\u88c1\u526a\u6216\u6d4b\u8bd5\u65f6\u89c6\u89c9\u641c\u7d22\uff0c\u4f46\u901a\u5e38\u4e0d\u660e\u786e\u533a\u5206\u611f\u77e5\u4e0e\u63a8\u7406\u3002</li>\n    <li>\u672c\u6587\u63d0\u51fa\u4e86\u4e00\u79cd\u540d\u4e3a Perceive-to-Reason (P2R) \u7684\u7edf\u4e00\u6846\u67b6\uff0c\u5206\u4e3a\u4e24\u4e2a\u9636\u6bb5\uff1a\u9996\u5148\u5b9a\u4f4d\u4e0e\u95ee\u9898\u76f8\u5173\u7684\u8bc1\u636e\uff0c\u7136\u540e\u57fa\u4e8e\u6ce8\u91ca\u56fe\u50cf\u548c\u88c1\u526a\u533a\u57df\u56de\u7b54\u95ee\u9898\u3002</li>\n    <li>\u5f15\u5165\u4e86\u611f\u77e5-\u63a8\u7406\u4ea4\u66ff\u7684\u5f3a\u5316\u5b66\u4e60\u7b56\u7565 PRA-GRPO\uff0c\u901a\u8fc7\u53ea\u4f7f\u7528\u6700\u7ec8\u7b54\u6848\u76d1\u7763\u4ea4\u66ff\u66f4\u65b0\u611f\u77e5\u548c\u63a8\u7406\u3002</li>\n    <li>P2R \u5728\u591a\u4e2a\u6a21\u578b\u89c4\u6a21\u4e0a\u6301\u7eed\u63d0\u9ad8\u6027\u80fd\uff0c\u5c24\u5176\u662f P2R-4B \u5728\u591a\u4e2a\u57fa\u51c6\u4efb\u52a1\u4e2d\u8868\u73b0\u4f18\u5f02\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Fine-grained visual reasoning is tough for vision-language models, especially with small details in high-resolution images.</li>\n    <li>Current methods use cropping or visual searches but don't separate perception from reasoning well.</li>\n    <li>The proposed method, Perceive-to-Reason (P2R), is a two-step process: first finding relevant visual evidence and then answering questions.</li>\n    <li>P2R uses a new learning strategy called PRA-GRPO to improve how the model learns perception and reasoning.</li>\n    <li>P2R shows better performance in various benchmarks, indicating that separating perception and reasoning helps in visual reasoning tasks.</li>\n</ul>"}, "publishedAt": "2026-06-30T20:00:00.000Z", "title": "Perceive-to-Reason: Decoupling Perception and Reasoning for Fine-Grained Visual Reasoning", "summary": "Fine-grained visual reasoning remains challenging for vision-language models, especially when small but critical visual cues are buried in high-resolution images. Existing approaches rely on repeated cropping or test-time visual search to introduce local evidence, but they typically do not explicitly distinguish perception from reasoning. In this paper, we propose Perceive-to-Reason (P2R), a unified framework that formulates fine-grained visual reasoning as a two-stage process: the model first localizes question-relevant evidence as a Perceiver, and then answers the question as a Reasoner based on the annotated image and cropped regions. To better align training with this decoupled formulation, we further introduce Perception-Reasoning Alternating GRPO (PRA-GRPO), a role-aware reinforcement learning strategy that alternates between perception-focused and reasoning-focused updates using only final-answer supervision. Built on top of Qwen3-VL-Instruct-2B/4B/8B, P2R consistently improves performance across model scales. In particular, P2R-4B achieves 93.2% on V-Star, 81.9% on HR-Bench-4K, and 80.5% on HR-Bench-8K, substantially outperforming its corresponding backbone. Further experiments show that the benefits of P2R extend beyond high-resolution benchmarks to broader multimodal reasoning tasks. These results suggest that explicitly decoupling perception from reasoning provides an effective framework for fine-grained visual reasoning.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2607.01191.png", "numComments": 1, "submittedBy": {"_id": "67505c291372c3446d0a1f5d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/rOVvWED4Fm6e8aWJDP5pj.jpeg", "fullname": "Hongxing Li", "name": "hongxingli", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 1, "isUserFollowing": false}, "organization": {"_id": "61bac2af530e5c78d7b99667", "name": "zju", "fullname": "Zhejiang University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/5e1058e9fcf41d740b69966d/7G1xjlxwCdMEmKcxNR0n5.png"}, "isAuthorParticipating": false}],
    "week": [{"paper": {"id": "2606.30534", "authors": [{"_id": "6a4334fd763f63ca3757e917", "user": {"_id": "68c429ef60f075cc46cc9cff", "avatarUrl": "/avatars/21d277a1b46eabc967121a111e270cdd.svg", "isPro": false, "fullname": "yh-wang", "user": "yh-wang", "type": "user", "name": "yh-wang"}, "name": "Yihao Wang", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T09:49:27.650Z", "hidden": false}, {"_id": "6a4334fd763f63ca3757e918", "user": {"_id": "668f5478b3991ac0c3fc9c2f", "avatarUrl": "/avatars/a775853d3b88e7b1c8494ca837b5495c.svg", "isPro": false, "fullname": "yuhengji", "user": "yuheng2000", "type": "user", "name": "yuheng2000"}, "name": "Yuheng Ji", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T09:49:25.392Z", "hidden": false}, {"_id": "6a4334fd763f63ca3757e919", "user": {"_id": "668fa476cbcaf7ab0e4c58b3", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/668fa476cbcaf7ab0e4c58b3/F5Jj-nPCjU6uxZyfkY3qw.jpeg", "isPro": false, "fullname": "Mingyu Cao", "user": "cmyopu", "type": "user", "name": "cmyopu"}, "name": "Mingyu Cao", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T08:47:12.327Z", "hidden": false}, {"_id": "6a4334fd763f63ca3757e91a", "user": {"_id": "671fa0de0a34a05602094909", "avatarUrl": "/avatars/e35890e1f71a8c3f4e33b35a027e180a.svg", "isPro": false, "fullname": "Yanqing Shen", "user": "syq1105", "type": "user", "name": "syq1105"}, "name": "Yanqing Shen", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T08:47:16.531Z", "hidden": false}, {"_id": "6a4334fd763f63ca3757e91b", "name": "Runze Xiao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e91c", "user": {"_id": "67ecd5dc6b33c72fba1fc70f", "avatarUrl": "/avatars/27ff8fb1534f1d277ae03e8adc64ffba.svg", "isPro": false, "fullname": "huaihai lyu", "user": "HuaihaiLyu", "type": "user", "name": "HuaihaiLyu"}, "name": "Huaihai Lyu", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T08:47:10.262Z", "hidden": false}, {"_id": "6a4334fd763f63ca3757e91d", "user": {"_id": "643613fdaaef013d1af18717", "avatarUrl": "/avatars/b4689886eaf2103d8e92f90ea5e5bc5e.svg", "isPro": false, "fullname": "Senwei Xie", "user": "jsw19", "type": "user", "name": "jsw19"}, "name": "Senwei Xie", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T09:49:51.559Z", "hidden": false}, {"_id": "6a4334fd763f63ca3757e91e", "name": "Euan Liu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e91f", "name": "Klara Tian", "hidden": false}, {"_id": "6a4334fd763f63ca3757e920", "name": "Tianfeng Long", "hidden": false}, {"_id": "6a4334fd763f63ca3757e921", "name": "Yichi Zhang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e922", "name": "Zhengliang Cai", "hidden": false}, {"_id": "6a4334fd763f63ca3757e923", "name": "Ruike Chen", "hidden": false}, {"_id": "6a4334fd763f63ca3757e924", "name": "Jifan Zhao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e925", "name": "Ruochuan Shi", "hidden": false}, {"_id": "6a4334fd763f63ca3757e926", "user": {"_id": "65fce52cb6fa00949682d41b", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/65fce52cb6fa00949682d41b/RZ6J1Ovix-jJW9KSiWcEk.jpeg", "isPro": false, "fullname": "Zihan Tang", "user": "tzh21", "type": "user", "name": "tzh21"}, "name": "Zihan Tang", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T08:47:14.193Z", "hidden": false}, {"_id": "6a4334fd763f63ca3757e927", "name": "Jing Lyu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e928", "name": "Wenxing Tan", "hidden": false}, {"_id": "6a4334fd763f63ca3757e929", "name": "Ningbo Zhang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e92a", "name": "Yangtao Hu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e92b", "name": "Yuming Gao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e92c", "name": "Xiansheng Chen", "hidden": false}, {"_id": "6a4334fd763f63ca3757e92d", "name": "Junkai Zhao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e92e", "name": "Congsheng Xu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e92f", "name": "Boan Zhu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e930", "name": "Ziqi Wang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e931", "name": "Yupu Feng", "hidden": false}, {"_id": "6a4334fd763f63ca3757e932", "name": "Qiongqiong Zhang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e933", "name": "Yingli Zhao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e934", "name": "Yulong Ao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e935", "name": "Shaoxuan Xie", "hidden": false}, {"_id": "6a4334fd763f63ca3757e936", "name": "You Liu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e937", "name": "Guocai Yao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e938", "name": "Leiduo Zhang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e939", "name": "Xiaodan Liu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e93a", "name": "Yunyan Zhang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e93b", "name": "Yance Jiao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e93c", "name": "Xinyan Yang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e93d", "name": "Jiaxing Wei", "hidden": false}, {"_id": "6a4334fd763f63ca3757e93e", "name": "Xu Liu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e93f", "name": "Tengfei Pan", "hidden": false}, {"_id": "6a4334fd763f63ca3757e940", "name": "Shaokai Nie", "hidden": false}, {"_id": "6a4334fd763f63ca3757e941", "name": "Chunlei Men", "hidden": false}, {"_id": "6a4334fd763f63ca3757e942", "name": "Sen Cui", "hidden": false}, {"_id": "6a4334fd763f63ca3757e943", "name": "Xiaojie Jin", "hidden": false}, {"_id": "6a4334fd763f63ca3757e944", "name": "Hongyang Li", "hidden": false}, {"_id": "6a4334fd763f63ca3757e945", "name": "Jianlan Luo", "hidden": false}, {"_id": "6a4334fd763f63ca3757e946", "name": "Yao Mu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e947", "name": "Yunchao Wei", "hidden": false}, {"_id": "6a4334fd763f63ca3757e948", "name": "Jun Yan", "hidden": false}, {"_id": "6a4334fd763f63ca3757e949", "name": "Hang Zhao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e94a", "name": "Xiaolong Zheng", "hidden": false}, {"_id": "6a4334fd763f63ca3757e94b", "name": "Jiaming Li", "hidden": false}, {"_id": "6a4334fd763f63ca3757e94c", "name": "Yonghua Lin", "hidden": false}, {"_id": "6a4334fd763f63ca3757e94d", "name": "Tiejun Huang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e94e", "name": "Zhongyuan Wang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e94f", "name": "Pengwei Wang", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/68c429ef60f075cc46cc9cff/ceZCPH1jShoRORZCEPALp.mp4"], "publishedAt": "2026-06-29T00:00:00.000Z", "submittedOnDailyAt": "2026-07-01T00:00:00.000Z", "title": "Orca: The World is in Your Mind", "submittedOnDailyBy": {"_id": "68c429ef60f075cc46cc9cff", "avatarUrl": "/avatars/21d277a1b46eabc967121a111e270cdd.svg", "isPro": false, "fullname": "yh-wang", "user": "yh-wang", "type": "user", "name": "yh-wang"}, "summary": "We introduce Orca, an initial instantiation of a general world foundation model. Orca learns a unified world latent space from multimodal world signals and exposes it through multimodal readout interfaces. Rather than optimizing isolated next-token, next-frame, or next-action prediction, we are centered on Next-State-Prediction modeling, offering a unified state-transition modeling route toward understanding, predicting, and acting upon the world. Orca learns through two complementary paradigms: unconscious learning captures dense natural state transitions from continuous videos, and conscious learning models sparse meaningful state transitions by language-described events and VQA supervision. For pre-training, we construct a large-scale world-learning inventory data, including 125K hours of video data and 160M event annotations. After pre-training, Orca learns a unified world latent space. To examine whether the learned latent supports downstream, we evaluate it by three representative downstream readouts: text generation, image prediction, and embodied action generation. Orca's backbone is frozen, and only the lightweight modality-specific decoders are trainable. Experiments show the scalability of the proposed paradigm and verify that stronger world latent enables stronger downstream readouts. Orca outperforms similar-sized specialized baselines. These results show that Orca, as a general world foundation model, presents a promising approach to understanding, predicting, and acting upon the world. Finally, we discuss the current limitations, aiming to provide useful insights and inspiration for the community.", "upvotes": 176, "discussionId": "6a4334fd763f63ca3757e950", "projectPage": "https://orca-wm.github.io/", "ai_summary": "Orca establishes a unified world latent space through next-state-prediction modeling using multimodal data and demonstrates superior performance in downstream tasks compared to specialized baselines.", "ai_keywords": ["world foundation model", "world latent space", "multimodal readout interfaces", "next-state-prediction modeling", "unconscious learning", "conscious learning", "world-learning inventory data", "embodied action generation", "downstream readouts", "modality-specific decoders"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "summary_zh": "<ul>\n    <li>Orca\u662f\u4e00\u4e2a\u901a\u7528\u7684\u4e16\u754c\u57fa\u7840\u6a21\u578b\uff0c\u901a\u8fc7\u591a\u6a21\u6001\u4fe1\u53f7\u5b66\u4e60\u7edf\u4e00\u7684\u4e16\u754c\u6f5c\u5728\u7a7a\u95f4\u3002</li>\n    <li>\u5b83\u4e13\u6ce8\u4e8e\u4e0b\u4e00\u72b6\u6001\u9884\u6d4b\u5efa\u6a21\uff0c\u800c\u4e0d\u662f\u5355\u72ec\u7684\u4e0b\u4e00\u6807\u8bb0\u6216\u4e0b\u4e00\u52a8\u4f5c\u9884\u6d4b\u3002</li>\n    <li>Orca\u901a\u8fc7\u65e0\u610f\u8bc6\u5b66\u4e60\u548c\u6709\u610f\u8bc6\u5b66\u4e60\u4e24\u79cd\u65b9\u5f0f\u8fdb\u884c\u5b66\u4e60\uff0c\u5904\u7406\u8fde\u7eed\u89c6\u9891\u548c\u8bed\u8a00\u63cf\u8ff0\u7684\u4e8b\u4ef6\u3002</li>\n    <li>\u9884\u8bad\u7ec3\u4f7f\u7528\u4e86\u5305\u62ec125K\u5c0f\u65f6\u89c6\u9891\u6570\u636e\u548c160M\u4e8b\u4ef6\u6ce8\u91ca\u7684\u5927\u89c4\u6a21\u6570\u636e\u96c6\u3002</li>\n    <li>Orca\u5728\u6587\u672c\u751f\u6210\u3001\u56fe\u50cf\u9884\u6d4b\u548c\u884c\u52a8\u751f\u6210\u7b49\u4efb\u52a1\u4e2d\u8868\u73b0\u4f18\u4e8e\u7c7b\u4f3c\u89c4\u6a21\u7684\u4e13\u4e1a\u6a21\u578b\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Orca is a new model designed to understand and predict the world by learning from various types of data, like videos and text.</li>\n    <li>It uses a method called Next-State-Prediction to model how things change in the world, rather than just predicting the next item in a sequence.</li>\n    <li>Orca learns in two ways: one involves observing continuous video for natural changes, and the other focuses on specific events described in language.</li>\n    <li>It was trained on a large dataset, including 125,000 hours of video and 160 million event descriptions, to create a unified understanding of the world.</li>\n    <li>Orca shows strong performance in generating text, predicting images, and planning actions, outperforming other specialized models.</li>\n</ul>"}, "publishedAt": "2026-06-28T20:00:00.000Z", "title": "Orca: The World is in Your Mind", "summary": "We introduce Orca, an initial instantiation of a general world foundation model. Orca learns a unified world latent space from multimodal world signals and exposes it through multimodal readout interfaces. Rather than optimizing isolated next-token, next-frame, or next-action prediction, we are centered on Next-State-Prediction modeling, offering a unified state-transition modeling route toward understanding, predicting, and acting upon the world. Orca learns through two complementary paradigms: unconscious learning captures dense natural state transitions from continuous videos, and conscious learning models sparse meaningful state transitions by language-described events and VQA supervision. For pre-training, we construct a large-scale world-learning inventory data, including 125K hours of video data and 160M event annotations. After pre-training, Orca learns a unified world latent space. To examine whether the learned latent supports downstream, we evaluate it by three representative downstream readouts: text generation, image prediction, and embodied action generation. Orca's backbone is frozen, and only the lightweight modality-specific decoders are trainable. Experiments show the scalability of the proposed paradigm and verify that stronger world latent enables stronger downstream readouts. Orca outperforms similar-sized specialized baselines. These results show that Orca, as a general world foundation model, presents a promising approach to understanding, predicting, and acting upon the world. Finally, we discuss the current limitations, aiming to provide useful insights and inspiration for the community.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/68c429ef60f075cc46cc9cff/ceZCPH1jShoRORZCEPALp.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.30534.png", "numComments": 5, "submittedBy": {"_id": "68c429ef60f075cc46cc9cff", "avatarUrl": "/avatars/21d277a1b46eabc967121a111e270cdd.svg", "fullname": "yh-wang", "name": "yh-wang", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 3, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2606.28733", "authors": [{"_id": "6a43896919e14c76c1bfad0b", "name": "Han Luo", "hidden": false}, {"_id": "6a43896919e14c76c1bfad0c", "name": "Bingbing Wen", "hidden": false}, {"_id": "6a43896919e14c76c1bfad0d", "name": "Lucy Lu Wang", "hidden": false}], "publishedAt": "2026-06-27T00:00:00.000Z", "submittedOnDailyAt": "2026-06-30T00:00:00.000Z", "title": "Agentic Abstention: Do Agents Know When to Stop Instead of Act?", "submittedOnDailyBy": {"_id": "68a0606dbbcbb7c347256908", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/68a0606dbbcbb7c347256908/JuZGxOT1EHi1dn2_qf2Xz.jpeg", "isPro": false, "fullname": "Han Luo", "user": "sxcn", "type": "user", "name": "sxcn"}, "summary": "LLM agents are expected to act over multiple turns, using search, browsing interfaces, and terminal tools to complete user goals. Yet not every goal is well specified or achievable in the available environment. In such cases, a reliable agent should recognize that further interaction is unlikely to help and abstain from additional tool calls. We define Agentic Abstention, the problem of deciding when an agent should stop acting under uncertainty. Unlike standard LLM abstention, which is usually evaluated as a single-turn answer-or-abstain decision, agentic abstention is a sequential decision problem: an agent can answer, abstain, or gather more information at each turn, and the need to abstain may only become clear after interacting with the environment. We study this problem across web shopping, terminal environments, and question answering, evaluating 13 LLM-as-agent systems and 2 agent scaffolds on more than 28,000 tasks. Our results show that the main challenge is not only whether agents can abstain, but also when they abstain. Some agents never abstain when they should, while others do so only after many unnecessary interactions. This gap is especially large on tasks where the instruction appears feasible until the environment reveals otherwise (e.g., no valid result matches the instruction). We further find that model scale, reasoning, and agent scaffolding affect abstention in different ways, where larger or more capable models sometimes perform worse at timely abstention. Finally, we introduce CONVOLVE, a context engineering method for improving agentic abstention that distills full interaction trajectories into reusable stopping rules. On WebShop, CONVOLVE substantially improves timely abstention without updating model parameters, raising Llama-3.3-70B's timely recall rate from 26.7 to 57.4. Our dataset and code are available at https://lhannnn.github.io/agentic-abstention", "upvotes": 120, "discussionId": "6a43896919e14c76c1bfad0e", "projectPage": "https://lhannnn.github.io/agentic-abstention", "ai_summary": "Agentic abstention involves determining when an AI agent should cease interaction under uncertainty, requiring sequential decision-making across multiple environments and task types.", "ai_keywords": ["agentic abstention", "LLM-as-agent systems", "sequential decision problem", "web shopping", "terminal environments", "question answering", "context engineering", "CONVOLVE", "stopping rules"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "6315a1bb86b3db2ac420100e", "name": "UW", "fullname": "University of Washington", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/61ac8f8a00d01045fca0ad2f/gr5B_WVvbMr4kTox5UkwZ.jpeg"}, "summary_zh": "<ul>\n    <li>LLM\u4ee3\u7406\u9700\u8981\u5728\u591a\u8f6e\u4ea4\u4e92\u4e2d\u5b8c\u6210\u7528\u6237\u76ee\u6807\uff0c\u4f46\u6709\u4e9b\u76ee\u6807\u53ef\u80fd\u4e0d\u660e\u786e\u6216\u4e0d\u53ef\u5b9e\u73b0\u3002</li>\n    <li>\u6211\u4eec\u5b9a\u4e49\u4e86\u201c\u4ee3\u7406\u6027\u653e\u5f03\u201d\uff0c\u5373\u5728\u4e0d\u786e\u5b9a\u60c5\u51b5\u4e0b\u51b3\u5b9a\u4f55\u65f6\u505c\u6b62\u884c\u52a8\u7684\u95ee\u9898\u3002</li>\n    <li>\u7814\u7a76\u663e\u793a\uff0c\u4e0d\u540c\u7684\u4ee3\u7406\u5728\u653e\u5f03\u65f6\u8868\u73b0\u4e0d\u4e00\uff0c\u6709\u4e9b\u5728\u5e94\u8be5\u653e\u5f03\u65f6\u4ece\u4e0d\u653e\u5f03\u3002</li>\n    <li>\u6a21\u578b\u7684\u89c4\u6a21\u3001\u63a8\u7406\u80fd\u529b\u548c\u4ee3\u7406\u6846\u67b6\u5bf9\u653e\u5f03\u51b3\u7b56\u5f71\u54cd\u4e0d\u540c\uff0c\u6709\u65f6\u8f83\u5927\u6a21\u578b\u7684\u653e\u5f03\u65f6\u673a\u53cd\u800c\u8f83\u5dee\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86CONVOLVE\u65b9\u6cd5\uff0c\u53ef\u6539\u5584\u4ee3\u7406\u6027\u653e\u5f03\uff0c\u663e\u8457\u63d0\u9ad8\u653e\u5f03\u7684\u53ca\u65f6\u6027\u3002</li>\n</ul>", "summary_simple": "<ul>\n  <li>LLM agents need to make decisions over multiple interactions and sometimes should stop trying to achieve a goal if it's unclear or unachievable.</li>\n  <li>Agentic Abstention is about figuring out when an agent should stop acting, which is more complex than just answering or abstaining in one turn.</li>\n  <li>The study evaluated 13 LLM systems and 2 agent scaffolds on over 28,000 tasks, finding that many agents struggle with when to abstain appropriately.</li>\n  <li>Some agents fail to abstain when they should, while others do so after too many unnecessary actions, especially when initial instructions seem feasible.</li>\n  <li>CONVOLVE is a new method introduced to help agents improve their timely abstention by using past interactions to create stopping rules, significantly increasing performance in certain tasks.</li>\n</ul>"}, "publishedAt": "2026-06-26T20:00:00.000Z", "title": "Agentic Abstention: Do Agents Know When to Stop Instead of Act?", "summary": "LLM agents are expected to act over multiple turns, using search, browsing interfaces, and terminal tools to complete user goals. Yet not every goal is well specified or achievable in the available environment. In such cases, a reliable agent should recognize that further interaction is unlikely to help and abstain from additional tool calls. We define Agentic Abstention, the problem of deciding when an agent should stop acting under uncertainty. Unlike standard LLM abstention, which is usually evaluated as a single-turn answer-or-abstain decision, agentic abstention is a sequential decision problem: an agent can answer, abstain, or gather more information at each turn, and the need to abstain may only become clear after interacting with the environment. We study this problem across web shopping, terminal environments, and question answering, evaluating 13 LLM-as-agent systems and 2 agent scaffolds on more than 28,000 tasks. Our results show that the main challenge is not only whether agents can abstain, but also when they abstain. Some agents never abstain when they should, while others do so only after many unnecessary interactions. This gap is especially large on tasks where the instruction appears feasible until the environment reveals otherwise (e.g., no valid result matches the instruction). We further find that model scale, reasoning, and agent scaffolding affect abstention in different ways, where larger or more capable models sometimes perform worse at timely abstention. Finally, we introduce CONVOLVE, a context engineering method for improving agentic abstention that distills full interaction trajectories into reusable stopping rules. On WebShop, CONVOLVE substantially improves timely abstention without updating model parameters, raising Llama-3.3-70B's timely recall rate from 26.7 to 57.4. Our dataset and code are available at https://lhannnn.github.io/agentic-abstention", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.28733.png", "numComments": 8, "submittedBy": {"_id": "68a0606dbbcbb7c347256908", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/68a0606dbbcbb7c347256908/JuZGxOT1EHi1dn2_qf2Xz.jpeg", "fullname": "Han Luo", "name": "sxcn", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 1, "isUserFollowing": false}, "organization": {"_id": "6315a1bb86b3db2ac420100e", "name": "UW", "fullname": "University of Washington", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/61ac8f8a00d01045fca0ad2f/gr5B_WVvbMr4kTox5UkwZ.jpeg"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.30626", "authors": [{"_id": "6a44750141f04ae4d7ad96bd", "user": {"_id": "67d63e228d5c7a132cbcf39b", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/no-auth/ynwA3Sya5irwMRCmSeLiC.png", "isPro": false, "fullname": "neil yu", "user": "yxl66666", "type": "user", "name": "yxl66666"}, "name": "Xinlei Yu", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T13:31:53.166Z", "hidden": false}, {"_id": "6a44750141f04ae4d7ad96be", "name": "Gen Li", "hidden": false}, {"_id": "6a44750141f04ae4d7ad96bf", "name": "Qingyi Si", "hidden": false}, {"_id": "6a44750141f04ae4d7ad96c0", "name": "Guibin Zhang", "hidden": false}, {"_id": "6a44750141f04ae4d7ad96c1", "name": "Yuqi Xu", "hidden": false}, {"_id": "6a44750141f04ae4d7ad96c2", "name": "Congcong Wang", "hidden": false}, {"_id": "6a44750141f04ae4d7ad96c3", "name": "Shuai Dong", "hidden": false}, {"_id": "6a44750141f04ae4d7ad96c4", "name": "Kaiwen Tuo", "hidden": false}, {"_id": "6a44750141f04ae4d7ad96c5", "name": "Xiangyu Zeng", "hidden": false}, {"_id": "6a44750141f04ae4d7ad96c6", "name": "Kaituo Feng", "hidden": false}, {"_id": "6a44750141f04ae4d7ad96c7", "name": "Qunzhong Wang", "hidden": false}, {"_id": "6a44750141f04ae4d7ad96c8", "user": {"_id": "673c7319d11b1c2e246ead9c", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/673c7319d11b1c2e246ead9c/IjFIO--N7Hm_BOEafhEQv.jpeg", "isPro": false, "fullname": "Yang Shi", "user": "DogNeverSleep", "type": "user", "name": "DogNeverSleep"}, "name": "Yang Shi", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T08:44:50.820Z", "hidden": false}, {"_id": "6a44750141f04ae4d7ad96c9", "name": "Xiaobin Hu", "hidden": false}, {"_id": "6a44750141f04ae4d7ad96ca", "name": "Xiangyu Yue", "hidden": false}, {"_id": "6a44750141f04ae4d7ad96cb", "name": "Jiaqi Wang", "hidden": false}, {"_id": "6a44750141f04ae4d7ad96cc", "name": "Shuicheng Yan", "hidden": false}], "publishedAt": "2026-06-29T00:00:00.000Z", "submittedOnDailyAt": "2026-07-01T00:00:00.000Z", "title": "DOPD: Dual On-policy Distillation", "submittedOnDailyBy": {"_id": "67d63e228d5c7a132cbcf39b", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/no-auth/ynwA3Sya5irwMRCmSeLiC.png", "isPro": false, "fullname": "neil yu", "user": "yxl66666", "type": "user", "name": "yxl66666"}, "summary": "On-policy distillation (OPD) offers superior capacity transfer by supervising student-sampled trajectories with dense token-level signals. To furnish high-quality supervision sources and thereby elevate the performance frontier of distillation, an intuitive direction is to infuse privileged information to either teacher or student itself. However, this additional input induces a potential failure mode we dub privilege illusion: a pattern that conflates the transferable capability gap that students are meant to close, and the information asymmetry gap that can only be mimicked but never replicated. This issue is further amplified by the inherent non-uniformity of token-level supervision, where only a small subset of tokens carries pivotal capability-bearing signals. To this end, we propose DOPD, an advantage-aware dual distillation paradigm that dynamically routes token-level supervision between privileged teacher and privileged student policies based on their advantage gap and relative probabilities. Each token receives supervision of different strength, objective, and strategy from either teacher or student itself, which transfers credible capability while simultaneously receiving auxiliary signals, to alleviate privilege illusion. Extensive experiments on both large language model (LLM) and vision-language model (VLM) settings demonstrate that DOPD consistently outperforms Vanilla OPD and other counterparts. Further results on stability, robustness, continual learning, and out-of-distribution tasks validate its superiority.", "upvotes": 75, "discussionId": "6a44750241f04ae4d7ad96cd", "ai_summary": "DOPD addresses privilege illusion in on-policy distillation by dynamically routing token-level supervision between teacher and student policies based on advantage gaps and probabilities, improving capability transfer in large and vision-language models.", "ai_keywords": ["on-policy distillation", "token-level signals", "privileged information", "privilege illusion", "advantage-aware dual distillation", "dynamic routing", "capability transfer", "large language models", "vision-language models"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "summary_zh": "<ul>\n    <li>On-policy distillation (OPD)\u901a\u8fc7\u5bc6\u96c6\u7684\u6807\u8bb0\u7ea7\u4fe1\u53f7\u63d0\u4f9b\u4e86\u66f4\u597d\u7684\u80fd\u529b\u8f6c\u79fb\u3002</li>\n    <li>\u5f15\u5165\u7279\u6743\u4fe1\u606f\u53ef\u4ee5\u63d0\u5347\u84b8\u998f\u7684\u8868\u73b0\uff0c\u4f46\u53ef\u80fd\u5bfc\u81f4\u201c\u7279\u6743\u5e7b\u89c9\u201d\u95ee\u9898\u3002</li>\n    <li>\u7279\u6743\u5e7b\u89c9\u4f1a\u6df7\u6dc6\u5b66\u751f\u9700\u8981\u514b\u670d\u7684\u80fd\u529b\u5dee\u8ddd\u548c\u4fe1\u606f\u4e0d\u5bf9\u79f0\u5dee\u8ddd\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86DOPD\uff0c\u8fd9\u662f\u4e00\u79cd\u52a8\u6001\u8c03\u6574\u76d1\u7763\u7684\u53cc\u91cd\u84b8\u998f\u65b9\u6cd5\uff0c\u53ef\u4ee5\u51cf\u8f7b\u7279\u6743\u5e7b\u89c9\u3002</li>\n    <li>DOPD\u5728\u5927\u91cf\u8bed\u8a00\u6a21\u578b\u548c\u89c6\u89c9\u8bed\u8a00\u6a21\u578b\u7684\u5b9e\u9a8c\u4e2d\u8868\u73b0\u4f18\u4e8e\u4f20\u7edf\u65b9\u6cd5\uff0c\u9a8c\u8bc1\u4e86\u5176\u4f18\u8d8a\u6027\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>On-policy distillation (OPD) improves learning by using detailed feedback from samples taken by the student model.</li>\n    <li>Adding extra information can help performance, but it can also create a problem called \"privilege illusion,\" where the student gets confused about what it can learn.</li>\n    <li>This confusion is worsened by the fact that not all parts of the data are equally useful for learning.</li>\n    <li>The proposed method, DOPD, helps by adjusting how feedback is given based on the strengths and weaknesses of the teacher and student models.</li>\n    <li>Tests show that DOPD works better than traditional OPD methods in various tasks, including language and vision-related challenges.</li>\n</ul>"}, "publishedAt": "2026-06-28T20:00:00.000Z", "title": "DOPD: Dual On-policy Distillation", "summary": "On-policy distillation (OPD) offers superior capacity transfer by supervising student-sampled trajectories with dense token-level signals. To furnish high-quality supervision sources and thereby elevate the performance frontier of distillation, an intuitive direction is to infuse privileged information to either teacher or student itself. However, this additional input induces a potential failure mode we dub privilege illusion: a pattern that conflates the transferable capability gap that students are meant to close, and the information asymmetry gap that can only be mimicked but never replicated. This issue is further amplified by the inherent non-uniformity of token-level supervision, where only a small subset of tokens carries pivotal capability-bearing signals. To this end, we propose DOPD, an advantage-aware dual distillation paradigm that dynamically routes token-level supervision between privileged teacher and privileged student policies based on their advantage gap and relative probabilities. Each token receives supervision of different strength, objective, and strategy from either teacher or student itself, which transfers credible capability while simultaneously receiving auxiliary signals, to alleviate privilege illusion. Extensive experiments on both large language model (LLM) and vision-language model (VLM) settings demonstrate that DOPD consistently outperforms Vanilla OPD and other counterparts. Further results on stability, robustness, continual learning, and out-of-distribution tasks validate its superiority.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.30626.png", "numComments": 1, "submittedBy": {"_id": "67d63e228d5c7a132cbcf39b", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/no-auth/ynwA3Sya5irwMRCmSeLiC.png", "fullname": "neil yu", "name": "yxl66666", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2606.30616", "authors": [{"_id": "6a432d66763f63ca3757e869", "name": "Lei Bai", "hidden": false}, {"_id": "6a432d66763f63ca3757e86a", "name": "Zongsheng Cao", "hidden": false}, {"_id": "6a432d66763f63ca3757e86b", "name": "Yang Chen", "hidden": false}, {"_id": "6a432d66763f63ca3757e86c", "name": "Zhiyao Cui", "hidden": false}, {"_id": "6a432d66763f63ca3757e86d", "name": "Shangheng Du", "hidden": false}, {"_id": "6a432d66763f63ca3757e86e", "name": "Yue Fan", "hidden": false}, {"_id": "6a432d66763f63ca3757e86f", "name": "Shiyang Feng", "hidden": false}, {"_id": "6a432d66763f63ca3757e870", "name": "Zijie Guo", "hidden": false}, {"_id": "6a432d66763f63ca3757e871", "name": "Haonan He", "hidden": false}, {"_id": "6a432d66763f63ca3757e872", "name": "Liang He", "hidden": false}, {"_id": "6a432d66763f63ca3757e873", "name": "Xiaohan He", "hidden": false}, {"_id": "6a432d66763f63ca3757e874", "name": "Shuyue Hu", "hidden": false}, {"_id": "6a432d66763f63ca3757e875", "name": "Yusong Hu", "hidden": false}, {"_id": "6a432d66763f63ca3757e876", "name": "Songtao Huang", "hidden": false}, {"_id": "6a432d66763f63ca3757e877", "name": "Yichen Jiang", "hidden": false}, {"_id": "6a432d66763f63ca3757e878", "name": "Hao Li", "hidden": false}, {"_id": "6a432d66763f63ca3757e879", "name": "Xin Li", "hidden": false}, {"_id": "6a432d66763f63ca3757e87a", "name": "Dahua Lin", "hidden": false}, {"_id": "6a432d66763f63ca3757e87b", "name": "Weihao Lin", "hidden": false}, {"_id": "6a432d66763f63ca3757e87c", "name": "Fenghua Ling", "hidden": false}, {"_id": "6a432d66763f63ca3757e87d", "name": "Dongrui Liu", "hidden": false}, {"_id": "6a432d66763f63ca3757e87e", "name": "Zhuo Liu", "hidden": false}, {"_id": "6a432d66763f63ca3757e87f", "name": "Runmin Ma", "hidden": false}, {"_id": "6a432d66763f63ca3757e880", "name": "Chunjiang Mu", "hidden": false}, {"_id": "6a432d66763f63ca3757e881", "name": "Haoyang Peng", "hidden": false}, {"_id": "6a432d66763f63ca3757e882", "name": "Tianshuo Peng", "hidden": false}, {"_id": "6a432d66763f63ca3757e883", "name": "Jinxin Shi", "hidden": false}, {"_id": "6a432d66763f63ca3757e884", "name": "Luohe Shi", "hidden": false}, {"_id": "6a432d66763f63ca3757e885", "name": "Boyuan Sun", "hidden": false}, {"_id": "6a432d66763f63ca3757e886", "name": "Zelin Tan", "hidden": false}, {"_id": "6a432d66763f63ca3757e887", "name": "Shengji Tang", "hidden": false}, {"_id": "6a432d66763f63ca3757e888", "name": "Qianyi Wang", "hidden": false}, {"_id": "6a432d66763f63ca3757e889", "name": "Yiming Wu", "hidden": false}, {"_id": "6a432d66763f63ca3757e88a", "name": "Yi Xie", "hidden": false}, {"_id": "6a432d66763f63ca3757e88b", "name": "Xiangchao Yan", "hidden": false}, {"_id": "6a432d66763f63ca3757e88c", "name": "Jingqi Ye", "hidden": false}, {"_id": "6a432d66763f63ca3757e88d", "name": "Peng Ye", "hidden": false}, {"_id": "6a432d66763f63ca3757e88e", "name": "Fangchen Yu", "hidden": false}, {"_id": "6a432d66763f63ca3757e88f", "name": "Jiakang Yuan", "hidden": false}, {"_id": "6a432d66763f63ca3757e890", "name": "Bihao Zhan", "hidden": false}, {"_id": "6a432d66763f63ca3757e891", "name": "Bo Zhang", "hidden": false}, {"_id": "6a432d66763f63ca3757e892", "name": "Chen Zhang", "hidden": false}, {"_id": "6a432d66763f63ca3757e893", "name": "Shufei Zhang", "hidden": false}, {"_id": "6a432d66763f63ca3757e894", "name": "Shuaiyu Zhang", "hidden": false}, {"_id": "6a432d66763f63ca3757e895", "name": "Wenlong Zhang", "hidden": false}, {"_id": "6a432d66763f63ca3757e896", "name": "Yiqun Zhang", "hidden": false}, {"_id": "6a432d66763f63ca3757e897", "name": "Junpeng Zhao", "hidden": false}, {"_id": "6a432d66763f63ca3757e898", "name": "Zhijie Zhong", "hidden": false}, {"_id": "6a432d66763f63ca3757e899", "name": "Bowen Zhou", "hidden": false}, {"_id": "6a432d66763f63ca3757e89a", "name": "Yuhao Zhou", "hidden": false}], "publishedAt": "2026-06-29T00:00:00.000Z", "submittedOnDailyAt": "2026-06-30T00:00:00.000Z", "title": "Scaling the Horizon, Not the Parameters: Reaching Trillion-Parameter Performance with a 35B Agent", "submittedOnDailyBy": {"_id": "667cf204268f6622dac71961", "avatarUrl": "/avatars/90e1928beb2a685e82e19758e4a6b7ae.svg", "isPro": false, "fullname": "shiyang", "user": "sY713", "type": "user", "name": "sY713"}, "summary": "We introduce Agents-A1, a 35B Mixture-of-Experts Agentic Model that reaches trillion-parameter-level performance by scaling the agent horizon. We investigate agent-horizon scaling from two perspectives: scaling long-horizon trajectories and scaling heterogeneous agent abilities. To support this goal, we build a long-horizon knowledge-action infrastructure that connects external knowledge, actions, observations, and verifier outcomes, producing agentic trajectories with an average length of 45K tokens. Based on this, we train Agents-A1 with a three-stage recipe. First, we perform full-domain supervised fine-tuning to align the base model with broad agentic behaviors. Second, we train domain-level teacher models to capture specialized expertise in each domain. Third, we propose a multi-teacher domain-routed on-policy distillation with salient vocabulary alignment to improve knowledge transfer efficiency across different domains, unifying six heterogeneous domains into one deployable student model. Agents-A1 achieves strong and broad performance for long-horizon agent benchmarks. Compared with 1T-parameter model such as Kimi-K2.6 and DeepSeek-V4-pro, Agents-A1 achieves leading results on SEAL-0 (56.4), IFBench (80.6), HiPhO (46.4), FrontierScience-Olympiad (79.0), and MolBench-Bind (56.8), and remains highly competitive on SciCode (44.3), HLE (47.6) and BrowseComp (75.5). We hope this work provides the community with a practical path for scaling the horizon using a 35B agent that can reach or match the performance of 1T models on long-horizon tasks.", "upvotes": 67, "discussionId": "6a432d66763f63ca3757e89b", "projectPage": "https://internscience.github.io/Agents-A1/", "githubRepo": "https://github.com/InternScience/Agents-A1", "githubRepoAddedBy": "user", "ai_summary": "Agents-A1, a 35B Mixture-of-Experts Agentic Model, achieves trillion-parameter-level performance through long-horizon trajectory scaling and heterogeneous agent ability scaling via a three-stage training approach involving supervised fine-tuning, domain-level teacher models, and multi-teacher distillation.", "ai_keywords": ["Mixture-of-Experts", "agentic model", "agent horizon", "long-horizon trajectories", "heterogeneous agent abilities", "knowledge-action infrastructure", "agentic trajectories", "supervised fine-tuning", "domain-level teacher models", "multi-teacher domain-routed on-policy distillation", "salient vocabulary alignment", "domain-routed training"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 68, "organization": {"_id": "690af7a885f71496ea396393", "name": "InternScience", "fullname": "Intern Science", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/65f2a4198404ac0e4c0f175f/XIPU4aCPBogXSrj6NrfLk.png"}, "summary_zh": "<ul>\n    <li>\u4ecb\u7ecd\u4e86Agents-A1\uff0c\u4e00\u4e2a35B\u7684\u6df7\u5408\u4e13\u5bb6\u667a\u80fd\u6a21\u578b\uff0c\u80fd\u591f\u5728\u957f\u65f6\u95f4\u4efb\u52a1\u4e2d\u8fbe\u5230\u4e07\u4ebf\u53c2\u6570\u7ea7\u522b\u7684\u6027\u80fd\u3002</li>\n    <li>\u7814\u7a76\u4e86\u5982\u4f55\u901a\u8fc7\u6269\u5c55\u4ee3\u7406\u7684\u89c6\u91ce\u6765\u63d0\u5347\u6a21\u578b\u7684\u80fd\u529b\uff0c\u5305\u62ec\u957f\u65f6\u95f4\u8def\u5f84\u548c\u4e0d\u540c\u4ee3\u7406\u80fd\u529b\u7684\u6269\u5c55\u3002</li>\n    <li>\u5efa\u7acb\u4e86\u4e00\u4e2a\u957f\u65f6\u95f4\u77e5\u8bc6-\u884c\u52a8\u57fa\u7840\u8bbe\u65bd\uff0c\u5e73\u5747\u751f\u621045K\u4e2a\u6807\u8bb0\u7684\u4ee3\u7406\u8f68\u8ff9\u3002</li>\n    <li>\u901a\u8fc7\u4e09\u9636\u6bb5\u7684\u65b9\u6cd5\u8bad\u7ec3Agents-A1\uff0c\u5305\u62ec\u5168\u9762\u7684\u76d1\u7763\u5fae\u8c03\u548c\u591a\u6559\u5e08\u6a21\u578b\u7684\u77e5\u8bc6\u8f6c\u79fb\u3002</li>\n    <li>\u5728\u591a\u4e2a\u957f\u65f6\u95f4\u4ee3\u7406\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u8868\u73b0\u4f18\u79c0\uff0c\u8d85\u8d8a\u4e86\u5176\u4ed61T\u53c2\u6570\u6a21\u578b\uff0c\u63d0\u4f9b\u4e86\u4e00\u79cd\u5b9e\u7528\u7684\u6269\u5c55\u8def\u5f84\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Agents-A1 is a new AI model with 35 billion parameters that performs as well as models with a trillion parameters by focusing on long-term planning.</li>\n    <li>The model improves performance by enhancing both its ability to plan for longer periods and by using different skills from various agents.</li>\n    <li>It uses a special system to connect knowledge, actions, and results, allowing it to generate lengthy and effective action plans.</li>\n    <li>Agents-A1 is trained in three stages, including fine-tuning the base model, training specialized models for different domains, and improving knowledge sharing across these domains.</li>\n    <li>It shows excellent results on various long-term tasks and benchmarks, outperforming some larger models while remaining competitive with others.</li>\n</ul>"}, "publishedAt": "2026-06-28T20:00:00.000Z", "title": "Scaling the Horizon, Not the Parameters: Reaching Trillion-Parameter Performance with a 35B Agent", "summary": "We introduce Agents-A1, a 35B Mixture-of-Experts Agentic Model that reaches trillion-parameter-level performance by scaling the agent horizon. We investigate agent-horizon scaling from two perspectives: scaling long-horizon trajectories and scaling heterogeneous agent abilities. To support this goal, we build a long-horizon knowledge-action infrastructure that connects external knowledge, actions, observations, and verifier outcomes, producing agentic trajectories with an average length of 45K tokens. Based on this, we train Agents-A1 with a three-stage recipe. First, we perform full-domain supervised fine-tuning to align the base model with broad agentic behaviors. Second, we train domain-level teacher models to capture specialized expertise in each domain. Third, we propose a multi-teacher domain-routed on-policy distillation with salient vocabulary alignment to improve knowledge transfer efficiency across different domains, unifying six heterogeneous domains into one deployable student model. Agents-A1 achieves strong and broad performance for long-horizon agent benchmarks. Compared with 1T-parameter model such as Kimi-K2.6 and DeepSeek-V4-pro, Agents-A1 achieves leading results on SEAL-0 (56.4), IFBench (80.6), HiPhO (46.4), FrontierScience-Olympiad (79.0), and MolBench-Bind (56.8), and remains highly competitive on SciCode (44.3), HLE (47.6) and BrowseComp (75.5). We hope this work provides the community with a practical path for scaling the horizon using a 35B agent that can reach or match the performance of 1T models on long-horizon tasks.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.30616.png", "numComments": 2, "submittedBy": {"_id": "667cf204268f6622dac71961", "avatarUrl": "/avatars/90e1928beb2a685e82e19758e4a6b7ae.svg", "fullname": "shiyang", "name": "sY713", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 1, "isUserFollowing": false}, "organization": {"_id": "690af7a885f71496ea396393", "name": "InternScience", "fullname": "Intern Science", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/65f2a4198404ac0e4c0f175f/XIPU4aCPBogXSrj6NrfLk.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.31315", "authors": [{"_id": "6a44786041f04ae4d7ad96f4", "name": "Hao Zhang", "hidden": false}, {"_id": "6a44786041f04ae4d7ad96f5", "name": "Yiming Hu", "hidden": false}, {"_id": "6a44786041f04ae4d7ad96f6", "name": "Yong Wang", "hidden": false}, {"_id": "6a44786041f04ae4d7ad96f7", "name": "Mingqiao Mo", "hidden": false}, {"_id": "6a44786041f04ae4d7ad96f8", "name": "Xin Xiao", "hidden": false}, {"_id": "6a44786041f04ae4d7ad96f9", "name": "Xiangxiang Chu", "hidden": false}], "publishedAt": "2026-06-30T00:00:00.000Z", "submittedOnDailyAt": "2026-07-01T00:00:00.000Z", "title": "BlockPilot: Instance-Adaptive Policy Learning for Diffusion-based Speculative Decoding", "submittedOnDailyBy": {"_id": "64d1dc5273174cecdffc97d3", "avatarUrl": "/avatars/6564e6b68fee9673f75b6366adf39a3b.svg", "isPro": false, "fullname": "Wang Yong", "user": "seashell11", "type": "user", "name": "seashell11"}, "summary": "Speculative decoding accelerates inference by using a lightweight draft model to generate candidate tokens in parallel, and are then verified by the target model, enabling lossless acceleration. Recently, diffusion-based speculative decoding further improves parallelism by generating multiple tokens per forward pass via block-level diffusion, achieving state-of-the-art (SOTA) performance. However, existing methods adopt a fixed inference block size and assume a uniform optimal decoding strategy across all inputs. In this paper, we show that this assumption is suboptimal, as the optimal block size varies across samples and plays a critical role in speculative decoding performance. Moreover, these values exhibit a clear local structure, concentrating around the training block size, which reduces the problem to a low-dimensional and structured decision space. Based on these insights, we propose BlockPilot, a sample-adaptive policy that predicts the optimal block size from the prefilling representation. Specifically, we formulate block size selection as a lightweight policy learning problem and propose an instance-adaptive decision mechanism that predicts the optimal block size based on the representation of the prefilling stage. The prediction is performed only once after prefilling, allowing for seamless integration. Extensive experiments demonstrate that our method is plug-and-play, introduces minimal overhead, and consistently improves efficiency, achieving an acceptance length of 5.92 and a 4.20times speedup on Qwen3-4B under temperature T=1.", "upvotes": 67, "discussionId": "6a44786041f04ae4d7ad96fa", "githubRepo": "https://github.com/AMAP-ML/BlockPilot", "githubRepoAddedBy": "user", "ai_summary": "Speculative decoding with adaptive block size selection improves inference efficiency by predicting optimal block sizes from prefilling representations, achieving significant speedup with minimal overhead.", "ai_keywords": ["speculative decoding", "draft model", "target model", "diffusion-based speculative decoding", "block-level diffusion", "inference block size", "prefilling representation", "policy learning", "instance-adaptive decision mechanism"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 56, "summary_zh": "<ul>\n    <li>\u63a8\u6d4b\u89e3\u7801\u901a\u8fc7\u4f7f\u7528\u8f7b\u91cf\u7ea7\u8349\u7a3f\u6a21\u578b\u5e76\u884c\u751f\u6210\u5019\u9009\u6807\u8bb0\uff0c\u52a0\u901f\u63a8\u7406\u8fc7\u7a0b\u3002</li>\n    <li>\u57fa\u4e8e\u6269\u6563\u7684\u63a8\u6d4b\u89e3\u7801\u8fdb\u4e00\u6b65\u63d0\u9ad8\u4e86\u5e76\u884c\u6027\uff0c\u901a\u8fc7\u5757\u7ea7\u6269\u6563\u6bcf\u6b21\u751f\u6210\u591a\u4e2a\u6807\u8bb0\u3002</li>\n    <li>\u73b0\u6709\u65b9\u6cd5\u4f7f\u7528\u56fa\u5b9a\u7684\u63a8\u7406\u5757\u5927\u5c0f\uff0c\u4f46\u4e0d\u540c\u6837\u672c\u7684\u6700\u4f73\u5757\u5927\u5c0f\u662f\u4e0d\u540c\u7684\u3002</li>\n    <li>\u63d0\u51fa\u4e86BlockPilot\uff0c\u8fd9\u662f\u4e00\u79cd\u6837\u672c\u81ea\u9002\u5e94\u7b56\u7565\uff0c\u6839\u636e\u9884\u586b\u5145\u8868\u793a\u9884\u6d4b\u6700\u4f73\u5757\u5927\u5c0f\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0c\u8be5\u65b9\u6cd5\u53ef\u65e0\u7f1d\u96c6\u6210\uff0c\u6548\u7387\u663e\u8457\u63d0\u5347\uff0cQwen3-4B\u6a21\u578b\u5728T=1\u65f6\u5b9e\u73b0\u4e864.20\u500d\u7684\u52a0\u901f\u3002 </li>\n</ul>", "summary_simple": "<ul>\n    <li>Speculative decoding speeds up model predictions by using a simple draft model to suggest possible next tokens, which are then checked by a more accurate target model.</li>\n    <li>Recent advancements in diffusion-based speculative decoding allow generating multiple tokens at once for better performance.</li>\n    <li>Current methods use a fixed block size for predictions, which isn't optimal since the best block size changes depending on the input.</li>\n    <li>The authors introduce BlockPilot, a new method that adapts the block size for each sample based on its initial representation, improving efficiency.</li>\n    <li>BlockPilot is easy to implement, adds little extra time to the process, and significantly enhances speed, achieving a 4.20 times speedup in certain tests.</li>\n</ul>"}, "publishedAt": "2026-06-29T20:00:00.000Z", "title": "BlockPilot: Instance-Adaptive Policy Learning for Diffusion-based Speculative Decoding", "summary": "Speculative decoding accelerates inference by using a lightweight draft model to generate candidate tokens in parallel, and are then verified by the target model, enabling lossless acceleration. Recently, diffusion-based speculative decoding further improves parallelism by generating multiple tokens per forward pass via block-level diffusion, achieving state-of-the-art (SOTA) performance. However, existing methods adopt a fixed inference block size and assume a uniform optimal decoding strategy across all inputs. In this paper, we show that this assumption is suboptimal, as the optimal block size varies across samples and plays a critical role in speculative decoding performance. Moreover, these values exhibit a clear local structure, concentrating around the training block size, which reduces the problem to a low-dimensional and structured decision space. Based on these insights, we propose BlockPilot, a sample-adaptive policy that predicts the optimal block size from the prefilling representation. Specifically, we formulate block size selection as a lightweight policy learning problem and propose an instance-adaptive decision mechanism that predicts the optimal block size based on the representation of the prefilling stage. The prediction is performed only once after prefilling, allowing for seamless integration. Extensive experiments demonstrate that our method is plug-and-play, introduces minimal overhead, and consistently improves efficiency, achieving an acceptance length of 5.92 and a 4.20times speedup on Qwen3-4B under temperature T=1.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.31315.png", "numComments": 1, "submittedBy": {"_id": "64d1dc5273174cecdffc97d3", "avatarUrl": "/avatars/6564e6b68fee9673f75b6366adf39a3b.svg", "fullname": "Wang Yong", "name": "seashell11", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "isUserFollowing": false}, "isAuthorParticipating": false}, {"paper": {"id": "2606.30410", "authors": [{"_id": "6a436c5c763f63ca3757eb04", "name": "Lennart Purucker", "hidden": false}, {"_id": "6a436c5c763f63ca3757eb05", "name": "Andrej Tschalzev", "hidden": false}, {"_id": "6a436c5c763f63ca3757eb06", "name": "Nick Erickson", "hidden": false}, {"_id": "6a436c5c763f63ca3757eb07", "name": "Gioia Blayer", "hidden": false}, {"_id": "6a436c5c763f63ca3757eb08", "name": "David Holzm\u00fcller", "hidden": false}, {"_id": "6a436c5c763f63ca3757eb09", "name": "Alan Arazi", "hidden": false}, {"_id": "6a436c5c763f63ca3757eb0a", "name": "Alexander Pfefferle", "hidden": false}, {"_id": "6a436c5c763f63ca3757eb0b", "name": "Mustafa Tajjar", "hidden": false}, {"_id": "6a436c5c763f63ca3757eb0c", "name": "Ga\u00ebl Varoquaux", "hidden": false}, {"_id": "6a436c5c763f63ca3757eb0d", "name": "Frank Hutter", "hidden": false}], "publishedAt": "2026-06-29T00:00:00.000Z", "submittedOnDailyAt": "2026-06-30T00:00:00.000Z", "title": "Beyond IID: How General Are Tabular Foundation Models, Really?", "submittedOnDailyBy": {"_id": "677d00ac70b9142c01cc90f9", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/677d00ac70b9142c01cc90f9/c2utzkEFwdUHPLN8-_AHb.png", "isPro": false, "fullname": "Lennart Purucker", "user": "LennartPurucker", "type": "user", "name": "LennartPurucker"}, "summary": "Foundation models for predictive machine learning on tabular data have recently gained significant traction in academia and industry. Research communities across disciplines are increasingly evaluating tabular foundation models on diverse datasets and tasks. However, these task- and discipline-specific evaluations remain largely inaccessible to model researchers because benchmark software and evaluation protocols are fragmented. As a result, model researchers rely on standard benchmarks, which are mostly defined for tasks where tabular foundation models already excel. The most challenging scenarios are excluded, limiting meaningful progress in the field by focusing on marginal improvements on IID data rather than on broader, more demanding challenges. To overcome this, we introduce BeyondArena, the first unified holistic benchmark for tabular data that supports diverse task types (IID, temporal, grouped), across sample size and feature dimensionality scales, with diverse feature types (with text, with high cardinality) from a broad range of disciplines. To enable unified benchmarking beyond standard benchmarks, we introduce Data Foundry, a Python framework and metadata schema for curating tabular datasets for predictive machine learning. Our results across 11 models and 142 curated datasets show that existing tabular foundation models excel on tiny- to medium-sized IID data, while traditional tree-based and deep learning models still dominate on non-IID, large, and high-dimensional datasets. BeyondArena guides model research for the most demanding challenges in tabular data, enabling progress towards truly foundational tabular models.", "upvotes": 36, "discussionId": "6a436c5d763f63ca3757eb0e", "projectPage": "https://tabarena.ai/", "ai_summary": "Tabular foundation models show varying performance across different data conditions, with traditional methods still outperforming newer approaches on complex, large-scale datasets.", "ai_keywords": ["tabular foundation models", "predictive machine learning", "benchmarking", "Data Foundry", "IID data", "non-IID data", "high-dimensional datasets", "tree-based models", "deep learning models"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "681759b3ea68a1d61ecf7cb2", "name": "TabArena", "fullname": "TabArena", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/677d00ac70b9142c01cc90f9/CnJrKydixYX6R10mHP1B0.png"}, "summary_zh": "<ul>\n    <li>\u57fa\u7840\u6a21\u578b\u5728\u8868\u683c\u6570\u636e\u7684\u9884\u6d4b\u673a\u5668\u5b66\u4e60\u4e2d\u8d8a\u6765\u8d8a\u53d7\u5230\u5173\u6ce8\uff0c\u5e7f\u6cdb\u5e94\u7528\u4e8e\u5b66\u672f\u548c\u5de5\u4e1a\u9886\u57df\u3002</li>\n    <li>\u76ee\u524d\u7684\u8bc4\u4f30\u65b9\u6cd5\u5206\u6563\uff0c\u6a21\u578b\u7814\u7a76\u8005\u96be\u4ee5\u83b7\u53d6\u7279\u5b9a\u4efb\u52a1\u7684\u8bc4\u4f30\u7ed3\u679c\uff0c\u9650\u5236\u4e86\u7814\u7a76\u8fdb\u5c55\u3002</li>\n    <li>\u5f15\u5165\u4e86BeyondArena\uff0c\u8fd9\u662f\u7b2c\u4e00\u4e2a\u7edf\u4e00\u7684\u8868\u683c\u6570\u636e\u57fa\u51c6\uff0c\u652f\u6301\u591a\u79cd\u4efb\u52a1\u7c7b\u578b\u548c\u7279\u5f81\u3002</li>\n    <li>\u63a8\u51fa\u4e86Data Foundry\uff0c\u4e00\u4e2aPython\u6846\u67b6\uff0c\u7528\u4e8e\u6574\u7406\u8868\u683c\u6570\u636e\u96c6\u4ee5\u8fdb\u884c\u9884\u6d4b\u673a\u5668\u5b66\u4e60\u3002</li>\n    <li>\u7814\u7a76\u7ed3\u679c\u8868\u660e\uff0c\u73b0\u6709\u6a21\u578b\u5728\u5c0f\u5230\u4e2d\u7b49\u89c4\u6a21\u7684IID\u6570\u636e\u4e0a\u8868\u73b0\u4f18\u79c0\uff0c\u4f46\u5728\u975eIID\u3001\u5927\u578b\u548c\u9ad8\u7ef4\u6570\u636e\u4e0a\uff0c\u4f20\u7edf\u6a21\u578b\u4f9d\u7136\u5360\u636e\u4f18\u52bf\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Foundation models for predictive machine learning on tabular data are becoming popular in both academia and industry.</li>\n    <li>Current evaluations of tabular models are scattered and hard to access, which limits researchers' ability to test models on challenging scenarios.</li>\n    <li>The standard benchmarks focus on tasks where tabular models perform well, ignoring more difficult cases.</li>\n    <li>BeyondArena is introduced as a new benchmark that covers various types of tasks and datasets, making it easier to evaluate model performance.</li>\n    <li>A Python framework called Data Foundry is also created to help curate diverse tabular datasets for better benchmarking and research progress.</li>\n</ul>"}, "publishedAt": "2026-06-28T20:00:00.000Z", "title": "Beyond IID: How General Are Tabular Foundation Models, Really?", "summary": "Foundation models for predictive machine learning on tabular data have recently gained significant traction in academia and industry. Research communities across disciplines are increasingly evaluating tabular foundation models on diverse datasets and tasks. However, these task- and discipline-specific evaluations remain largely inaccessible to model researchers because benchmark software and evaluation protocols are fragmented. As a result, model researchers rely on standard benchmarks, which are mostly defined for tasks where tabular foundation models already excel. The most challenging scenarios are excluded, limiting meaningful progress in the field by focusing on marginal improvements on IID data rather than on broader, more demanding challenges. To overcome this, we introduce BeyondArena, the first unified holistic benchmark for tabular data that supports diverse task types (IID, temporal, grouped), across sample size and feature dimensionality scales, with diverse feature types (with text, with high cardinality) from a broad range of disciplines. To enable unified benchmarking beyond standard benchmarks, we introduce Data Foundry, a Python framework and metadata schema for curating tabular datasets for predictive machine learning. Our results across 11 models and 142 curated datasets show that existing tabular foundation models excel on tiny- to medium-sized IID data, while traditional tree-based and deep learning models still dominate on non-IID, large, and high-dimensional datasets. BeyondArena guides model research for the most demanding challenges in tabular data, enabling progress towards truly foundational tabular models.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.30410.png", "numComments": 2, "submittedBy": {"_id": "677d00ac70b9142c01cc90f9", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/677d00ac70b9142c01cc90f9/c2utzkEFwdUHPLN8-_AHb.png", "fullname": "Lennart Purucker", "name": "LennartPurucker", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 5, "isUserFollowing": false}, "organization": {"_id": "681759b3ea68a1d61ecf7cb2", "name": "TabArena", "fullname": "TabArena", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/677d00ac70b9142c01cc90f9/CnJrKydixYX6R10mHP1B0.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.29513", "authors": [{"_id": "6a436bcd763f63ca3757eafb", "user": {"_id": "6884f5827d771707a5cde4ca", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/no-auth/mntXoTKke2rmgCR70IvJr.png", "isPro": false, "fullname": "Mijin Yoo", "user": "mynameisyoomimi", "type": "user", "name": "mynameisyoomimi"}, "name": "Mijin Yoo", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T08:46:14.563Z", "hidden": false}, {"_id": "6a436bcd763f63ca3757eafc", "name": "In Cho", "hidden": false}, {"_id": "6a436bcd763f63ca3757eafd", "name": "Subin Jeon", "hidden": false}, {"_id": "6a436bcd763f63ca3757eafe", "name": "Jiwoo Lee", "hidden": false}, {"_id": "6a436bcd763f63ca3757eaff", "name": "Eunbyung Park", "hidden": false}, {"_id": "6a436bcd763f63ca3757eb00", "name": "Seon Joo Kim", "hidden": false}], "publishedAt": "2026-06-28T00:00:00.000Z", "submittedOnDailyAt": "2026-07-01T00:00:00.000Z", "title": "Scenes as Objects, Not Primitives: Instance-Structured 3D Tokenization from Unposed Views", "submittedOnDailyBy": {"_id": "6884f5827d771707a5cde4ca", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/no-auth/mntXoTKke2rmgCR70IvJr.png", "isPro": false, "fullname": "Mijin Yoo", "user": "mynameisyoomimi", "type": "user", "name": "mynameisyoomimi"}, "summary": "A 3D scene is understood through its objects, not the primitives that compose them. Yet feed-forward reconstruction methods output dense, unstructured sets of points or Gaussians, leaving object-level structure to be recovered after the fact. We propose a feed-forward framework that decomposes a scene into instance-structured 3D token groups directly from unposed multi-view images -- compact object-centric units from which reconstruction, segmentation, and manipulation all follow. Each token group pairs an instance token capturing entity-level identity with anchor tokens that encode local geometry and appearance, which are decoded into a set of 3D Gaussians. This two-level factorization decouples object identity from local appearance, making object instances a native interface of the representation rather than a derived product. The token groups are learned through differentiable rendering with joint reconstruction and segmentation supervision, requiring no 3D annotations. Our feed-forward model surpasses per-scene optimization baselines in class-agnostic instance segmentation while remaining competitive in novel view synthesis. Beyond these metrics, the same token groups directly unlock instance-level scene editing -- removing, translating, or inserting objects by operating on their groups -- as well as efficient open-vocabulary 3D instance retrieval, where retrieval complexity scales with the number of instances rather than primitives.", "upvotes": 34, "discussionId": "6a436bcd763f63ca3757eb01", "projectPage": "https://yoomimi.github.io/instok3d", "ai_summary": "A feed-forward framework decomposes 3D scenes into instance-structured token groups from multi-view images, enabling direct object-level reconstruction, segmentation, and manipulation without 3D annotations.", "ai_keywords": ["feed-forward framework", "3D scene decomposition", "instance-structured token groups", "unposed multi-view images", "3D Gaussians", "differentiable rendering", "joint reconstruction and segmentation supervision", "class-agnostic instance segmentation", "novel view synthesis", "instance-level scene editing", "open-vocabulary 3D instance retrieval"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "summary_zh": "<ul>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u4e00\u79cd\u65b0\u65b9\u6cd5\uff0c\u53ef\u4ee5\u4ece\u591a\u4e2a\u89c6\u89d2\u7684\u56fe\u50cf\u4e2d\u76f4\u63a5\u5c063D\u573a\u666f\u5206\u89e3\u6210\u7ed3\u6784\u5316\u7684\u5bf9\u8c61\u7ec4\u3002</li>\n    <li>\u6bcf\u4e2a\u5bf9\u8c61\u7ec4\u5305\u542b\u4e00\u4e2a\u5b9e\u4f8b\u6807\u8bb0\u548c\u591a\u4e2a\u951a\u6807\u8bb0\uff0c\u4ee5\u4fbf\u66f4\u597d\u5730\u6355\u6349\u7269\u4f53\u7684\u8eab\u4efd\u3001\u51e0\u4f55\u5f62\u72b6\u548c\u5916\u89c2\u3002</li>\n    <li>\u8fd9\u79cd\u65b9\u6cd5\u4e0e\u4f20\u7edf\u7684\u70b9\u4e91\u65b9\u6cd5\u4e0d\u540c\uff0c\u53ef\u4ee5\u5728\u4e0d\u9700\u89813D\u6807\u6ce8\u7684\u60c5\u51b5\u4e0b\u8fdb\u884c\u91cd\u5efa\u548c\u5206\u5272\u3002</li>\n    <li>\u6211\u4eec\u7684\u6a21\u578b\u5728\u5b9e\u4f8b\u5206\u5272\u548c\u65b0\u89c6\u56fe\u5408\u6210\u65b9\u9762\u8868\u73b0\u4f18\u4e8e\u73b0\u6709\u7684\u4f18\u5316\u57fa\u7ebf\u3002</li>\n    <li>\u8fd9\u79cd\u5bf9\u8c61\u7ec4\u8fd8\u652f\u6301\u5b9e\u4f8b\u7ea7\u522b\u7684\u573a\u666f\u7f16\u8f91\u548c\u9ad8\u6548\u76843D\u5b9e\u4f8b\u68c0\u7d22\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>The framework analyzes a 3D scene by breaking it down into groups of object tokens from unposed images.</li>\n    <li>Each token group consists of an identity token for the object and anchor tokens for its shape and appearance.</li>\n    <li>This approach allows for better reconstruction, segmentation, and manipulation of 3D objects without needing 3D data upfront.</li>\n    <li>The model outperforms traditional methods in instance segmentation and is competitive in generating new views of scenes.</li>\n    <li>It enables easy scene editing and efficient retrieval of 3D objects based on their instances rather than basic shapes.</li>\n</ul>"}, "publishedAt": "2026-06-27T20:00:00.000Z", "title": "Scenes as Objects, Not Primitives: Instance-Structured 3D Tokenization from Unposed Views", "summary": "A 3D scene is understood through its objects, not the primitives that compose them. Yet feed-forward reconstruction methods output dense, unstructured sets of points or Gaussians, leaving object-level structure to be recovered after the fact. We propose a feed-forward framework that decomposes a scene into instance-structured 3D token groups directly from unposed multi-view images -- compact object-centric units from which reconstruction, segmentation, and manipulation all follow. Each token group pairs an instance token capturing entity-level identity with anchor tokens that encode local geometry and appearance, which are decoded into a set of 3D Gaussians. This two-level factorization decouples object identity from local appearance, making object instances a native interface of the representation rather than a derived product. The token groups are learned through differentiable rendering with joint reconstruction and segmentation supervision, requiring no 3D annotations. Our feed-forward model surpasses per-scene optimization baselines in class-agnostic instance segmentation while remaining competitive in novel view synthesis. Beyond these metrics, the same token groups directly unlock instance-level scene editing -- removing, translating, or inserting objects by operating on their groups -- as well as efficient open-vocabulary 3D instance retrieval, where retrieval complexity scales with the number of instances rather than primitives.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.29513.png", "numComments": 1, "submittedBy": {"_id": "6884f5827d771707a5cde4ca", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/no-auth/mntXoTKke2rmgCR70IvJr.png", "fullname": "Mijin Yoo", "name": "mynameisyoomimi", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2606.32039", "authors": [{"_id": "6a44853741f04ae4d7ad9795", "user": {"_id": "6a1aecae7401763b13902d21", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6a1aecae7401763b13902d21/Xnvn-it64TD036FWorAWQ.webp", "isPro": false, "fullname": "Bin Lin", "user": "BinLin203", "type": "user", "name": "BinLin203"}, "name": "Bin Lin", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T08:44:26.823Z", "hidden": false}, {"_id": "6a44853741f04ae4d7ad9796", "name": "Zheyuan Liu", "hidden": false}, {"_id": "6a44853741f04ae4d7ad9797", "name": "Chenguo Lin", "hidden": false}, {"_id": "6a44853741f04ae4d7ad9798", "name": "Sixiang Chen", "hidden": false}, {"_id": "6a44853741f04ae4d7ad9799", "name": "Yunyang Ge", "hidden": false}, {"_id": "6a44853741f04ae4d7ad979a", "user": {"_id": "64ecb174f22081b4ac7ca397", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64ecb174f22081b4ac7ca397/PiAPtD_rbuhGOqfE6ZSIu.jpeg", "isPro": true, "fullname": "Yunlong Lin", "user": "LYL1015", "type": "user", "name": "LYL1015"}, "name": "Yunlong Lin", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T08:44:29.146Z", "hidden": false}, {"_id": "6a44853741f04ae4d7ad979b", "name": "Jianwei Zhang", "hidden": false}, {"_id": "6a44853741f04ae4d7ad979c", "name": "Miles Yang", "hidden": false}, {"_id": "6a44853741f04ae4d7ad979d", "name": "Zhao Zhong", "hidden": false}, {"_id": "6a44853741f04ae4d7ad979e", "name": "Liefeng Bo", "hidden": false}, {"_id": "6a44853741f04ae4d7ad979f", "name": "Li Yuan", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6367a8175bb06007ea099b8f/BltnPpNkiBJkSwGODiUW2.png", "https://cdn-uploads.huggingface.co/production/uploads/6367a8175bb06007ea099b8f/0dH0yutHkngaZzz2KiBOt.png", "https://cdn-uploads.huggingface.co/production/uploads/6367a8175bb06007ea099b8f/Bv7lS-Lvhgo2l5g_bKl_9.png", "https://cdn-uploads.huggingface.co/production/uploads/6367a8175bb06007ea099b8f/jVvEEHiYKn3YK02V7sQ3m.png", "https://cdn-uploads.huggingface.co/production/uploads/6367a8175bb06007ea099b8f/Mg0_qxIhdUHHVWh7hkU0c.png"], "publishedAt": "2026-06-30T00:00:00.000Z", "submittedOnDailyAt": "2026-07-01T00:00:00.000Z", "title": "GEAR: Guided End-to-End AutoRegression for Image Synthesis", "submittedOnDailyBy": {"_id": "6367a8175bb06007ea099b8f", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6367a8175bb06007ea099b8f/IjG7HyWyWRlVt_XwRbxRW.jpeg", "isPro": false, "fullname": "linbin", "user": "LanguageBind", "type": "user", "name": "LanguageBind"}, "summary": "Visual generative models are typically trained in two stages. A tokenizer is first trained for reconstruction and then frozen, after which a generator is trained on its discrete indices or continuous latents. This decoupling leaves the tokenizer unaware of what the generator finds easy to model. We present GEAR (Guided End-to-end AutoRegression), which trains a vector-quantized (VQ) tokenizer and an autoregressive (AR) generator jointly and end-to-end, guided by representation alignment. The key obstacle is that the VQ index fed to the AR model is non-differentiable, so gradients cannot reach the tokenizer, and a straight-through estimator collapses. GEAR resolves this with a dual read-out of the codebook assignment. A hard, one-hot branch trains the AR with next-token prediction, while a differentiable soft branch carries a representation-alignment loss that flows back to guide only the tokenizer. The AR model thereby steers its tokenizer toward an index distribution it can predict more easily. This shifts the alignment burden from the tokenizer to the AR: the tokenizer's own features become less DINOv2-like while the AR's become more so, the opposite of diffusion-side recipes that make the latent itself semantic. GEAR speeds up ImageNet gFID convergence by up to 10x relative to the strong LlamaGen-REPA baseline, learns markedly better patch-level and spatially-coherent features, and generalizes across quantizers (VQVAE, LFQ, IBQ) and to text-to-image generation.", "upvotes": 28, "discussionId": "6a44853741f04ae4d7ad97a0", "projectPage": "https://linb203.github.io/gear", "githubRepo": "https://github.com/Tencent-Hunyuan/GEAR", "githubRepoAddedBy": "user", "ai_summary": "GEAR trains a vector-quantized tokenizer and autoregressive generator jointly end-to-end using representation alignment, overcoming non-differentiability issues through a dual read-out approach that improves convergence speed and feature quality.", "ai_keywords": ["vector-quantized", "autoregressive", "representation alignment", "straight-through estimator", "codebook assignment", "next-token prediction", "DINOv2", "ImageNet", "gFID", "VQVAE", "LFQ", "IBQ", "text-to-image generation"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 47, "organization": {"_id": "6645f953c39288df638dbdd5", "name": "Tencent-Hunyuan", "fullname": "Tencent Hunyuan", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/62d22496c58f969c152bcefd/woKSjt2wXvBNKussyYPsa.png"}, "summary_zh": "<ul>\n    <li>\u89c6\u89c9\u751f\u6210\u6a21\u578b\u901a\u5e38\u5206\u4e3a\u4e24\u4e2a\u9636\u6bb5\u8bad\u7ec3\uff0c\u5148\u8bad\u7ec3\u4e00\u4e2a\u5206\u8bcd\u5668\uff0c\u7136\u540e\u8bad\u7ec3\u751f\u6210\u5668\u3002</li>\n    <li>GEAR\u6a21\u578b\u8054\u5408\u8bad\u7ec3\u77e2\u91cf\u91cf\u5316\u5206\u8bcd\u5668\u548c\u81ea\u56de\u5f52\u751f\u6210\u5668\uff0c\u4ee5\u63d0\u9ad8\u8868\u793a\u5bf9\u9f50\u3002</li>\n    <li>GEAR\u89e3\u51b3\u4e86\u5206\u8bcd\u5668\u4e0e\u751f\u6210\u5668\u4e4b\u95f4\u7684\u68af\u5ea6\u4f20\u9012\u95ee\u9898\uff0c\u901a\u8fc7\u53cc\u91cd\u8bfb\u53d6\u4ee3\u7801\u7c3f\u5206\u914d\u3002</li>\n    <li>\u8be5\u6a21\u578b\u52a0\u901f\u4e86ImageNet gFID\u6536\u655b\u901f\u5ea6\uff0c\u63d0\u5347\u4e86\u7279\u5f81\u5b66\u4e60\u6548\u679c\u3002</li>\n    <li>GEAR\u80fd\u591f\u8de8\u4e0d\u540c\u91cf\u5316\u5668\u548c\u6587\u672c\u5230\u56fe\u50cf\u751f\u6210\u8fdb\u884c\u6cdb\u5316\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Visual generative models usually train in two steps: first a tokenizer, then a generator, but they don't work together well.</li>\n    <li>GEAR is a new method that trains both the tokenizer and generator at the same time, improving their cooperation.</li>\n    <li>GEAR uses a special approach to handle a challenge where the tokenizer's output can't directly help the generator learn.</li>\n    <li>This method helps the generator guide the tokenizer to better predict what it needs, making the whole model more effective.</li>\n    <li>GEAR is faster than previous methods and produces better features, working well across different types of models and tasks.</li>\n</ul>"}, "publishedAt": "2026-06-29T20:00:00.000Z", "title": "GEAR: Guided End-to-End AutoRegression for Image Synthesis", "summary": "Visual generative models are typically trained in two stages. A tokenizer is first trained for reconstruction and then frozen, after which a generator is trained on its discrete indices or continuous latents. This decoupling leaves the tokenizer unaware of what the generator finds easy to model. We present GEAR (Guided End-to-end AutoRegression), which trains a vector-quantized (VQ) tokenizer and an autoregressive (AR) generator jointly and end-to-end, guided by representation alignment. The key obstacle is that the VQ index fed to the AR model is non-differentiable, so gradients cannot reach the tokenizer, and a straight-through estimator collapses. GEAR resolves this with a dual read-out of the codebook assignment. A hard, one-hot branch trains the AR with next-token prediction, while a differentiable soft branch carries a representation-alignment loss that flows back to guide only the tokenizer. The AR model thereby steers its tokenizer toward an index distribution it can predict more easily. This shifts the alignment burden from the tokenizer to the AR: the tokenizer's own features become less DINOv2-like while the AR's become more so, the opposite of diffusion-side recipes that make the latent itself semantic. GEAR speeds up ImageNet gFID convergence by up to 10x relative to the strong LlamaGen-REPA baseline, learns markedly better patch-level and spatially-coherent features, and generalizes across quantizers (VQVAE, LFQ, IBQ) and to text-to-image generation.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6367a8175bb06007ea099b8f/BltnPpNkiBJkSwGODiUW2.png", "https://cdn-uploads.huggingface.co/production/uploads/6367a8175bb06007ea099b8f/0dH0yutHkngaZzz2KiBOt.png", "https://cdn-uploads.huggingface.co/production/uploads/6367a8175bb06007ea099b8f/Bv7lS-Lvhgo2l5g_bKl_9.png", "https://cdn-uploads.huggingface.co/production/uploads/6367a8175bb06007ea099b8f/jVvEEHiYKn3YK02V7sQ3m.png", "https://cdn-uploads.huggingface.co/production/uploads/6367a8175bb06007ea099b8f/Mg0_qxIhdUHHVWh7hkU0c.png"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.32039.png", "numComments": 7, "submittedBy": {"_id": "6367a8175bb06007ea099b8f", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6367a8175bb06007ea099b8f/IjG7HyWyWRlVt_XwRbxRW.jpeg", "fullname": "linbin", "name": "LanguageBind", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 207, "isUserFollowing": false}, "organization": {"_id": "6645f953c39288df638dbdd5", "name": "Tencent-Hunyuan", "fullname": "Tencent Hunyuan", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/62d22496c58f969c152bcefd/woKSjt2wXvBNKussyYPsa.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.29082", "authors": [{"_id": "6a432a3a763f63ca3757e83c", "user": {"_id": "6434b6619bd5a84b5dcfa4de", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6434b6619bd5a84b5dcfa4de/h8Q6kPNjFNc03wmdboHzq.jpeg", "isPro": true, "fullname": "Young-Jun Lee", "user": "passing2961", "type": "user", "name": "passing2961"}, "name": "Young-Jun Lee", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T13:54:14.803Z", "hidden": false}, {"_id": "6a432a3a763f63ca3757e83d", "name": "Seungone Kim", "hidden": false}, {"_id": "6a432a3a763f63ca3757e83e", "name": "Minki Kang", "hidden": false}, {"_id": "6a432a3a763f63ca3757e83f", "user": {"_id": "6054b4106158e94e71944d25", "avatarUrl": "/avatars/5d0d61f01c2a7587366508053563f723.svg", "isPro": false, "fullname": "Alistair Cheong", "user": "cheongalc", "type": "user", "name": "cheongalc"}, "name": "Alistair Cheong Liang Chuen", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T09:50:03.762Z", "hidden": false}, {"_id": "6a432a3a763f63ca3757e840", "name": "Zerui Chen", "hidden": false}, {"_id": "6a432a3a763f63ca3757e841", "name": "Seungho Han", "hidden": false}, {"_id": "6a432a3a763f63ca3757e842", "name": "Taehee Jung", "hidden": false}, {"_id": "6a432a3a763f63ca3757e843", "name": "Dongyeop Kang", "hidden": false}], "publishedAt": "2026-06-27T00:00:00.000Z", "submittedOnDailyAt": "2026-07-01T00:00:00.000Z", "title": "Evolution Fine-Tuning: Learning to Discover Across 371 Optimization Tasks", "submittedOnDailyBy": {"_id": "6434b6619bd5a84b5dcfa4de", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6434b6619bd5a84b5dcfa4de/h8Q6kPNjFNc03wmdboHzq.jpeg", "isPro": true, "fullname": "Young-Jun Lee", "user": "passing2961", "type": "user", "name": "passing2961"}, "summary": "Would experience designing faster GPU kernels also help close in on a long-standing open mathematical conjecture? Large Language Models (LLMs) integrated into evolutionary search have recently produced state-of-the-art solutions on optimization tasks, including open mathematical conjectures, GPU kernel design, scientific law discovery, and combinatorial puzzles. To achieve this, prior work applied search scaffolds to one target task at a time, so every new problem is approached from scratch and the experience accumulated during search is discarded once the model finishes its attempt. This leaves the capability of iteratively evolving a solution (e.g., knowing which part to mutate and how, deciding when to backtrack) entirely in the scaffold rather than in the model itself. Whether the model itself could acquire this capability and reuse it across different tasks has been largely unexamined. To address this, we introduce Evolution Fine-Tuning (EFT), a mid-training paradigm that teaches LLMs to evolve solutions across tasks by converting evolutionary search trajectories into supervision. We construct Finch Collection, a 156K-trajectory dataset spanning 10 domains and 371 optimization tasks, and fine-tune open-source LLMs from 2B to 9B parameters. Empirically, EFT confers cross-task generalization: across 22 held-out tasks, our models surpass their base counterparts by 10.22% on average. Furthermore, when paired with test-time RL, our model matches state-of-the-art performance on two circle-packing tasks and outperforms its base-model counterpart on the Erd\u0151s minimum-overlap problem. EFT thus serves as a \"practice phase\" for general-purpose discovery agents that do not solve new problems from scratch.", "upvotes": 23, "discussionId": "6a432a3a763f63ca3757e844", "projectPage": "https://open-galapagos.github.io/evolution_finetuning/", "githubRepo": "https://github.com/Open-Galapagos/evolution-fine-tuning", "githubRepoAddedBy": "user", "ai_summary": "Evolutionary fine-tuning enables large language models to develop cross-task problem-solving capabilities by learning from search trajectories, demonstrating improved performance on mathematical conjectures and optimization tasks.", "ai_keywords": ["evolutionary search", "large language models", "optimization tasks", "mathematical conjectures", "evolutionary fine-tuning", "search trajectories", "cross-task generalization", "reinforcement learning", "test-time RL", "trajectory supervision"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 10, "organization": {"_id": "643536750b30bd434ea1f1c3", "name": "minnesotanlp", "fullname": "Minnesota NLP", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/61e0c5053a1781f66b4e9aed/YHpZgv9x3v9lLYnXyOWi_.png"}, "summary_zh": "<ul>\n    <li>\u7814\u7a76\u63a2\u8ba8\u4e86GPU\u5185\u6838\u8bbe\u8ba1\u7ecf\u9a8c\u662f\u5426\u80fd\u5e2e\u52a9\u89e3\u51b3\u957f\u671f\u672a\u89e3\u7684\u6570\u5b66\u731c\u60f3\u3002</li>\n    <li>\u5927\u578b\u8bed\u8a00\u6a21\u578b\uff08LLMs\uff09\u4e0e\u8fdb\u5316\u641c\u7d22\u7ed3\u5408\uff0c\u5728\u4f18\u5316\u4efb\u52a1\u4e0a\u53d6\u5f97\u4e86\u6700\u4f73\u89e3\u51b3\u65b9\u6848\u3002</li>\n    <li>\u4ee5\u5f80\u65b9\u6cd5\u5728\u6bcf\u4e2a\u76ee\u6807\u4efb\u52a1\u4e0a\u5355\u72ec\u8fdb\u884c\u641c\u7d22\uff0c\u65e0\u6cd5\u7d2f\u8ba1\u641c\u7d22\u7ecf\u9a8c\u3002</li>\n    <li>\u63d0\u51fa\u4e86\u8fdb\u5316\u5fae\u8c03\uff08EFT\uff09\u65b9\u6cd5\uff0c\u6559\u4f1aLLMs\u5728\u4e0d\u540c\u4efb\u52a1\u4e2d\u6f14\u53d8\u89e3\u51b3\u65b9\u6848\u3002</li>\n    <li>\u5b9e\u9a8c\u7ed3\u679c\u663e\u793a\uff0cEFT\u63d0\u9ad8\u4e86\u6a21\u578b\u5728\u591a\u4e2a\u4efb\u52a1\u4e0a\u7684\u8868\u73b0\uff0c\u7279\u522b\u662f\u5728\u7279\u5b9a\u95ee\u9898\u4e0a\u8d85\u8fc7\u4e86\u57fa\u7840\u6a21\u578b\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Experience in designing faster GPU kernels may assist in solving a longstanding mathematical problem.</li>\n    <li>Large Language Models (LLMs) are being used with evolutionary search techniques to tackle various optimization tasks, including mathematical conjectures.</li>\n    <li>Previous methods treated each problem separately, losing any learned experience after each attempt.</li>\n    <li>Evolution Fine-Tuning (EFT) is introduced as a way to help LLMs learn from previous tasks and improve across different problems.</li>\n    <li>Using a dataset with 156,000 search trajectories, EFT shows improved performance across multiple tasks, surpassing base models by an average of 10.22%.</li>\n</ul>"}, "publishedAt": "2026-06-26T20:00:00.000Z", "title": "Evolution Fine-Tuning: Learning to Discover Across 371 Optimization Tasks", "summary": "Would experience designing faster GPU kernels also help close in on a long-standing open mathematical conjecture? Large Language Models (LLMs) integrated into evolutionary search have recently produced state-of-the-art solutions on optimization tasks, including open mathematical conjectures, GPU kernel design, scientific law discovery, and combinatorial puzzles. To achieve this, prior work applied search scaffolds to one target task at a time, so every new problem is approached from scratch and the experience accumulated during search is discarded once the model finishes its attempt. This leaves the capability of iteratively evolving a solution (e.g., knowing which part to mutate and how, deciding when to backtrack) entirely in the scaffold rather than in the model itself. Whether the model itself could acquire this capability and reuse it across different tasks has been largely unexamined. To address this, we introduce Evolution Fine-Tuning (EFT), a mid-training paradigm that teaches LLMs to evolve solutions across tasks by converting evolutionary search trajectories into supervision. We construct Finch Collection, a 156K-trajectory dataset spanning 10 domains and 371 optimization tasks, and fine-tune open-source LLMs from 2B to 9B parameters. Empirically, EFT confers cross-task generalization: across 22 held-out tasks, our models surpass their base counterparts by 10.22% on average. Furthermore, when paired with test-time RL, our model matches state-of-the-art performance on two circle-packing tasks and outperforms its base-model counterpart on the Erd\u0151s minimum-overlap problem. EFT thus serves as a \"practice phase\" for general-purpose discovery agents that do not solve new problems from scratch.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.29082.png", "numComments": 1, "submittedBy": {"_id": "6434b6619bd5a84b5dcfa4de", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6434b6619bd5a84b5dcfa4de/h8Q6kPNjFNc03wmdboHzq.jpeg", "fullname": "Young-Jun Lee", "name": "passing2961", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 15, "isUserFollowing": false}, "organization": {"_id": "643536750b30bd434ea1f1c3", "name": "minnesotanlp", "fullname": "Minnesota NLP", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/61e0c5053a1781f66b4e9aed/YHpZgv9x3v9lLYnXyOWi_.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.29215", "authors": [{"_id": "6a449b8341f04ae4d7ad9831", "name": "Yijie Jin", "hidden": false}, {"_id": "6a449b8341f04ae4d7ad9832", "name": "Jiajun Xu", "hidden": false}, {"_id": "6a449b8341f04ae4d7ad9833", "name": "Yuxuan Liu", "hidden": false}, {"_id": "6a449b8341f04ae4d7ad9834", "name": "Chenkai Xu", "hidden": false}, {"_id": "6a449b8341f04ae4d7ad9835", "name": "Yi Tu", "hidden": false}, {"_id": "6a449b8341f04ae4d7ad9836", "name": "Jiajun Li", "hidden": false}, {"_id": "6a449b8341f04ae4d7ad9837", "name": "Dandan Tu", "hidden": false}, {"_id": "6a449b8341f04ae4d7ad9838", "name": "Xiaohui Yan", "hidden": false}, {"_id": "6a449b8341f04ae4d7ad9839", "name": "Kai Yu", "hidden": false}, {"_id": "6a449b8341f04ae4d7ad983a", "name": "Pengfei Liu", "hidden": false}, {"_id": "6a449b8341f04ae4d7ad983b", "name": "Zhijie Deng", "hidden": false}], "publishedAt": "2026-06-30T00:00:00.000Z", "submittedOnDailyAt": "2026-07-01T00:00:00.000Z", "title": "Multi-Block Diffusion Language Models", "submittedOnDailyBy": {"_id": "66d05337e62d6bbf50186c2f", "avatarUrl": "/avatars/f5be15e754f0fbbb37d2cc5ea417f729.svg", "isPro": false, "fullname": "Yijie Jin", "user": "DrewJin0827", "type": "user", "name": "DrewJin0827"}, "summary": "Block Diffusion Language Models (BD-LMs) improve diffusion-based text generation with KV caching and flexible-length generation. A natural next step is to extend them from Single-Block Diffusion (SingleBD) to Multi-Block Diffusion (MultiBD), where a running-set of consecutive blocks is decoded concurrently for inter-block parallelism. However, existing BD-LMs are mostly trained under teacher forcing, where the model observes only one noisy block conditioned on a clean prefix. While the recent diffusion forcing strategy introduces visibility among multiple noisy blocks, its training states still differ from MultiBD inference, where decoding operates on a bounded running-set with heterogeneous slot-wise noise patterns. To bridge this gap, we propose Multi-Block Diffusion Language Models (MBD-LMs), obtained by post-training BD-LMs with Multi-block Teacher Forcing (MultiTF). MultiTF integrates teacher forcing and diffusion forcing by training on bounded noise-groups conditioned on clean prefixes, with randomized noise-schedulers that better match MultiBD inference states. To make MultiBD practically executable, we further introduce an optimized decoding algorithm based on the Block Buffer mechanism that preserves prefix-cache reuse, keeps input shapes static, and translates increased decoding parallelism into wall-clock acceleration. Empirically, MBD-LLaDA2-Mini increases average Tokens Per Forward pass (TPF) from 3.47 to 6.19 and improves average accuracy from 79.95% to 81.03%; when combined with DMax, MBD-LLaDA2-Mini-DMax reaches an average TPF of 9.34 with only a 1.02% accuracy drop on math and code benchmarks.", "upvotes": 22, "discussionId": "6a449b8441f04ae4d7ad983c", "projectPage": "https://sjtu-deng-lab.github.io/mbd-lms", "githubRepo": "https://github.com/SJTU-DENG-Lab/mbd-lms", "githubRepoAddedBy": "user", "ai_summary": "Multi-Block Diffusion Language Models extend single-block diffusion to concurrent block decoding with improved training strategies and optimized decoding algorithms.", "ai_keywords": ["Block Diffusion Language Models", "Multi-Block Diffusion", "teacher forcing", "diffusion forcing", "Multi-block Teacher Forcing", "noise-schedulers", "Block Buffer mechanism", "Tokens Per Forward pass", "diffusion-based text generation", "inter-block parallelism", "prefix-cache reuse", "static input shapes", "wall-clock acceleration"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 20, "organization": {"_id": "673d5fe8d031224e947dc235", "name": "SJTU-DENG-Lab", "fullname": "DENG Lab @ SJTU", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/64bba541da140e461924dfed/_WPqM9jCqIIkS73aTeZP-.png"}, "summary_zh": "<ul>\n    <li>\u533a\u5757\u6269\u6563\u8bed\u8a00\u6a21\u578b\uff08BD-LM\uff09\u901a\u8fc7KV\u7f13\u5b58\u548c\u7075\u6d3b\u957f\u5ea6\u751f\u6210\u6539\u8fdb\u4e86\u57fa\u4e8e\u6269\u6563\u7684\u6587\u672c\u751f\u6210\u3002</li>\n    <li>\u5c06BD-LM\u4ece\u5355\u533a\u5757\u6269\u6563\uff08SingleBD\uff09\u6269\u5c55\u5230\u591a\u533a\u5757\u6269\u6563\uff08MultiBD\uff09\uff0c\u53ef\u4ee5\u5b9e\u73b0\u533a\u5757\u95f4\u7684\u5e76\u884c\u89e3\u7801\u3002</li>\n    <li>\u63d0\u51fa\u7684\u591a\u533a\u5757\u6269\u6563\u8bed\u8a00\u6a21\u578b\uff08MBD-LM\uff09\u901a\u8fc7\u591a\u533a\u5757\u6559\u5e08\u5f3a\u8feb\uff08MultiTF\uff09\u5728\u5e72\u51c0\u524d\u7f00\u4e0a\u8bad\u7ec3\uff0c\u89e3\u51b3\u4e86\u73b0\u6709\u6a21\u578b\u7684\u8bad\u7ec3\u4e0e\u63a8\u7406\u72b6\u6001\u5dee\u5f02\u3002</li>\n    <li>\u5f15\u5165\u4e86\u4e00\u79cd\u57fa\u4e8e\u533a\u5757\u7f13\u51b2\u673a\u5236\u7684\u4f18\u5316\u89e3\u7801\u7b97\u6cd5\uff0c\u63d0\u9ad8\u4e86\u89e3\u7801\u5e76\u884c\u6027\u548c\u901f\u5ea6\u3002</li>\n    <li>\u5b9e\u9a8c\u7ed3\u679c\u663e\u793a\uff0cMBD-LLaDA2-Mini\u7684\u6bcf\u6b21\u524d\u5411\u4f20\u9012\u7684\u5e73\u5747\u4ee4\u724c\u6570\u4ece3.47\u589e\u52a0\u52306.19\uff0c\u51c6\u786e\u7387\u4ece79.95%\u63d0\u9ad8\u523081.03%\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Block Diffusion Language Models (BD-LMs) enhance text generation using caching and can generate flexible-length outputs.</li>\n    <li>The next step is to develop Multi-Block Diffusion (MultiBD) models that decode multiple blocks at once for faster processing.</li>\n    <li>Current BD-LMs are mostly trained in a way that doesn't match how MultiBD operates, so a new training method called Multi-Block Teacher Forcing (MultiTF) is introduced.</li>\n    <li>MultiTF combines two training strategies to better align with how MultiBD works and uses randomized noise for better performance.</li>\n    <li>The new MBD-LLaDA2-Mini model shows significant improvements, increasing the average tokens processed per pass and maintaining high accuracy on benchmarks.</li>\n</ul>"}, "publishedAt": "2026-06-29T20:00:00.000Z", "title": "Multi-Block Diffusion Language Models", "summary": "Block Diffusion Language Models (BD-LMs) improve diffusion-based text generation with KV caching and flexible-length generation. A natural next step is to extend them from Single-Block Diffusion (SingleBD) to Multi-Block Diffusion (MultiBD), where a running-set of consecutive blocks is decoded concurrently for inter-block parallelism. However, existing BD-LMs are mostly trained under teacher forcing, where the model observes only one noisy block conditioned on a clean prefix. While the recent diffusion forcing strategy introduces visibility among multiple noisy blocks, its training states still differ from MultiBD inference, where decoding operates on a bounded running-set with heterogeneous slot-wise noise patterns. To bridge this gap, we propose Multi-Block Diffusion Language Models (MBD-LMs), obtained by post-training BD-LMs with Multi-block Teacher Forcing (MultiTF). MultiTF integrates teacher forcing and diffusion forcing by training on bounded noise-groups conditioned on clean prefixes, with randomized noise-schedulers that better match MultiBD inference states. To make MultiBD practically executable, we further introduce an optimized decoding algorithm based on the Block Buffer mechanism that preserves prefix-cache reuse, keeps input shapes static, and translates increased decoding parallelism into wall-clock acceleration. Empirically, MBD-LLaDA2-Mini increases average Tokens Per Forward pass (TPF) from 3.47 to 6.19 and improves average accuracy from 79.95% to 81.03%; when combined with DMax, MBD-LLaDA2-Mini-DMax reaches an average TPF of 9.34 with only a 1.02% accuracy drop on math and code benchmarks.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.29215.png", "numComments": 1, "submittedBy": {"_id": "66d05337e62d6bbf50186c2f", "avatarUrl": "/avatars/f5be15e754f0fbbb37d2cc5ea417f729.svg", "fullname": "Yijie Jin", "name": "DrewJin0827", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 4, "isUserFollowing": false}, "organization": {"_id": "673d5fe8d031224e947dc235", "name": "SJTU-DENG-Lab", "fullname": "DENG Lab @ SJTU", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/64bba541da140e461924dfed/_WPqM9jCqIIkS73aTeZP-.png"}, "isAuthorParticipating": false}],
    "month": [{"paper": {"id": "2606.09967", "authors": [{"_id": "6a28c3c5e7d78ea7587e52bd", "name": "Ming Qian", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52be", "name": "Tianjian Ouyang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52bf", "name": "Mingchao Sun", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c0", "name": "Zijian Wang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c1", "name": "Jincheng Xiong", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c2", "name": "Jiarong Han", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c3", "name": "Yongchang Zhang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c4", "name": "Jiawei Zhang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c5", "name": "Xu Wang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c6", "name": "Yu Liu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c7", "name": "Luyang Tang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c8", "name": "Fei Yu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c9", "name": "Zengye Ge", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52ca", "name": "Mengmeng Du", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52cb", "name": "Yuan Liu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52cc", "name": "Nianfei Fan", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52cd", "name": "Song Wang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52ce", "name": "Yingliang Peng", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52cf", "name": "Chunxue Jia", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d0", "name": "Yang Liu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d1", "name": "Shiying Zeng", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d2", "name": "Haozhe Shi", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d3", "name": "Junnan Lai", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d4", "name": "Hongyu Pan", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d5", "name": "Zheng Wu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d6", "name": "Ning Guo", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d7", "name": "Mu Xu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d8", "name": "Hang Zhang", "hidden": false}], "publishedAt": "2026-06-08T00:00:00.000Z", "submittedOnDailyAt": "2026-06-10T00:00:00.000Z", "title": "ABot-Earth 0.5: Generative 3D Earth Model", "submittedOnDailyBy": {"_id": "6433bc32a4c9c55871a42812", "avatarUrl": "/avatars/c27c063d02419b8ba32657514c07e3b2.svg", "isPro": false, "fullname": "qian#143", "user": "qian43", "type": "user", "name": "qian43"}, "summary": "We present ABot-Earth 0.5, a generative 3D framework designed to synthesize vast, seamless 3D environments from ubiquitous, geospatially referenced satellite imagery. To achieve this, we propose a novel generative model formulated directly with the 3D Gaussian Splatting (3DGS) representation. The model is trained on a diverse corpus of existing real-world urban reconstructions, learning to generate realistic geometry and textures. At inference, it synthesizes novel 3D scenes conditioned solely on satellite imagery at a scalable rate of under 10 minutes per square kilometer, while demonstrating exceptional realism. The framework is designed for accessibility, with integrated hierarchical level-of-detail (LOD) structures that permit real-time, interactive visualization on web-based map engines. This high-fidelity simulation sandbox effectively mitigates the sim-to-real domain gap, enabling critical downstream Embodied AI applications like closed-loop UAV navigation. By providing an ultra-low-cost and high-efficiency solution, ABot-Earth 0.5 significantly lowers the technical and financial barriers to large-scale 3D reconstruction and empowers the future of global digital earth visualization.", "upvotes": 194, "discussionId": "6a28c3c5e7d78ea7587e52d9", "projectPage": "https://abot-earth.amap.com/", "githubRepo": "https://github.com/amap-cvlab/ABot-Earth-0.5", "githubRepoAddedBy": "user", "ai_summary": "ABot-Earth 0.5 generates realistic 3D environments from satellite imagery using 3D Gaussian Splatting representation, enabling fast synthesis and real-time visualization for Embodied AI applications.", "ai_keywords": ["3D Gaussian Splatting", "generative model", "satellite imagery", "3D environment synthesis", "level-of-detail", "real-time visualization", "Embodied AI", "UAV navigation", "digital earth visualization"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 109, "organization": {"_id": "641415d08900ef6afa2fcb73", "name": "acvlab", "fullname": "Alibaba AMAP CV Lab", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6414106ce7d5f817d204e160/dfveRtrRy8Xn7QpG684zl.png"}, "summary_zh": "<ul>\n    <li>ABot-Earth 0.5 \u662f\u4e00\u4e2a\u751f\u6210\u6027 3D \u6846\u67b6\uff0c\u53ef\u4ee5\u4ece\u536b\u661f\u56fe\u50cf\u5408\u6210\u65e0\u7f1d\u7684 3D \u73af\u5883\u3002</li>\n    <li>\u8be5\u6a21\u578b\u4f7f\u7528\u4e00\u79cd\u65b0\u578b\u751f\u6210\u6a21\u578b\uff0c\u80fd\u591f\u751f\u6210\u903c\u771f\u7684\u51e0\u4f55\u5f62\u72b6\u548c\u7eb9\u7406\u3002</li>\n    <li>\u7cfb\u7edf\u53ef\u4ee5\u5728\u6bcf\u5e73\u65b9\u516c\u91cc\u4e0d\u5230 10 \u5206\u949f\u7684\u65f6\u95f4\u5185\u5408\u6210\u65b0\u7684 3D \u573a\u666f\uff0c\u5e76\u4e14\u975e\u5e38\u771f\u5b9e\u3002</li>\n    <li>\u5b83\u652f\u6301\u5b9e\u65f6\u4ea4\u4e92\u53ef\u89c6\u5316\uff0c\u9002\u7528\u4e8e\u7f51\u9875\u5730\u56fe\u5f15\u64ce\u3002</li>\n    <li>ABot-Earth 0.5 \u964d\u4f4e\u4e86\u5927\u89c4\u6a21 3D \u91cd\u5efa\u7684\u6280\u672f\u548c\u8d22\u52a1\u95e8\u69db\uff0c\u63a8\u52a8\u5168\u7403\u6570\u5b57\u5730\u7403\u53ef\u89c6\u5316\u7684\u53d1\u5c55\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>ABot-Earth 0.5 is a new tool that creates realistic 3D environments using satellite images.</li>\n    <li>It uses a special model to learn from existing urban 3D designs to generate new scenes.</li>\n    <li>The tool can create 3D scenes quickly, taking less than 10 minutes per square kilometer.</li>\n    <li>It allows for real-time viewing on web maps, making it accessible and user-friendly.</li>\n    <li>ABot-Earth 0.5 helps improve AI applications, such as drones navigating in real environments.</li>\n</ul>"}, "publishedAt": "2026-06-07T20:00:00.000Z", "title": "ABot-Earth 0.5: Generative 3D Earth Model", "summary": "We present ABot-Earth 0.5, a generative 3D framework designed to synthesize vast, seamless 3D environments from ubiquitous, geospatially referenced satellite imagery. To achieve this, we propose a novel generative model formulated directly with the 3D Gaussian Splatting (3DGS) representation. The model is trained on a diverse corpus of existing real-world urban reconstructions, learning to generate realistic geometry and textures. At inference, it synthesizes novel 3D scenes conditioned solely on satellite imagery at a scalable rate of under 10 minutes per square kilometer, while demonstrating exceptional realism. The framework is designed for accessibility, with integrated hierarchical level-of-detail (LOD) structures that permit real-time, interactive visualization on web-based map engines. This high-fidelity simulation sandbox effectively mitigates the sim-to-real domain gap, enabling critical downstream Embodied AI applications like closed-loop UAV navigation. By providing an ultra-low-cost and high-efficiency solution, ABot-Earth 0.5 significantly lowers the technical and financial barriers to large-scale 3D reconstruction and empowers the future of global digital earth visualization.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.09967.png", "numComments": 3, "submittedBy": {"_id": "6433bc32a4c9c55871a42812", "avatarUrl": "/avatars/c27c063d02419b8ba32657514c07e3b2.svg", "fullname": "qian#143", "name": "qian43", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 6, "isUserFollowing": false}, "organization": {"_id": "641415d08900ef6afa2fcb73", "name": "acvlab", "fullname": "Alibaba AMAP CV Lab", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6414106ce7d5f817d204e160/dfveRtrRy8Xn7QpG684zl.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.30534", "authors": [{"_id": "6a4334fd763f63ca3757e917", "user": {"_id": "68c429ef60f075cc46cc9cff", "avatarUrl": "/avatars/21d277a1b46eabc967121a111e270cdd.svg", "isPro": false, "fullname": "yh-wang", "user": "yh-wang", "type": "user", "name": "yh-wang"}, "name": "Yihao Wang", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T09:49:27.650Z", "hidden": false}, {"_id": "6a4334fd763f63ca3757e918", "user": {"_id": "668f5478b3991ac0c3fc9c2f", "avatarUrl": "/avatars/a775853d3b88e7b1c8494ca837b5495c.svg", "isPro": false, "fullname": "yuhengji", "user": "yuheng2000", "type": "user", "name": "yuheng2000"}, "name": "Yuheng Ji", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T09:49:25.392Z", "hidden": false}, {"_id": "6a4334fd763f63ca3757e919", "user": {"_id": "668fa476cbcaf7ab0e4c58b3", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/668fa476cbcaf7ab0e4c58b3/F5Jj-nPCjU6uxZyfkY3qw.jpeg", "isPro": false, "fullname": "Mingyu Cao", "user": "cmyopu", "type": "user", "name": "cmyopu"}, "name": "Mingyu Cao", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T08:47:12.327Z", "hidden": false}, {"_id": "6a4334fd763f63ca3757e91a", "user": {"_id": "671fa0de0a34a05602094909", "avatarUrl": "/avatars/e35890e1f71a8c3f4e33b35a027e180a.svg", "isPro": false, "fullname": "Yanqing Shen", "user": "syq1105", "type": "user", "name": "syq1105"}, "name": "Yanqing Shen", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T08:47:16.531Z", "hidden": false}, {"_id": "6a4334fd763f63ca3757e91b", "name": "Runze Xiao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e91c", "user": {"_id": "67ecd5dc6b33c72fba1fc70f", "avatarUrl": "/avatars/27ff8fb1534f1d277ae03e8adc64ffba.svg", "isPro": false, "fullname": "huaihai lyu", "user": "HuaihaiLyu", "type": "user", "name": "HuaihaiLyu"}, "name": "Huaihai Lyu", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T08:47:10.262Z", "hidden": false}, {"_id": "6a4334fd763f63ca3757e91d", "user": {"_id": "643613fdaaef013d1af18717", "avatarUrl": "/avatars/b4689886eaf2103d8e92f90ea5e5bc5e.svg", "isPro": false, "fullname": "Senwei Xie", "user": "jsw19", "type": "user", "name": "jsw19"}, "name": "Senwei Xie", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T09:49:51.559Z", "hidden": false}, {"_id": "6a4334fd763f63ca3757e91e", "name": "Euan Liu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e91f", "name": "Klara Tian", "hidden": false}, {"_id": "6a4334fd763f63ca3757e920", "name": "Tianfeng Long", "hidden": false}, {"_id": "6a4334fd763f63ca3757e921", "name": "Yichi Zhang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e922", "name": "Zhengliang Cai", "hidden": false}, {"_id": "6a4334fd763f63ca3757e923", "name": "Ruike Chen", "hidden": false}, {"_id": "6a4334fd763f63ca3757e924", "name": "Jifan Zhao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e925", "name": "Ruochuan Shi", "hidden": false}, {"_id": "6a4334fd763f63ca3757e926", "user": {"_id": "65fce52cb6fa00949682d41b", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/65fce52cb6fa00949682d41b/RZ6J1Ovix-jJW9KSiWcEk.jpeg", "isPro": false, "fullname": "Zihan Tang", "user": "tzh21", "type": "user", "name": "tzh21"}, "name": "Zihan Tang", "status": "claimed_verified", "statusLastChangedAt": "2026-07-01T08:47:14.193Z", "hidden": false}, {"_id": "6a4334fd763f63ca3757e927", "name": "Jing Lyu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e928", "name": "Wenxing Tan", "hidden": false}, {"_id": "6a4334fd763f63ca3757e929", "name": "Ningbo Zhang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e92a", "name": "Yangtao Hu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e92b", "name": "Yuming Gao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e92c", "name": "Xiansheng Chen", "hidden": false}, {"_id": "6a4334fd763f63ca3757e92d", "name": "Junkai Zhao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e92e", "name": "Congsheng Xu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e92f", "name": "Boan Zhu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e930", "name": "Ziqi Wang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e931", "name": "Yupu Feng", "hidden": false}, {"_id": "6a4334fd763f63ca3757e932", "name": "Qiongqiong Zhang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e933", "name": "Yingli Zhao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e934", "name": "Yulong Ao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e935", "name": "Shaoxuan Xie", "hidden": false}, {"_id": "6a4334fd763f63ca3757e936", "name": "You Liu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e937", "name": "Guocai Yao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e938", "name": "Leiduo Zhang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e939", "name": "Xiaodan Liu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e93a", "name": "Yunyan Zhang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e93b", "name": "Yance Jiao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e93c", "name": "Xinyan Yang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e93d", "name": "Jiaxing Wei", "hidden": false}, {"_id": "6a4334fd763f63ca3757e93e", "name": "Xu Liu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e93f", "name": "Tengfei Pan", "hidden": false}, {"_id": "6a4334fd763f63ca3757e940", "name": "Shaokai Nie", "hidden": false}, {"_id": "6a4334fd763f63ca3757e941", "name": "Chunlei Men", "hidden": false}, {"_id": "6a4334fd763f63ca3757e942", "name": "Sen Cui", "hidden": false}, {"_id": "6a4334fd763f63ca3757e943", "name": "Xiaojie Jin", "hidden": false}, {"_id": "6a4334fd763f63ca3757e944", "name": "Hongyang Li", "hidden": false}, {"_id": "6a4334fd763f63ca3757e945", "name": "Jianlan Luo", "hidden": false}, {"_id": "6a4334fd763f63ca3757e946", "name": "Yao Mu", "hidden": false}, {"_id": "6a4334fd763f63ca3757e947", "name": "Yunchao Wei", "hidden": false}, {"_id": "6a4334fd763f63ca3757e948", "name": "Jun Yan", "hidden": false}, {"_id": "6a4334fd763f63ca3757e949", "name": "Hang Zhao", "hidden": false}, {"_id": "6a4334fd763f63ca3757e94a", "name": "Xiaolong Zheng", "hidden": false}, {"_id": "6a4334fd763f63ca3757e94b", "name": "Jiaming Li", "hidden": false}, {"_id": "6a4334fd763f63ca3757e94c", "name": "Yonghua Lin", "hidden": false}, {"_id": "6a4334fd763f63ca3757e94d", "name": "Tiejun Huang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e94e", "name": "Zhongyuan Wang", "hidden": false}, {"_id": "6a4334fd763f63ca3757e94f", "name": "Pengwei Wang", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/68c429ef60f075cc46cc9cff/ceZCPH1jShoRORZCEPALp.mp4"], "publishedAt": "2026-06-29T00:00:00.000Z", "submittedOnDailyAt": "2026-07-01T00:00:00.000Z", "title": "Orca: The World is in Your Mind", "submittedOnDailyBy": {"_id": "68c429ef60f075cc46cc9cff", "avatarUrl": "/avatars/21d277a1b46eabc967121a111e270cdd.svg", "isPro": false, "fullname": "yh-wang", "user": "yh-wang", "type": "user", "name": "yh-wang"}, "summary": "We introduce Orca, an initial instantiation of a general world foundation model. Orca learns a unified world latent space from multimodal world signals and exposes it through multimodal readout interfaces. Rather than optimizing isolated next-token, next-frame, or next-action prediction, we are centered on Next-State-Prediction modeling, offering a unified state-transition modeling route toward understanding, predicting, and acting upon the world. Orca learns through two complementary paradigms: unconscious learning captures dense natural state transitions from continuous videos, and conscious learning models sparse meaningful state transitions by language-described events and VQA supervision. For pre-training, we construct a large-scale world-learning inventory data, including 125K hours of video data and 160M event annotations. After pre-training, Orca learns a unified world latent space. To examine whether the learned latent supports downstream, we evaluate it by three representative downstream readouts: text generation, image prediction, and embodied action generation. Orca's backbone is frozen, and only the lightweight modality-specific decoders are trainable. Experiments show the scalability of the proposed paradigm and verify that stronger world latent enables stronger downstream readouts. Orca outperforms similar-sized specialized baselines. These results show that Orca, as a general world foundation model, presents a promising approach to understanding, predicting, and acting upon the world. Finally, we discuss the current limitations, aiming to provide useful insights and inspiration for the community.", "upvotes": 176, "discussionId": "6a4334fd763f63ca3757e950", "projectPage": "https://orca-wm.github.io/", "ai_summary": "Orca establishes a unified world latent space through next-state-prediction modeling using multimodal data and demonstrates superior performance in downstream tasks compared to specialized baselines.", "ai_keywords": ["world foundation model", "world latent space", "multimodal readout interfaces", "next-state-prediction modeling", "unconscious learning", "conscious learning", "world-learning inventory data", "embodied action generation", "downstream readouts", "modality-specific decoders"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "summary_zh": "<ul>\n    <li>Orca\u662f\u4e00\u4e2a\u901a\u7528\u7684\u4e16\u754c\u57fa\u7840\u6a21\u578b\uff0c\u901a\u8fc7\u591a\u6a21\u6001\u4fe1\u53f7\u5b66\u4e60\u7edf\u4e00\u7684\u4e16\u754c\u6f5c\u5728\u7a7a\u95f4\u3002</li>\n    <li>\u5b83\u4e13\u6ce8\u4e8e\u4e0b\u4e00\u72b6\u6001\u9884\u6d4b\u5efa\u6a21\uff0c\u800c\u4e0d\u662f\u5355\u72ec\u7684\u4e0b\u4e00\u6807\u8bb0\u6216\u4e0b\u4e00\u52a8\u4f5c\u9884\u6d4b\u3002</li>\n    <li>Orca\u901a\u8fc7\u65e0\u610f\u8bc6\u5b66\u4e60\u548c\u6709\u610f\u8bc6\u5b66\u4e60\u4e24\u79cd\u65b9\u5f0f\u8fdb\u884c\u5b66\u4e60\uff0c\u5904\u7406\u8fde\u7eed\u89c6\u9891\u548c\u8bed\u8a00\u63cf\u8ff0\u7684\u4e8b\u4ef6\u3002</li>\n    <li>\u9884\u8bad\u7ec3\u4f7f\u7528\u4e86\u5305\u62ec125K\u5c0f\u65f6\u89c6\u9891\u6570\u636e\u548c160M\u4e8b\u4ef6\u6ce8\u91ca\u7684\u5927\u89c4\u6a21\u6570\u636e\u96c6\u3002</li>\n    <li>Orca\u5728\u6587\u672c\u751f\u6210\u3001\u56fe\u50cf\u9884\u6d4b\u548c\u884c\u52a8\u751f\u6210\u7b49\u4efb\u52a1\u4e2d\u8868\u73b0\u4f18\u4e8e\u7c7b\u4f3c\u89c4\u6a21\u7684\u4e13\u4e1a\u6a21\u578b\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Orca is a new model designed to understand and predict the world by learning from various types of data, like videos and text.</li>\n    <li>It uses a method called Next-State-Prediction to model how things change in the world, rather than just predicting the next item in a sequence.</li>\n    <li>Orca learns in two ways: one involves observing continuous video for natural changes, and the other focuses on specific events described in language.</li>\n    <li>It was trained on a large dataset, including 125,000 hours of video and 160 million event descriptions, to create a unified understanding of the world.</li>\n    <li>Orca shows strong performance in generating text, predicting images, and planning actions, outperforming other specialized models.</li>\n</ul>"}, "publishedAt": "2026-06-28T20:00:00.000Z", "title": "Orca: The World is in Your Mind", "summary": "We introduce Orca, an initial instantiation of a general world foundation model. Orca learns a unified world latent space from multimodal world signals and exposes it through multimodal readout interfaces. Rather than optimizing isolated next-token, next-frame, or next-action prediction, we are centered on Next-State-Prediction modeling, offering a unified state-transition modeling route toward understanding, predicting, and acting upon the world. Orca learns through two complementary paradigms: unconscious learning captures dense natural state transitions from continuous videos, and conscious learning models sparse meaningful state transitions by language-described events and VQA supervision. For pre-training, we construct a large-scale world-learning inventory data, including 125K hours of video data and 160M event annotations. After pre-training, Orca learns a unified world latent space. To examine whether the learned latent supports downstream, we evaluate it by three representative downstream readouts: text generation, image prediction, and embodied action generation. Orca's backbone is frozen, and only the lightweight modality-specific decoders are trainable. Experiments show the scalability of the proposed paradigm and verify that stronger world latent enables stronger downstream readouts. Orca outperforms similar-sized specialized baselines. These results show that Orca, as a general world foundation model, presents a promising approach to understanding, predicting, and acting upon the world. Finally, we discuss the current limitations, aiming to provide useful insights and inspiration for the community.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/68c429ef60f075cc46cc9cff/ceZCPH1jShoRORZCEPALp.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.30534.png", "numComments": 5, "submittedBy": {"_id": "68c429ef60f075cc46cc9cff", "avatarUrl": "/avatars/21d277a1b46eabc967121a111e270cdd.svg", "fullname": "yh-wang", "name": "yh-wang", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 3, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2606.10651", "authors": [{"_id": "6a28cfb8e7d78ea7587e5406", "name": "Kwai Keye Team", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5407", "name": "Bin Wen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5408", "name": "Changyi Liu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5409", "name": "Chengru Song", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540a", "name": "Chongling Rao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540b", "name": "Guowang Zhang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540c", "name": "Han Li", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540d", "name": "Haonan Fan", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540e", "name": "Hengrui Ju", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540f", "name": "Jiankang Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5410", "name": "Jiapeng Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5411", "name": "Jiawei Yuan", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5412", "name": "Kaixuan Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5413", "name": "Kaiyu Jiang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5414", "name": "Kun Gai", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5415", "name": "Lingzhi Zhou", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5416", "name": "Na Nie", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5417", "name": "Sen Na", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5418", "name": "Tianke Zhang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5419", "name": "Tingting Gao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541a", "name": "Xuanyu Zheng", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541b", "name": "Yulong Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541c", "name": "Fan Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541d", "name": "Haixuan Gao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541e", "name": "Lele Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541f", "name": "Mingqiao Liu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5420", "name": "Muxi Diao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5421", "name": "Qi Zhang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5422", "name": "Qile Su", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5423", "name": "Wei Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5424", "name": "Wentao Hong", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5425", "name": "Xingyu Lu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5426", "name": "Yancheng Long", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5427", "name": "Yankai Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5428", "name": "Yingxin Li", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5429", "name": "Yiyang Fan", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542a", "name": "Yu Xia", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542b", "name": "Yuzhe Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542c", "name": "Ziliang Lai", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542d", "name": "Chuan Yi", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542e", "name": "Haonan Jia", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542f", "name": "Tianming Liang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5430", "name": "Weixin Xu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5431", "name": "Xiaoxiao Ma", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5432", "name": "Yang Tian", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5433", "name": "Yufei Han", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5434", "name": "Feng Han", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5435", "name": "Hang Li", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5436", "name": "Jing Wang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5437", "name": "Jinghui Jia", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5438", "name": "Junmin Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5439", "name": "Junyu Shi", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e543a", "name": "Ruilin Zhang", "hidden": false}], "publishedAt": "2026-06-09T00:00:00.000Z", "submittedOnDailyAt": "2026-06-10T00:00:00.000Z", "title": "Kwai Keye-VL-2.0 Technical Report", "submittedOnDailyBy": {"_id": "66c98c27fafc0fc87c280749", "avatarUrl": "/avatars/c71db3bee0fcd9aabcc38fd871d1cb75.svg", "isPro": false, "fullname": "Tianming Liang", "user": "liangtm", "type": "user", "name": "liangtm"}, "summary": "We introduce Kwai Keye-VL-2.0-30B-A3B, an open-source Mixture-of-Experts (MoE) multimodal foundation model designed to advance long-video understanding and agentic intelligence. To address the challenges of ultra-long contexts, information redundancy, and prohibitive computational costs inherent in hour-level videos, Keye-VL-2.0 is the first to adapt DeepSeek Sparse Attention (DSA) to GQA-based multimodal architectures, enabling lossless 256K context processing while capturing critical frames and long-range temporal dependencies. This architecture is underpinned by a highly optimized training and inference infrastructure, including scalable video I/O, heterogeneous ViT-LM parallelism, and custom DSA kernels that significantly maximize throughput and minimize computational overhead. Furthermore, to overcome the algorithmic dilemma of catastrophic forgetting during multi-task alignment, we introduce Cross-Modal Multi-Teacher On-Policy Distillation (MOPD) paired with Context-RL and Video-RL. By distilling dense token-level teacher feedback from on-policy rollouts back into the MoE backbone, which activates only 3B parameters, Keye-VL-2.0 natively empowers advanced agent collaboration across Code, Tool, and Search scenarios with multimodal self-correction. Extensive evaluations across video understanding, temporal grounding, reasoning, STEM, and agent benchmarks demonstrate that Keye-VL-2.0-30B-A3B achieves state-of-the-art performance among models of similar scale, particularly excelling in fine-grained temporal localization on TimeLens and long-video comprehension on Video-MME-v2 and LongVideoBench. We release our model checkpoints to accelerate community progress toward scalable and robust multimodal agentic applications.", "upvotes": 167, "discussionId": "6a28cfb8e7d78ea7587e543b", "projectPage": "https://kwai-keye.github.io/", "githubRepo": "https://github.com/Kwai-Keye/Keye", "githubRepoAddedBy": "user", "ai_summary": "Kwai Keye-VL-2.0-30B-A3B is an open-source Mixture-of-Experts multimodal foundation model that enables long-video understanding and agentic intelligence through DeepSeek Sparse Attention and specialized training infrastructure.", "ai_keywords": ["Mixture-of-Experts", "multimodal foundation model", "DeepSeek Sparse Attention", "GQA-based architectures", "256K context processing", "heterogeneous ViT-LM parallelism", "custom DSA kernels", "Cross-Modal Multi-Teacher On-Policy Distillation", "Context-RL", "Video-RL", "dense token-level teacher feedback", "on-policy rollouts", "agent collaboration", "Code", "Tool", "Search scenarios", "multimodal self-correction"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 785, "organization": {"_id": "685d2e9b7aa0388f4fcaf7b2", "name": "KwaiKeye", "fullname": "Kwai Keye", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/685ba798484e3233f5ff6f11/gW0pROtvsWctypxYTBbWZ.png"}, "summary_zh": "<ul>\n    <li>\u6211\u4eec\u63a8\u51fa\u4e86Kwai Keye-VL-2.0-30B-A3B\uff0c\u8fd9\u662f\u4e00\u4e2a\u5f00\u6e90\u7684\u6df7\u5408\u4e13\u5bb6\uff08MoE\uff09\u591a\u6a21\u6001\u57fa\u7840\u6a21\u578b\uff0c\u65e8\u5728\u6539\u5584\u957f\u89c6\u9891\u7406\u89e3\u548c\u667a\u80fd\u4f53\u667a\u80fd\u3002</li>\n    <li>\u8be5\u6a21\u578b\u91c7\u7528DeepSeek\u7a00\u758f\u6ce8\u610f\u529b\uff08DSA\uff09\uff0c\u80fd\u591f\u65e0\u635f\u5904\u7406256K\u4e0a\u4e0b\u6587\uff0c\u540c\u65f6\u6355\u6349\u91cd\u8981\u753b\u9762\u548c\u957f\u65f6\u95f4\u4f9d\u8d56\u5173\u7cfb\u3002</li>\n    <li>Keye-VL-2.0\u5177\u5907\u4f18\u5316\u7684\u8bad\u7ec3\u548c\u63a8\u7406\u57fa\u7840\u8bbe\u65bd\uff0c\u663e\u8457\u63d0\u9ad8\u4e86\u5904\u7406\u6548\u7387\u5e76\u964d\u4f4e\u4e86\u8ba1\u7b97\u6210\u672c\u3002</li>\n    <li>\u4e3a\u89e3\u51b3\u591a\u4efb\u52a1\u5bf9\u9f50\u65f6\u7684\u707e\u96be\u6027\u9057\u5fd8\u95ee\u9898\uff0c\u6211\u4eec\u5f15\u5165\u4e86\u8de8\u6a21\u6001\u591a\u6559\u5e08\u5728\u7ebf\u84b8\u998f\uff08MOPD\uff09\uff0c\u4fc3\u8fdb\u667a\u80fd\u4f53\u5728\u591a\u79cd\u573a\u666f\u4e0b\u7684\u534f\u4f5c\u3002</li>\n    <li>\u7ecf\u8fc7\u5e7f\u6cdb\u8bc4\u4f30\uff0cKeye-VL-2.0-30B-A3B\u5728\u89c6\u9891\u7406\u89e3\u548c\u65f6\u95f4\u5b9a\u4f4d\u7b49\u4efb\u52a1\u4e2d\u8868\u73b0\u51fa\u8272\uff0c\u5e76\u91ca\u653e\u4e86\u6a21\u578b\u68c0\u67e5\u70b9\u4ee5\u4fc3\u8fdb\u793e\u533a\u8fdb\u6b65\u3002</li>\n</ul>", "summary_simple": "<ul>\n  <li>Introducing Kwai Keye-VL-2.0-30B-A3B, a new open-source model for understanding long videos and improving intelligent agents.</li>\n  <li>The model uses advanced techniques to handle very long video contexts without losing important information, allowing it to process up to 256,000 pieces of information effectively.</li>\n  <li>It employs a special training method to prevent losing learned information when adapting to different tasks, which helps the model work better in various scenarios.</li>\n  <li>Keye-VL-2.0 shows excellent results in understanding videos and answering questions about them, outperforming similar models in tests.</li>\n  <li>The model's resources are available to the community to support the development of advanced applications that can work with multiple types of data.</li>\n</ul>"}, "publishedAt": "2026-06-08T20:00:00.000Z", "title": "Kwai Keye-VL-2.0 Technical Report", "summary": "We introduce Kwai Keye-VL-2.0-30B-A3B, an open-source Mixture-of-Experts (MoE) multimodal foundation model designed to advance long-video understanding and agentic intelligence. To address the challenges of ultra-long contexts, information redundancy, and prohibitive computational costs inherent in hour-level videos, Keye-VL-2.0 is the first to adapt DeepSeek Sparse Attention (DSA) to GQA-based multimodal architectures, enabling lossless 256K context processing while capturing critical frames and long-range temporal dependencies. This architecture is underpinned by a highly optimized training and inference infrastructure, including scalable video I/O, heterogeneous ViT-LM parallelism, and custom DSA kernels that significantly maximize throughput and minimize computational overhead. Furthermore, to overcome the algorithmic dilemma of catastrophic forgetting during multi-task alignment, we introduce Cross-Modal Multi-Teacher On-Policy Distillation (MOPD) paired with Context-RL and Video-RL. By distilling dense token-level teacher feedback from on-policy rollouts back into the MoE backbone, which activates only 3B parameters, Keye-VL-2.0 natively empowers advanced agent collaboration across Code, Tool, and Search scenarios with multimodal self-correction. Extensive evaluations across video understanding, temporal grounding, reasoning, STEM, and agent benchmarks demonstrate that Keye-VL-2.0-30B-A3B achieves state-of-the-art performance among models of similar scale, particularly excelling in fine-grained temporal localization on TimeLens and long-video comprehension on Video-MME-v2 and LongVideoBench. We release our model checkpoints to accelerate community progress toward scalable and robust multimodal agentic applications.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.10651.png", "numComments": 1, "submittedBy": {"_id": "66c98c27fafc0fc87c280749", "avatarUrl": "/avatars/c71db3bee0fcd9aabcc38fd871d1cb75.svg", "fullname": "Tianming Liang", "name": "liangtm", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2, "isUserFollowing": false}, "organization": {"_id": "685d2e9b7aa0388f4fcaf7b2", "name": "KwaiKeye", "fullname": "Kwai Keye", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/685ba798484e3233f5ff6f11/gW0pROtvsWctypxYTBbWZ.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.14777", "authors": [{"_id": "6a30c3bfa0d4daae4285fefd", "name": "Dingyu Yao", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285fefe", "name": "Junhao Zhou", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285feff", "user": {"_id": "66f4d2b62dc07e76a1dc464b", "avatarUrl": "/avatars/b1884b750a6ec46a83d247e933d59d63.svg", "isPro": false, "fullname": "steven young", "user": "iieycx", "type": "user", "name": "iieycx"}, "name": "Chenxu Yang", "status": "claimed_verified", "statusLastChangedAt": "2026-06-16T16:15:00.215Z", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff00", "name": "Chuanyu Qin", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff01", "name": "Haowen Hou", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff02", "name": "Zheming Liang", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff03", "name": "Congcong Wang", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff04", "name": "Yuhang Cao", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff05", "name": "Shenglong Ye", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff06", "name": "Shuai Xie", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff07", "name": "Shuhuan Gu", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff08", "name": "Haoyang Huang", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff09", "name": "Qingyi Si", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff0a", "name": "Nan Duan", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff0b", "user": {"_id": "64b4eec4faa3181a5eab9c46", "avatarUrl": "/avatars/bcc9bf5cbf67546ad2b4c9ec8b96ac96.svg", "isPro": true, "fullname": "Jiaqi Wang", "user": "myownskyW7", "type": "user", "name": "myownskyW7"}, "name": "Jiaqi Wang", "status": "claimed_verified", "statusLastChangedAt": "2026-06-16T12:05:58.790Z", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/66f4d2b62dc07e76a1dc464b/rPwOTrTL9yUkRzOgUfNoM.mp4", "https://cdn-uploads.huggingface.co/production/uploads/66f4d2b62dc07e76a1dc464b/BunI2wEEfCDQcodB7q3uq.mp4"], "publishedAt": "2026-06-10T00:00:00.000Z", "submittedOnDailyAt": "2026-06-16T00:00:00.000Z", "title": "JoyAI-VL-Interaction: Real-Time Vision-Language Interaction Intelligence", "submittedOnDailyBy": {"_id": "66f4d2b62dc07e76a1dc464b", "avatarUrl": "/avatars/b1884b750a6ec46a83d247e933d59d63.svg", "isPro": false, "fullname": "steven young", "user": "iieycx", "type": "user", "name": "iieycx"}, "summary": "Many moments in the real world do not wait for a user to ask. A fire starts on a security monitor, an expression flickers across a video call, or a product a viewer wants flashes by in a livestream. Yet today's large models remain mostly turn-based by design: they answer only when addressed, and even video-call apps that appear interactive still operate as question-answer systems, reacting only when polled or prompted. We argue for a different paradigm: a model that is present in the world like a person. It continuously watches what is happening now, decides on its own whether to speak or stay silent, interacts in real time, and delegates to a background model when the problem is hard. To advance interaction models and their adoption across domains, we make two fully open-sourced contributions. First, we release JoyAI-VL-Interaction, an 8B-scale, vision-first VL-interaction model. The model makes the response decision internally, choosing each second to stay silent, respond, or delegate to a background model, and it excels at vision-triggered responsiveness and time awareness. We pair it with a transferable training recipe, from which capabilities we never trained for emerge, such as guiding a shopper through changing app screens or improvising a lecture from a slide deck. Second, we release a complete, deployable system built around that model. The system streams any ongoing video into the model, making it genuinely present in the world. All other components are pluggable, including ASR/TTS modules, memory, visualization UI, and a background brain that can connect to any API or agent. Across six real-world scenarios, human raters prefer JoyAI-VL-Interaction over the in-app video-call assistants of Doubao and Gemini by a wide margin. To our knowledge, this is the first open, vision-driven interaction model released together with its training recipe, data, and complete deployable system.", "upvotes": 157, "discussionId": "6a30c3bfa0d4daae4285ff0c", "projectPage": "https://joyai-vl-video-future-academy-jd.github.io/JoyAI-VL-Interaction/", "githubRepo": "https://github.com/jd-opensource/JoyAI-VL-Interaction", "githubRepoAddedBy": "user", "ai_summary": "A vision-language model operates continuously in real-time, making autonomous decisions about when to respond or delegate, enabling interactive systems that perceive and act upon environmental changes without user prompting.", "ai_keywords": ["vision-language model", "real-time interaction", "autonomous decision-making", "vision-triggered responsiveness", "time awareness", "background model", "deployable system", "video streaming", "interactive AI", "continuous perception"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 209, "organization": {"_id": "68cb7c874f4a1865540c455c", "name": "jdopensource", "fullname": "JD.com Open Source", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/68c0e2ab44ea28a974e3074b/g-4gTubd16qUtwmGZ0n4h.png"}, "summary_zh": "<ul>\n    <li>\u73b0\u5b9e\u4e16\u754c\u4e2d\u7684\u5f88\u591a\u65f6\u523b\u4e0d\u9700\u8981\u7528\u6237\u4e3b\u52a8\u63d0\u95ee\uff0c\u6bd4\u5982\u5b89\u5168\u76d1\u63a7\u4e2d\u7684\u706b\u707e\u3001\u89c6\u9891\u901a\u8bdd\u4e2d\u7684\u8868\u60c5\u53d8\u5316\u6216\u76f4\u64ad\u4e2d\u7684\u4ea7\u54c1\u5c55\u793a\u3002</li>\n    <li>\u76ee\u524d\u7684\u5927\u578b\u6a21\u578b\u4e3b\u8981\u662f\u57fa\u4e8e\u63d0\u95ee\u7684\u8bbe\u8ba1\uff0c\u53ea\u5728\u88ab\u95ee\u5230\u65f6\u624d\u4f5c\u51fa\u53cd\u5e94\uff0c\u7f3a\u4e4f\u5b9e\u65f6\u4e92\u52a8\u80fd\u529b\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u4e00\u79cd\u65b0\u7684\u6a21\u578b\u8303\u5f0f\uff0c\u53ef\u4ee5\u50cf\u4eba\u4e00\u6837\u6301\u7eed\u89c2\u5bdf\u5468\u56f4\u73af\u5883\uff0c\u81ea\u4e3b\u51b3\u5b9a\u4f55\u65f6\u53d1\u8a00\uff0c\u5b9e\u65f6\u4e92\u52a8\u5e76\u5728\u590d\u6742\u95ee\u9898\u4e0a\u59d4\u6258\u540e\u53f0\u6a21\u578b\u3002</li>\n    <li>\u6211\u4eec\u53d1\u5e03\u4e86JoyAI-VL-Interaction\uff0c\u8fd9\u662f\u4e00\u4e2a8B\u89c4\u6a21\u7684\u89c6\u89c9\u4f18\u5148\u4ea4\u4e92\u6a21\u578b\uff0c\u80fd\u591f\u5728\u6bcf\u4e00\u79d2\u51b3\u5b9a\u4fdd\u6301\u6c89\u9ed8\u3001\u56de\u5e94\u6216\u59d4\u6258\u540e\u53f0\u6a21\u578b\u3002</li>\n    <li>\u6211\u4eec\u7684\u7cfb\u7edf\u5728\u516d\u4e2a\u771f\u5b9e\u573a\u666f\u4e2d\u8868\u73b0\u4f18\u4e8eDoubao\u548cGemini\u7684\u5e94\u7528\u5185\u89c6\u9891\u901a\u8bdd\u52a9\u624b\uff0c\u5e76\u4e14\u662f\u9996\u4e2a\u516c\u5f00\u53d1\u5e03\u7684\u89c6\u89c9\u9a71\u52a8\u4ea4\u4e92\u6a21\u578b\uff0c\u5e26\u6709\u8bad\u7ec3\u98df\u8c31\u548c\u5b8c\u6574\u7684\u53ef\u90e8\u7f72\u7cfb\u7edf\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Current AI models respond only when asked, like in video calls, but we propose a new model that acts more like a person, watching and interacting in real time.</li>\n    <li>We introduce JoyAI-VL-Interaction, a vision-first AI model that decides when to respond, stay quiet, or ask for help from another model.</li>\n    <li>This model can adapt to various tasks, like helping a shopper or giving a lecture, even without specific training for those tasks.</li>\n    <li>We also provide a complete system that streams video to the model, allowing it to be actively involved in real-world situations.</li>\n    <li>In tests, users preferred our model over existing video call assistants, marking a significant improvement in interaction quality.</li>\n</ul>"}, "publishedAt": "2026-06-09T20:00:00.000Z", "title": "JoyAI-VL-Interaction: Real-Time Vision-Language Interaction Intelligence", "summary": "Many moments in the real world do not wait for a user to ask. A fire starts on a security monitor, an expression flickers across a video call, or a product a viewer wants flashes by in a livestream. Yet today's large models remain mostly turn-based by design: they answer only when addressed, and even video-call apps that appear interactive still operate as question-answer systems, reacting only when polled or prompted. We argue for a different paradigm: a model that is present in the world like a person. It continuously watches what is happening now, decides on its own whether to speak or stay silent, interacts in real time, and delegates to a background model when the problem is hard. To advance interaction models and their adoption across domains, we make two fully open-sourced contributions. First, we release JoyAI-VL-Interaction, an 8B-scale, vision-first VL-interaction model. The model makes the response decision internally, choosing each second to stay silent, respond, or delegate to a background model, and it excels at vision-triggered responsiveness and time awareness. We pair it with a transferable training recipe, from which capabilities we never trained for emerge, such as guiding a shopper through changing app screens or improvising a lecture from a slide deck. Second, we release a complete, deployable system built around that model. The system streams any ongoing video into the model, making it genuinely present in the world. All other components are pluggable, including ASR/TTS modules, memory, visualization UI, and a background brain that can connect to any API or agent. Across six real-world scenarios, human raters prefer JoyAI-VL-Interaction over the in-app video-call assistants of Doubao and Gemini by a wide margin. To our knowledge, this is the first open, vision-driven interaction model released together with its training recipe, data, and complete deployable system.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/66f4d2b62dc07e76a1dc464b/rPwOTrTL9yUkRzOgUfNoM.mp4", "https://cdn-uploads.huggingface.co/production/uploads/66f4d2b62dc07e76a1dc464b/BunI2wEEfCDQcodB7q3uq.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.14777.png", "numComments": 2, "submittedBy": {"_id": "66f4d2b62dc07e76a1dc464b", "avatarUrl": "/avatars/b1884b750a6ec46a83d247e933d59d63.svg", "fullname": "steven young", "name": "iieycx", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2, "isUserFollowing": false}, "organization": {"_id": "68cb7c874f4a1865540c455c", "name": "jdopensource", "fullname": "JD.com Open Source", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/68c0e2ab44ea28a974e3074b/g-4gTubd16qUtwmGZ0n4h.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.28733", "authors": [{"_id": "6a43896919e14c76c1bfad0b", "name": "Han Luo", "hidden": false}, {"_id": "6a43896919e14c76c1bfad0c", "name": "Bingbing Wen", "hidden": false}, {"_id": "6a43896919e14c76c1bfad0d", "name": "Lucy Lu Wang", "hidden": false}], "publishedAt": "2026-06-27T00:00:00.000Z", "submittedOnDailyAt": "2026-06-30T00:00:00.000Z", "title": "Agentic Abstention: Do Agents Know When to Stop Instead of Act?", "submittedOnDailyBy": {"_id": "68a0606dbbcbb7c347256908", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/68a0606dbbcbb7c347256908/JuZGxOT1EHi1dn2_qf2Xz.jpeg", "isPro": false, "fullname": "Han Luo", "user": "sxcn", "type": "user", "name": "sxcn"}, "summary": "LLM agents are expected to act over multiple turns, using search, browsing interfaces, and terminal tools to complete user goals. Yet not every goal is well specified or achievable in the available environment. In such cases, a reliable agent should recognize that further interaction is unlikely to help and abstain from additional tool calls. We define Agentic Abstention, the problem of deciding when an agent should stop acting under uncertainty. Unlike standard LLM abstention, which is usually evaluated as a single-turn answer-or-abstain decision, agentic abstention is a sequential decision problem: an agent can answer, abstain, or gather more information at each turn, and the need to abstain may only become clear after interacting with the environment. We study this problem across web shopping, terminal environments, and question answering, evaluating 13 LLM-as-agent systems and 2 agent scaffolds on more than 28,000 tasks. Our results show that the main challenge is not only whether agents can abstain, but also when they abstain. Some agents never abstain when they should, while others do so only after many unnecessary interactions. This gap is especially large on tasks where the instruction appears feasible until the environment reveals otherwise (e.g., no valid result matches the instruction). We further find that model scale, reasoning, and agent scaffolding affect abstention in different ways, where larger or more capable models sometimes perform worse at timely abstention. Finally, we introduce CONVOLVE, a context engineering method for improving agentic abstention that distills full interaction trajectories into reusable stopping rules. On WebShop, CONVOLVE substantially improves timely abstention without updating model parameters, raising Llama-3.3-70B's timely recall rate from 26.7 to 57.4. Our dataset and code are available at https://lhannnn.github.io/agentic-abstention", "upvotes": 120, "discussionId": "6a43896919e14c76c1bfad0e", "projectPage": "https://lhannnn.github.io/agentic-abstention", "ai_summary": "Agentic abstention involves determining when an AI agent should cease interaction under uncertainty, requiring sequential decision-making across multiple environments and task types.", "ai_keywords": ["agentic abstention", "LLM-as-agent systems", "sequential decision problem", "web shopping", "terminal environments", "question answering", "context engineering", "CONVOLVE", "stopping rules"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "6315a1bb86b3db2ac420100e", "name": "UW", "fullname": "University of Washington", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/61ac8f8a00d01045fca0ad2f/gr5B_WVvbMr4kTox5UkwZ.jpeg"}, "summary_zh": "<ul>\n    <li>LLM\u4ee3\u7406\u9700\u8981\u5728\u591a\u8f6e\u4ea4\u4e92\u4e2d\u5b8c\u6210\u7528\u6237\u76ee\u6807\uff0c\u4f46\u6709\u4e9b\u76ee\u6807\u53ef\u80fd\u4e0d\u660e\u786e\u6216\u4e0d\u53ef\u5b9e\u73b0\u3002</li>\n    <li>\u6211\u4eec\u5b9a\u4e49\u4e86\u201c\u4ee3\u7406\u6027\u653e\u5f03\u201d\uff0c\u5373\u5728\u4e0d\u786e\u5b9a\u60c5\u51b5\u4e0b\u51b3\u5b9a\u4f55\u65f6\u505c\u6b62\u884c\u52a8\u7684\u95ee\u9898\u3002</li>\n    <li>\u7814\u7a76\u663e\u793a\uff0c\u4e0d\u540c\u7684\u4ee3\u7406\u5728\u653e\u5f03\u65f6\u8868\u73b0\u4e0d\u4e00\uff0c\u6709\u4e9b\u5728\u5e94\u8be5\u653e\u5f03\u65f6\u4ece\u4e0d\u653e\u5f03\u3002</li>\n    <li>\u6a21\u578b\u7684\u89c4\u6a21\u3001\u63a8\u7406\u80fd\u529b\u548c\u4ee3\u7406\u6846\u67b6\u5bf9\u653e\u5f03\u51b3\u7b56\u5f71\u54cd\u4e0d\u540c\uff0c\u6709\u65f6\u8f83\u5927\u6a21\u578b\u7684\u653e\u5f03\u65f6\u673a\u53cd\u800c\u8f83\u5dee\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86CONVOLVE\u65b9\u6cd5\uff0c\u53ef\u6539\u5584\u4ee3\u7406\u6027\u653e\u5f03\uff0c\u663e\u8457\u63d0\u9ad8\u653e\u5f03\u7684\u53ca\u65f6\u6027\u3002</li>\n</ul>", "summary_simple": "<ul>\n  <li>LLM agents need to make decisions over multiple interactions and sometimes should stop trying to achieve a goal if it's unclear or unachievable.</li>\n  <li>Agentic Abstention is about figuring out when an agent should stop acting, which is more complex than just answering or abstaining in one turn.</li>\n  <li>The study evaluated 13 LLM systems and 2 agent scaffolds on over 28,000 tasks, finding that many agents struggle with when to abstain appropriately.</li>\n  <li>Some agents fail to abstain when they should, while others do so after too many unnecessary actions, especially when initial instructions seem feasible.</li>\n  <li>CONVOLVE is a new method introduced to help agents improve their timely abstention by using past interactions to create stopping rules, significantly increasing performance in certain tasks.</li>\n</ul>"}, "publishedAt": "2026-06-26T20:00:00.000Z", "title": "Agentic Abstention: Do Agents Know When to Stop Instead of Act?", "summary": "LLM agents are expected to act over multiple turns, using search, browsing interfaces, and terminal tools to complete user goals. Yet not every goal is well specified or achievable in the available environment. In such cases, a reliable agent should recognize that further interaction is unlikely to help and abstain from additional tool calls. We define Agentic Abstention, the problem of deciding when an agent should stop acting under uncertainty. Unlike standard LLM abstention, which is usually evaluated as a single-turn answer-or-abstain decision, agentic abstention is a sequential decision problem: an agent can answer, abstain, or gather more information at each turn, and the need to abstain may only become clear after interacting with the environment. We study this problem across web shopping, terminal environments, and question answering, evaluating 13 LLM-as-agent systems and 2 agent scaffolds on more than 28,000 tasks. Our results show that the main challenge is not only whether agents can abstain, but also when they abstain. Some agents never abstain when they should, while others do so only after many unnecessary interactions. This gap is especially large on tasks where the instruction appears feasible until the environment reveals otherwise (e.g., no valid result matches the instruction). We further find that model scale, reasoning, and agent scaffolding affect abstention in different ways, where larger or more capable models sometimes perform worse at timely abstention. Finally, we introduce CONVOLVE, a context engineering method for improving agentic abstention that distills full interaction trajectories into reusable stopping rules. On WebShop, CONVOLVE substantially improves timely abstention without updating model parameters, raising Llama-3.3-70B's timely recall rate from 26.7 to 57.4. Our dataset and code are available at https://lhannnn.github.io/agentic-abstention", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.28733.png", "numComments": 8, "submittedBy": {"_id": "68a0606dbbcbb7c347256908", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/68a0606dbbcbb7c347256908/JuZGxOT1EHi1dn2_qf2Xz.jpeg", "fullname": "Han Luo", "name": "sxcn", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 1, "isUserFollowing": false}, "organization": {"_id": "6315a1bb86b3db2ac420100e", "name": "UW", "fullname": "University of Washington", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/61ac8f8a00d01045fca0ad2f/gr5B_WVvbMr4kTox5UkwZ.jpeg"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.18023", "authors": [{"_id": "6a3201f3bc818ff14e453d61", "name": "Jian Yang", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d62", "name": "Shawn Guo", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d63", "name": "Wei Zhang", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d64", "user": {"_id": "64ab99dcb76bfd863eba64c1", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64ab99dcb76bfd863eba64c1/UBXwDPx17X-gl-SzBPvrc.jpeg", "isPro": false, "fullname": "TY.Zheng", "user": "aaabiao", "type": "user", "name": "aaabiao"}, "name": "Tianyu Zheng", "status": "claimed_verified", "statusLastChangedAt": "2026-06-17T11:21:10.407Z", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d65", "name": "Yaxin Du", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d66", "name": "Haau-Sing Li", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d67", "user": {"_id": "66a8e2538407031e388c501f", "avatarUrl": "/avatars/d16d51f7b1e111efd6d0985995b614be.svg", "isPro": false, "fullname": "wjj", "user": "wuyuverse", "type": "user", "name": "wuyuverse"}, "name": "Jiajun Wu", "status": "claimed_verified", "statusLastChangedAt": "2026-06-17T11:21:12.507Z", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d68", "name": "Yue Song", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d69", "name": "Yan Xing", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6a", "name": "Qingsong Cai", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6b", "name": "Zelong Huang", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6c", "name": "Chuan Hao", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6d", "name": "Ran Tao", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6e", "name": "Xianglong Liu", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6f", "name": "Wayne Xin Zhao", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d70", "name": "Mingjie Tang", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d71", "name": "Weifeng Lv", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d72", "name": "Ming Zhou", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d73", "name": "Bryan Dai", "hidden": false}], "publishedAt": "2026-06-16T00:00:00.000Z", "submittedOnDailyAt": "2026-06-17T00:00:00.000Z", "title": "LoopCoder-v2: Only Loop Once for Efficient Test-Time Computation Scaling", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "Looped Transformers scale latent computation by repeatedly applying shared blocks, but sequential looping increases latency and KV-cache memory with the loop count. Parallel loop Transformers (PLT) alleviate this cost through cross-loop position offsets (CLP) and shared-KV gated sliding-window attention, making loop count a practical design choice. We therefore study PLT loop-count selection through a gain--cost view: an extra loop may refine representations, but CLP also introduces a positional mismatch at each loop boundary. We instantiate this study by training LoopCoder-v2, a family of 7B PLT coders with different loop counts, from scratch on 18T tokens, followed by matched instruction tuning and evaluation. Empirically, the two-loop variant delivers broad gains over the non-looped baseline across code generation, code reasoning, agentic software engineering, and tool-use benchmarks, improving SWE-bench Verified from 43.0 to 64.4 points and Multi-SWE from 14.0 to 31.0 points. In contrast, variants with three or more loops regress, revealing a strongly non-monotonic loop-count effect. Our diagnostics show that loop 2 provides the main productive refinement, while later loops yield diminishing, oscillatory updates and reduced representational diversity. Because the CLP-induced mismatch remains roughly fixed as refinement gains shrink, the offset cost increasingly dominates. This gain--cost trade-off explains PLT's saturation at two loops and provides diagnostics for loop-count selection.", "upvotes": 113, "discussionId": "6a3201f3bc818ff14e453d74", "ai_summary": "Parallel loop Transformers achieve better code generation performance with two loops due to refined representations, while additional loops cause diminishing returns and increased positional mismatch costs.", "ai_keywords": ["Looped Transformers", "parallel loop Transformers", "cross-loop position offsets", "shared-KV gated sliding-window attention", "loop-count selection", "LoopCoder-v2", "instruction tuning", "SWE-bench", "Multi-SWE"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "summary_zh": "<ul>\n    <li>\u5faa\u73af\u53d8\u538b\u5668\u901a\u8fc7\u91cd\u590d\u5e94\u7528\u5171\u4eab\u6a21\u5757\u6765\u63d0\u9ad8\u6f5c\u5728\u8ba1\u7b97\u80fd\u529b\uff0c\u4f46\u589e\u52a0\u5faa\u73af\u6b21\u6570\u4f1a\u589e\u52a0\u5ef6\u8fdf\u548c\u5185\u5b58\u9700\u6c42\u3002</li>\n    <li>\u5e76\u884c\u5faa\u73af\u53d8\u538b\u5668\uff08PLT\uff09\u901a\u8fc7\u4ea4\u53c9\u5faa\u73af\u4f4d\u7f6e\u504f\u79fb\u548c\u5171\u4eabKV\u95e8\u63a7\u6ed1\u52a8\u7a97\u53e3\u6ce8\u610f\u529b\u6765\u964d\u4f4e\u8fd9\u4e9b\u6210\u672c\uff0c\u4f7f\u5f97\u5faa\u73af\u6b21\u6570\u6210\u4e3a\u4e00\u79cd\u5b9e\u7528\u7684\u8bbe\u8ba1\u9009\u62e9\u3002</li>\n    <li>\u901a\u8fc7\u7814\u7a76PLT\u7684\u5faa\u73af\u6b21\u6570\u9009\u62e9\uff0c\u53d1\u73b0\u989d\u5916\u7684\u5faa\u73af\u53ef\u80fd\u4f1a\u6539\u5584\u8868\u793a\uff0c\u4f46\u4e5f\u4f1a\u5728\u6bcf\u4e2a\u5faa\u73af\u8fb9\u754c\u5f15\u5165\u4f4d\u7f6e\u4e0d\u5339\u914d\u3002</li>\n    <li>\u8bad\u7ec3\u4e86\u4e00\u4e2a\u540d\u4e3aLoopCoder-v2\u76847B PLT\u7f16\u7801\u5668\u7cfb\u5217\uff0c\u7ed3\u679c\u663e\u793a\u4e24\u4e2a\u5faa\u73af\u7684\u53d8\u4f53\u5728\u4ee3\u7801\u751f\u6210\u548c\u8f6f\u4ef6\u5de5\u7a0b\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u8868\u73b0\u826f\u597d\u3002</li>\n    <li>\u7814\u7a76\u53d1\u73b0\uff0c\u5faa\u73af\u6b21\u6570\u8d85\u8fc7\u4e24\u4e2a\u65f6\uff0c\u6548\u679c\u53cd\u800c\u4e0b\u964d\uff0c\u8bf4\u660e\u5faa\u73af\u6b21\u6570\u7684\u5f71\u54cd\u662f\u975e\u5355\u8c03\u7684\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Looped Transformers improve performance by using shared blocks repeatedly, but this can slow things down and increase memory use.</li>\n    <li>Parallel loop Transformers (PLT) reduce these issues with techniques that allow for better performance without too much extra cost.</li>\n    <li>We studied how to choose the number of loops in PLT by looking at the trade-offs between benefits and costs.</li>\n    <li>The best results came from using two loops, which improved performance significantly in tasks like code generation and software engineering.</li>\n    <li>More than two loops led to worse performance, as the benefits decreased while the costs increased, showing a clear limit to how many loops are useful.</li>\n</ul>"}, "publishedAt": "2026-06-15T20:00:00.000Z", "title": "LoopCoder-v2: Only Loop Once for Efficient Test-Time Computation Scaling", "summary": "Looped Transformers scale latent computation by repeatedly applying shared blocks, but sequential looping increases latency and KV-cache memory with the loop count. Parallel loop Transformers (PLT) alleviate this cost through cross-loop position offsets (CLP) and shared-KV gated sliding-window attention, making loop count a practical design choice. We therefore study PLT loop-count selection through a gain--cost view: an extra loop may refine representations, but CLP also introduces a positional mismatch at each loop boundary. We instantiate this study by training LoopCoder-v2, a family of 7B PLT coders with different loop counts, from scratch on 18T tokens, followed by matched instruction tuning and evaluation. Empirically, the two-loop variant delivers broad gains over the non-looped baseline across code generation, code reasoning, agentic software engineering, and tool-use benchmarks, improving SWE-bench Verified from 43.0 to 64.4 points and Multi-SWE from 14.0 to 31.0 points. In contrast, variants with three or more loops regress, revealing a strongly non-monotonic loop-count effect. Our diagnostics show that loop 2 provides the main productive refinement, while later loops yield diminishing, oscillatory updates and reduced representational diversity. Because the CLP-induced mismatch remains roughly fixed as refinement gains shrink, the offset cost increasingly dominates. This gain--cost trade-off explains PLT's saturation at two loops and provides diagnostics for loop-count selection.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.18023.png", "numComments": 3, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 319, "isUserFollowing": false}, "isAuthorParticipating": false}, {"paper": {"id": "2606.13681", "authors": [{"_id": "6a2b77ca4957fcdd3aac06a4", "user": {"_id": "67580d23f498e0436ce182fb", "avatarUrl": "/avatars/696d1c91dbd43d267747d7e98af096bd.svg", "isPro": false, "fullname": "Jundong Xu", "user": "Aiden0526", "type": "user", "name": "Aiden0526"}, "name": "Jundong Xu", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T06:56:31.093Z", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a5", "name": "Qingchuan Li", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a6", "name": "Jiaying Wu", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a7", "name": "Yihuai Lan", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a8", "name": "Shuyue Stella Li", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a9", "name": "Huichi Zhou", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06aa", "name": "Bowen Jiang", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ab", "name": "Lei Wang", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ac", "name": "Jun Wang", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ad", "name": "Anh Tuan Luu", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ae", "name": "Caiming Xiong", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06af", "name": "Hae Won Park", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06b0", "name": "Bryan Hooi", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06b1", "name": "Zhiyuan Hu", "hidden": false}], "publishedAt": "2026-06-11T00:00:00.000Z", "submittedOnDailyAt": "2026-06-12T00:00:00.000Z", "title": "EvoArena: Tracking Memory Evolution for Robust LLM Agents in Dynamic Environments", "submittedOnDailyBy": {"_id": "64351475901c5734bcb64248", "avatarUrl": "/avatars/12346d4301c1bfb00ce0ea128a93cc15.svg", "isPro": false, "fullname": "Zhiyuan Hu", "user": "zhiyuanhucs", "type": "user", "name": "zhiyuanhucs"}, "summary": "Large language model (LLM) agents have achieved strong performance on a wide range of benchmarks, yet most evaluations assume static environments. In contrast, real-world deployment is inherently dynamic, requiring agents to continually align their knowledge, skills, and behavior with changing environments and updated task conditions. To address this gap, we introduce EvoArena, a benchmark suite that models environment changes as sequences of progressive updates across terminal, software, and social domains. We further propose EvoMem, a patch-based memory paradigm that records memory evolution as structured update histories, enabling agents to reason about environmental evolution through changes in their memory. Experiments show that current agents struggle on EvoArena, achieving an average accuracy of 39.6% across evolving terminal, software, and social-preference domains. EvoMem consistently improves performance, yielding an average gain of 1.5% on EvoArena and also improving standard benchmarks such as GAIA and LoCoMo by 6.1% and 4.8%. Beyond individual tasks, EvoMem further improves chain-level accuracy by 3.7% on EvoArena, where success requires completing a consecutive sequence of related evolutionary subtasks. Mechanistic analysis shows that EvoMem improves evidence capture in the memory, indicating better preservation of complete evolving environment states. Our results highlight the importance of modeling evolution in both evaluation and memory for reliable agent deployment.", "upvotes": 104, "discussionId": "6a2b77ca4957fcdd3aac06b2", "projectPage": "https://aiden0526.github.io/EvoArena/", "githubRepo": "https://github.com/Aiden0526/EvoArena", "githubRepoAddedBy": "user", "ai_summary": "EvoArena benchmark and EvoMem memory paradigm address the challenge of dynamic environments in LLM agents by modeling progressive updates and structured memory evolution, showing improved performance on evolving tasks.", "ai_keywords": ["large language model agents", "EvoArena", "EvoMem", "memory evolution", "environment changes", "progressive updates", "terminal domain", "software domain", "social domain", "chain-level accuracy", "mechanistic analysis"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 8, "organization": {"_id": "63728bde14d543d507ae970d", "name": "MIT", "fullname": "Massachusetts Institute of Technology", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/S90qoeEJeEYaYf-c7Zs8g.png"}, "summary_zh": "<ul>\n    <li>\u5927\u578b\u8bed\u8a00\u6a21\u578b\u4ee3\u7406\u5728\u9759\u6001\u73af\u5883\u4e2d\u8868\u73b0\u826f\u597d\uff0c\u4f46\u73b0\u5b9e\u4e16\u754c\u662f\u52a8\u6001\u7684\uff0c\u9700\u8981\u9002\u5e94\u53d8\u5316\u3002</li>\n    <li>\u6211\u4eec\u4ecb\u7ecd\u4e86EvoArena\uff0c\u8fd9\u662f\u4e00\u4e2a\u6a21\u62df\u73af\u5883\u53d8\u5316\u7684\u57fa\u51c6\u5957\u4ef6\uff0c\u6db5\u76d6\u7ec8\u7aef\u3001\u8f6f\u4ef6\u548c\u793e\u4f1a\u9886\u57df\u3002</li>\n    <li>\u63d0\u51fa\u4e86EvoMem\uff0c\u8fd9\u662f\u4e00\u79cd\u57fa\u4e8e\u8865\u4e01\u7684\u8bb0\u5fc6\u6a21\u5f0f\uff0c\u8bb0\u5f55\u8bb0\u5fc6\u7684\u6f14\u53d8\uff0c\u5e2e\u52a9\u4ee3\u7406\u7406\u89e3\u73af\u5883\u53d8\u5316\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0c\u5f53\u524d\u4ee3\u7406\u5728EvoArena\u4e0a\u7684\u5e73\u5747\u51c6\u786e\u7387\u4ec5\u4e3a39.6%\uff0c\u800cEvoMem\u53ef\u63d0\u9ad81.5%\u7684\u8868\u73b0\u3002</li>\n    <li>EvoMem\u8fd8\u63d0\u9ad8\u4e86\u6807\u51c6\u57fa\u51c6\u7684\u8868\u73b0\uff0c\u5f3a\u8c03\u5728\u8bc4\u4f30\u548c\u8bb0\u5fc6\u4e2d\u5efa\u6a21\u6f14\u53d8\u7684\u91cd\u8981\u6027\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Large language model agents perform well in tests, but these tests often ignore real-world changes.</li>\n    <li>EvoArena is a new benchmark that simulates changing environments in different areas like technology and social settings.</li>\n    <li>EvoMem is a memory system that helps agents keep track of changes over time, improving their understanding of evolving situations.</li>\n    <li>Using EvoMem, agents showed a slight performance improvement in EvoArena and also did better on other standard tests.</li>\n    <li>The study emphasizes that considering changes and improving memory is crucial for deploying agents effectively in the real world.</li>\n</ul>"}, "publishedAt": "2026-06-10T20:00:00.000Z", "title": "EvoArena: Tracking Memory Evolution for Robust LLM Agents in Dynamic Environments", "summary": "Large language model (LLM) agents have achieved strong performance on a wide range of benchmarks, yet most evaluations assume static environments. In contrast, real-world deployment is inherently dynamic, requiring agents to continually align their knowledge, skills, and behavior with changing environments and updated task conditions. To address this gap, we introduce EvoArena, a benchmark suite that models environment changes as sequences of progressive updates across terminal, software, and social domains. We further propose EvoMem, a patch-based memory paradigm that records memory evolution as structured update histories, enabling agents to reason about environmental evolution through changes in their memory. Experiments show that current agents struggle on EvoArena, achieving an average accuracy of 39.6% across evolving terminal, software, and social-preference domains. EvoMem consistently improves performance, yielding an average gain of 1.5% on EvoArena and also improving standard benchmarks such as GAIA and LoCoMo by 6.1% and 4.8%. Beyond individual tasks, EvoMem further improves chain-level accuracy by 3.7% on EvoArena, where success requires completing a consecutive sequence of related evolutionary subtasks. Mechanistic analysis shows that EvoMem improves evidence capture in the memory, indicating better preservation of complete evolving environment states. Our results highlight the importance of modeling evolution in both evaluation and memory for reliable agent deployment.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.13681.png", "numComments": 1, "submittedBy": {"_id": "64351475901c5734bcb64248", "avatarUrl": "/avatars/12346d4301c1bfb00ce0ea128a93cc15.svg", "fullname": "Zhiyuan Hu", "name": "zhiyuanhucs", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 7, "isUserFollowing": false}, "organization": {"_id": "63728bde14d543d507ae970d", "name": "MIT", "fullname": "Massachusetts Institute of Technology", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/S90qoeEJeEYaYf-c7Zs8g.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.11176", "authors": [{"_id": "6a28e548e7d78ea7587e5537", "user": {"_id": "64440be5af034cdfd69ca3a7", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64440be5af034cdfd69ca3a7/qmx24QiDFT29vleCxL9TX.jpeg", "isPro": false, "fullname": "Qinghong (Kevin) Lin", "user": "KevinQHLin", "type": "user", "name": "KevinQHLin"}, "name": "Kevin Qinghong Lin", "status": "claimed_verified", "statusLastChangedAt": "2026-06-11T08:42:18.205Z", "hidden": false}, {"_id": "6a28e548e7d78ea7587e5538", "name": "Batu EI", "hidden": false}, {"_id": "6a28e548e7d78ea7587e5539", "name": "Yuhong Shi", "hidden": false}, {"_id": "6a28e548e7d78ea7587e553a", "name": "Pan Lu", "hidden": false}, {"_id": "6a28e548e7d78ea7587e553b", "name": "Philip Torr", "hidden": false}, {"_id": "6a28e548e7d78ea7587e553c", "name": "James Zou", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/64440be5af034cdfd69ca3a7/LsAABVvjGPA5Mjio-EkWd.mp4"], "publishedAt": "2026-06-09T00:00:00.000Z", "submittedOnDailyAt": "2026-06-16T00:00:00.000Z", "title": "Data Journalist Agent: Transforming Data into Verifiable Multimodal Stories", "submittedOnDailyBy": {"_id": "64440be5af034cdfd69ca3a7", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64440be5af034cdfd69ca3a7/qmx24QiDFT29vleCxL9TX.jpeg", "isPro": false, "fullname": "Qinghong (Kevin) Lin", "user": "KevinQHLin", "type": "user", "name": "KevinQHLin"}, "summary": "Data tells stories that shape society; the data journalist's job is to turn raw information into stories non-experts can trust. A high-quality news feature takes a newsroom team weeks: hunting for context, running statistics, choosing an angle, and designing visuals. Recent agents handle individual steps well: data-science agents close the analysis loop, while design agents synthesize beautiful websites. But can an agent serve as a data journalist end to end? We introduce Data Journalist Agent (Data2Story), a multi-agent framework that orchestrates specialized roles into a single virtual newsroom. Data2Story contributes two innovations. (i) Claims are evidence-grounded: an Inspector links every number, angle, and asset back to data, code, or an external reference. (ii) Articles are multimodally generative: rather than defaulting to plain text and static charts, Data2Story reasons about what readers will want to see, then deploys multimodal tools, such as interactive maps for geography and audio for music. We evaluate Data2Story on 18 articles, each paired with the originally published expert piece, along four axes: (a) human-agent angle coverage; (b) rubric evaluation with 53 participants across five dimensions; (c) computer-use agents as judges, a cost-saving proxy for how readers navigate interactive articles; and (d) verifiability, where a coding verifier re-executes statements against the data and checks claims against references. Data2Story produces competitive, evidence-traceable multimedia stories, with particular strength in transparency and auditability. Human articles retain an edge in editorial angle, creative design, and presentation. We position Data2Story as a collaborator for journalists, enabling more evidence-based, transparent, and verifiable reporting. Code and demos are available at https://data2story.github.io.", "upvotes": 100, "discussionId": "6a28e548e7d78ea7587e553d", "projectPage": "https://data2story.github.io/", "githubRepo": "https://github.com/QinghongLin/data2story-skill", "githubRepoAddedBy": "user", "ai_summary": "A multi-agent framework automates data journalism by generating evidence-grounded, multimodal news stories while maintaining transparency and verifiability.", "ai_keywords": ["multi-agent framework", "data journalism", "evidence-grounded", "multimodal generation", "verifiability", "article generation", "data storytelling"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 45, "organization": {"_id": "627bbc28fbab61b048eba8b6", "name": "Oxford", "fullname": "University of Oxford", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/68e396f2b5bb631e9b2fac9a/u0ey2LfYu6uG6iu8m_kH7.png"}, "summary_zh": "<ul>\n    <li>\u6570\u636e\u8bb2\u8ff0\u5f71\u54cd\u793e\u4f1a\uff0c\u6570\u636e\u8bb0\u8005\u7684\u5de5\u4f5c\u662f\u5c06\u539f\u59cb\u4fe1\u606f\u8f6c\u5316\u4e3a\u53ef\u4fe1\u7684\u6545\u4e8b\u3002</li>\n    <li>Data2Story\u662f\u4e00\u4e2a\u591a\u4ee3\u7406\u6846\u67b6\uff0c\u65e8\u5728\u6a21\u62df\u865a\u62df\u65b0\u95fb\u5ba4\uff0c\u6574\u5408\u4e0d\u540c\u4e13\u4e1a\u89d2\u8272\u3002</li>\n    <li>\u5b83\u7684\u4e24\u9879\u521b\u65b0\uff1a\u4e00\u662f\u5c06\u6240\u6709\u6570\u636e\u548c\u89c2\u70b9\u4e0e\u8bc1\u636e\u5173\u8054\uff0c\u4e8c\u662f\u751f\u6210\u591a\u79cd\u5f62\u5f0f\u7684\u6587\u7ae0\uff0c\u5982\u4e92\u52a8\u5730\u56fe\u548c\u97f3\u9891\u3002</li>\n    <li>\u8bc4\u4f30\u7ed3\u679c\u663e\u793a\uff0cData2Story\u80fd\u591f\u751f\u6210\u5177\u6709\u7ade\u4e89\u529b\u7684\u591a\u5a92\u4f53\u6545\u4e8b\uff0c\u4f46\u4eba\u7c7b\u8bb0\u8005\u5728\u521b\u610f\u548c\u7f16\u8f91\u89d2\u5ea6\u4e0a\u4ecd\u6709\u4f18\u52bf\u3002</li>\n    <li>Data2Story\u65e8\u5728\u6210\u4e3a\u8bb0\u8005\u7684\u5408\u4f5c\u4f19\u4f34\uff0c\u4fc3\u8fdb\u66f4\u57fa\u4e8e\u8bc1\u636e\u3001\u900f\u660e\u548c\u53ef\u9a8c\u8bc1\u7684\u62a5\u9053\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>A data journalist's role is to turn raw data into trustworthy stories for the public.</li>\n    <li>Data2Story is a new tool that combines different specialized agents to create news articles from start to finish.</li>\n    <li>It offers two key features: it connects all claims to solid evidence and produces articles with various media formats, like interactive maps and audio.</li>\n    <li>Data2Story was tested on 18 articles and showed good results in transparency and reliability, but human journalists still excel in creativity and design.</li>\n    <li>The aim of Data2Story is to assist journalists in producing better, evidence-based news stories.</li>\n</ul>"}, "publishedAt": "2026-06-08T20:00:00.000Z", "title": "Data Journalist Agent: Transforming Data into Verifiable Multimodal Stories", "summary": "Data tells stories that shape society; the data journalist's job is to turn raw information into stories non-experts can trust. A high-quality news feature takes a newsroom team weeks: hunting for context, running statistics, choosing an angle, and designing visuals. Recent agents handle individual steps well: data-science agents close the analysis loop, while design agents synthesize beautiful websites. But can an agent serve as a data journalist end to end? We introduce Data Journalist Agent (Data2Story), a multi-agent framework that orchestrates specialized roles into a single virtual newsroom. Data2Story contributes two innovations. (i) Claims are evidence-grounded: an Inspector links every number, angle, and asset back to data, code, or an external reference. (ii) Articles are multimodally generative: rather than defaulting to plain text and static charts, Data2Story reasons about what readers will want to see, then deploys multimodal tools, such as interactive maps for geography and audio for music. We evaluate Data2Story on 18 articles, each paired with the originally published expert piece, along four axes: (a) human-agent angle coverage; (b) rubric evaluation with 53 participants across five dimensions; (c) computer-use agents as judges, a cost-saving proxy for how readers navigate interactive articles; and (d) verifiability, where a coding verifier re-executes statements against the data and checks claims against references. Data2Story produces competitive, evidence-traceable multimedia stories, with particular strength in transparency and auditability. Human articles retain an edge in editorial angle, creative design, and presentation. We position Data2Story as a collaborator for journalists, enabling more evidence-based, transparent, and verifiable reporting. Code and demos are available at https://data2story.github.io.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/64440be5af034cdfd69ca3a7/LsAABVvjGPA5Mjio-EkWd.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.11176.png", "numComments": 4, "submittedBy": {"_id": "64440be5af034cdfd69ca3a7", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64440be5af034cdfd69ca3a7/qmx24QiDFT29vleCxL9TX.jpeg", "fullname": "Qinghong (Kevin) Lin", "name": "KevinQHLin", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 49, "isUserFollowing": false}, "organization": {"_id": "627bbc28fbab61b048eba8b6", "name": "Oxford", "fullname": "University of Oxford", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/68e396f2b5bb631e9b2fac9a/u0ey2LfYu6uG6iu8m_kH7.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.07297", "authors": [{"_id": "6a26b590e4c258a0294923e5", "user": {"_id": "65db54e5ab2f64915c0b9cf0", "avatarUrl": "/avatars/d451523cad8c17cda603eea2961c50ad.svg", "isPro": false, "fullname": "Shaoqiu Zhang", "user": "qiushao", "type": "user", "name": "qiushao"}, "name": "Shaoqiu Zhang", "status": "claimed_verified", "statusLastChangedAt": "2026-06-09T12:45:33.488Z", "hidden": false}, {"_id": "6a26b590e4c258a0294923e6", "name": "Yuhang Wang", "hidden": false}, {"_id": "6a26b590e4c258a0294923e7", "name": "Jialiang Liang", "hidden": false}, {"_id": "6a26b590e4c258a0294923e8", "user": {"_id": "645b0c3ec35da9c7afd95421", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/645b0c3ec35da9c7afd95421/vYBrCDagHsXAo6J2p-uG0.jpeg", "isPro": false, "fullname": "Yuling", "user": "YerbaPage", "type": "user", "name": "YerbaPage"}, "name": "Yuling Shi", "status": "claimed_verified", "statusLastChangedAt": "2026-06-09T12:45:35.921Z", "hidden": false}, {"_id": "6a26b590e4c258a0294923e9", "name": "Wenhao Zeng", "hidden": false}, {"_id": "6a26b590e4c258a0294923ea", "name": "Maoquan Wang", "hidden": false}, {"_id": "6a26b590e4c258a0294923eb", "name": "Shilin He", "hidden": false}, {"_id": "6a26b590e4c258a0294923ec", "name": "Ningyuan Xu", "hidden": false}, {"_id": "6a26b590e4c258a0294923ed", "name": "Siyu Ye", "hidden": false}, {"_id": "6a26b590e4c258a0294923ee", "name": "Kai Cai", "hidden": false}, {"_id": "6a26b590e4c258a0294923ef", "name": "Xiaodong Gu", "hidden": false}], "publishedAt": "2026-06-05T00:00:00.000Z", "submittedOnDailyAt": "2026-06-09T00:00:00.000Z", "title": "SWE-Explore: Benchmarking How Coding Agents Explore Repositories", "submittedOnDailyBy": {"_id": "645b0c3ec35da9c7afd95421", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/645b0c3ec35da9c7afd95421/vYBrCDagHsXAo6J2p-uG0.jpeg", "isPro": false, "fullname": "Yuling", "user": "YerbaPage", "type": "user", "name": "YerbaPage"}, "summary": "Repository-level coding benchmarks such as SWE-bench have driven a rapid surge in the capabilities of coding agents. Yet they usually treat coding tasks as a holistic, binary prediction problem (e.g., resolved or unresolved), neglecting fine-grained agent capabilities such as repository understanding, context retrieval, code localization, and bug diagnosis. In this paper, we introduce SWE-Explore, a benchmark that isolates the evaluation of repository exploration, a critical capability of coding agents. Given a repository and an issue, SWE-Explore asks an explorer to return a ranked list of relevant code regions under a fixed line budget. SWE-Explore covers 848 issues across 10 programming languages and 203 open-source repositories. For each instance, we derive line-level ground truth from independent agent trajectories that successfully solved the same issue, distilling the specific code regions their solution paths actually consulted. We evaluate exploration along coverage, ranking, and context-efficiency dimensions, showing that these metrics strongly track downstream repair behavior. Across a broad set of retrieval methods, general coding agents, and specialized localizers, we find that agentic explorers form a clear tier above classical retrieval. While file-level localization is already strong for modern methods, line-level coverage and efficient ranking remain the key axes differentiating state-of-the-art explorers.", "upvotes": 98, "discussionId": "6a26b590e4c258a0294923f0", "projectPage": "https://huggingface.co/datasets/SWE-Explore-Bench/SWE-Explore-Bench", "githubRepo": "https://github.com/Qiushao-E/SWE-Explore-Bench", "githubRepoAddedBy": "user", "ai_summary": "SWE-Explore introduces a benchmark for evaluating coding agents' repository exploration capabilities by requiring ranked lists of relevant code regions within line budgets, demonstrating that agentic exploration outperforms traditional retrieval methods.", "ai_keywords": ["repository exploration", "coding agents", "SWE-bench", "SWE-Explore", "line budget", "code localization", "context retrieval", "repository understanding", "bug diagnosis", "retrieval methods", "agentic explorers", "line-level coverage", "ranking", "context-efficiency"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 13, "organization": {"_id": "63e5ef7bf2e9a8f22c515654", "name": "SJTU", "fullname": "Shanghai Jiao Tong University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1676013394657-63e5ee22b6a40bf941da0928.png"}, "summary_zh": "<ul>\n    <li>\u63d0\u51fa\u4e86SWE-Explore\u57fa\u51c6\uff0c\u4e13\u6ce8\u4e8e\u8bc4\u4f30\u7f16\u7801\u4ee3\u7406\u7684\u5b58\u50a8\u5e93\u63a2\u7d22\u80fd\u529b\u3002</li>\n    <li>SWE-Explore\u8981\u6c42\u4ee3\u7406\u6839\u636e\u95ee\u9898\u8fd4\u56de\u76f8\u5173\u4ee3\u7801\u533a\u57df\u7684\u6392\u540d\u5217\u8868\u3002</li>\n    <li>\u8be5\u57fa\u51c6\u6db5\u76d610\u79cd\u7f16\u7a0b\u8bed\u8a00\u548c203\u4e2a\u5f00\u6e90\u5b58\u50a8\u5e93\u7684848\u4e2a\u95ee\u9898\u3002</li>\n    <li>\u901a\u8fc7\u5206\u6790\u6210\u529f\u89e3\u51b3\u95ee\u9898\u7684\u4ee3\u7406\u8def\u5f84\uff0c\u63d0\u53d6\u4e86\u5177\u4f53\u7684\u4ee3\u7801\u533a\u57df\u4f5c\u4e3a\u8bc4\u4f30\u6807\u51c6\u3002</li>\n    <li>\u7ed3\u679c\u663e\u793a\uff0c\u4ee3\u7406\u63a2\u7d22\u8005\u5728\u8986\u76d6\u7387\u3001\u6392\u540d\u548c\u4e0a\u4e0b\u6587\u6548\u7387\u65b9\u9762\u4f18\u4e8e\u4f20\u7edf\u7684\u68c0\u7d22\u65b9\u6cd5\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>The paper presents SWE-Explore, a new benchmark to evaluate how well coding agents can explore code repositories.</li>\n    <li>SWE-Explore focuses on specific skills like understanding the repository, finding context, and diagnosing bugs, rather than just solving coding problems.</li>\n    <li>The benchmark includes 848 issues from 10 programming languages and 203 open-source repositories.</li>\n    <li>It measures how well coding agents can return relevant code sections while staying within a set limit of lines.</li>\n    <li>The study finds that specialized coding agents perform significantly better than traditional retrieval methods, especially in terms of line-level coverage and efficient ranking.</li>\n</ul>"}, "publishedAt": "2026-06-04T20:00:00.000Z", "title": "SWE-Explore: Benchmarking How Coding Agents Explore Repositories", "summary": "Repository-level coding benchmarks such as SWE-bench have driven a rapid surge in the capabilities of coding agents. Yet they usually treat coding tasks as a holistic, binary prediction problem (e.g., resolved or unresolved), neglecting fine-grained agent capabilities such as repository understanding, context retrieval, code localization, and bug diagnosis. In this paper, we introduce SWE-Explore, a benchmark that isolates the evaluation of repository exploration, a critical capability of coding agents. Given a repository and an issue, SWE-Explore asks an explorer to return a ranked list of relevant code regions under a fixed line budget. SWE-Explore covers 848 issues across 10 programming languages and 203 open-source repositories. For each instance, we derive line-level ground truth from independent agent trajectories that successfully solved the same issue, distilling the specific code regions their solution paths actually consulted. We evaluate exploration along coverage, ranking, and context-efficiency dimensions, showing that these metrics strongly track downstream repair behavior. Across a broad set of retrieval methods, general coding agents, and specialized localizers, we find that agentic explorers form a clear tier above classical retrieval. While file-level localization is already strong for modern methods, line-level coverage and efficient ranking remain the key axes differentiating state-of-the-art explorers.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.07297.png", "numComments": 1, "submittedBy": {"_id": "645b0c3ec35da9c7afd95421", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/645b0c3ec35da9c7afd95421/vYBrCDagHsXAo6J2p-uG0.jpeg", "fullname": "Yuling", "name": "YerbaPage", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 105, "isUserFollowing": false}, "organization": {"_id": "63e5ef7bf2e9a8f22c515654", "name": "SJTU", "fullname": "Shanghai Jiao Tong University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1676013394657-63e5ee22b6a40bf941da0928.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.19195", "authors": [{"_id": "6a3407a3fc3a8b1102d9442a", "user": {"_id": "66d0ba2420e64fc408564bbb", "avatarUrl": "/avatars/355566cfb6347750a5faab7c87fcb79c.svg", "isPro": false, "fullname": "Anduin Dan", "user": "AnduinD", "type": "user", "name": "AnduinD"}, "name": "Kangsheng Duan", "status": "claimed_verified", "statusLastChangedAt": "2026-06-19T14:20:45.706Z", "hidden": false}, {"_id": "6a3407a3fc3a8b1102d9442b", "user": {"_id": "633d4630e1aec4b8b33ad5b8", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/633d4630e1aec4b8b33ad5b8/owFqnyCMW8yuo9VcjA1hx.jpeg", "isPro": false, "fullname": "Ziyang Xu", "user": "Uyoung", "type": "user", "name": "Uyoung"}, "name": "Ziyang Xu", "status": "claimed_verified", "statusLastChangedAt": "2026-06-19T14:20:28.418Z", "hidden": false}, {"_id": "6a3407a3fc3a8b1102d9442c", "name": "Wenyu Liu", "hidden": false}, {"_id": "6a3407a3fc3a8b1102d9442d", "name": "Xiaohu Ruan", "hidden": false}, {"_id": "6a3407a3fc3a8b1102d9442e", "name": "Xiaoxin Chen", "hidden": false}, {"_id": "6a3407a3fc3a8b1102d9442f", "name": "Xinggang Wang", "hidden": false}], "publishedAt": "2026-06-17T00:00:00.000Z", "submittedOnDailyAt": "2026-06-19T00:00:00.000Z", "title": "Moebius: 0.2B Lightweight Image Inpainting Framework with 10B-Level Performance", "submittedOnDailyBy": {"_id": "633d4630e1aec4b8b33ad5b8", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/633d4630e1aec4b8b33ad5b8/owFqnyCMW8yuo9VcjA1hx.jpeg", "isPro": false, "fullname": "Ziyang Xu", "user": "Uyoung", "type": "user", "name": "Uyoung"}, "summary": "While 10B-level industrial foundation models have pushed the boundaries of image inpainting, their prohibitive computational costs severely hinder practical deployment. Constructing a highly optimized task-specific specialist offers a promising solution; however, extreme structural compression inevitably triggers a severe representation bottleneck. To conquer this, we propose Moebius, a highly efficient lightweight inpainting framework. We systematically reconstruct the diffusion backbone by introducing the Local-\u03bb Mix Interaction (L\u03bbMI) block. Comprising Local-\u03bb and Interactive-\u03bb modules, it elegantly summarizes spatial contexts and global semantic priors into fixed-size linear matrices, preserving complex latent interactions while drastically shedding parameters. Furthermore, to unlock the full representational capacity of this highly compact architecture, we synergistically pair it with an adaptive multi-granularity distillation strategy. Operating strictly within the latent space to avoid expensive pixel-space decoding, this strategy dynamically balances multiple gradient-based losses to achieve high-fidelity alignment. Extensive experiments across natural and portrait benchmarks demonstrate that this optimal synergy enables Moebius to rival or even surpass the generation quality of the 10B-level industrial generalist FLUX.1-Fill-Dev. Remarkably, Moebius achieves this using less than 2\\% of the parameters (0.22B vs. 11.9B) while delivering a >15times acceleration in total inference time, setting a new efficiency standard for high-fidelity inpainting. Project page at https://hustvl.github.io/Moebius.", "upvotes": 97, "discussionId": "6a3407a3fc3a8b1102d94430", "projectPage": "https://hustvl.github.io/Moebius", "githubRepo": "https://github.com/hustvl/Moebius", "githubRepoAddedBy": "user", "ai_summary": "A lightweight image inpainting framework achieves high-fidelity results with significantly reduced parameters and inference time through novel local-global interaction blocks and adaptive distillation strategies.", "ai_keywords": ["diffusion backbone", "Local-\u03bb Mix Interaction", "L\u03bbMI block", "spatial contexts", "global semantic priors", "fixed-size linear matrices", "representation bottleneck", "adaptive multi-granularity distillation", "latent space", "gradient-based losses", "high-fidelity inpainting", "parameter-efficient fine-tuning"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 52, "summary_zh": "<ul>\n    <li>Moebius\u662f\u4e00\u4e2a\u9ad8\u6548\u7684\u8f7b\u91cf\u7ea7\u56fe\u50cf\u4fee\u590d\u6846\u67b6\uff0c\u65e8\u5728\u964d\u4f4e\u8ba1\u7b97\u6210\u672c\u3002</li>\n    <li>\u901a\u8fc7\u5f15\u5165Local-\u03bb Mix Interaction (L\u03bbMI)\u6a21\u5757\uff0cMoebius\u80fd\u591f\u6709\u6548\u5730\u603b\u7ed3\u7a7a\u95f4\u4e0a\u4e0b\u6587\u548c\u5168\u5c40\u8bed\u4e49\u4fe1\u606f\u3002</li>\n    <li>\u8be5\u6846\u67b6\u4f7f\u7528\u9002\u5e94\u6027\u7684\u591a\u7c92\u5ea6\u84b8\u998f\u7b56\u7565\uff0c\u4ee5\u63d0\u9ad8\u5176\u8868\u73b0\u80fd\u529b\uff0c\u907f\u514d\u6602\u8d35\u7684\u50cf\u7d20\u7a7a\u95f4\u89e3\u7801\u3002</li>\n    <li>Moebius\u5728\u81ea\u7136\u548c\u4eba\u50cf\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u8868\u73b0\u51fa\u8272\uff0c\u751f\u6210\u8d28\u91cf\u53ef\u4e0e\u5927\u578b\u6a21\u578bFLUX.1-Fill-Dev\u76f8\u5ab2\u7f8e\u3002</li>\n    <li>Moebius\u7684\u53c2\u6570\u91cf\u4e0d\u52302%\uff0c\u4e14\u63a8\u7406\u901f\u5ea6\u6bd4\u4f20\u7edf\u6a21\u578b\u5feb\u8d85\u8fc715\u500d\uff0c\u6811\u7acb\u4e86\u9ad8\u4fdd\u771f\u56fe\u50cf\u4fee\u590d\u7684\u65b0\u6807\u51c6\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Moebius is a lightweight framework for image inpainting that improves efficiency while maintaining high quality.</li>\n    <li>It uses a new Local-\u03bb Mix Interaction (L\u03bbMI) block to summarize important information while reducing the number of parameters.</li>\n    <li>The framework pairs with a special strategy to optimize performance without expensive processing, focusing on key features in the data.</li>\n    <li>Moebius can achieve image quality comparable to larger models while using less than 2% of their parameters and speeding up processing time by over 15 times.</li>\n    <li>Overall, Moebius sets a new standard for effective and efficient high-quality image inpainting.</li>\n</ul>"}, "publishedAt": "2026-06-16T20:00:00.000Z", "title": "Moebius: 0.2B Lightweight Image Inpainting Framework with 10B-Level Performance", "summary": "While 10B-level industrial foundation models have pushed the boundaries of image inpainting, their prohibitive computational costs severely hinder practical deployment. Constructing a highly optimized task-specific specialist offers a promising solution; however, extreme structural compression inevitably triggers a severe representation bottleneck. To conquer this, we propose Moebius, a highly efficient lightweight inpainting framework. We systematically reconstruct the diffusion backbone by introducing the Local-\u03bb Mix Interaction (L\u03bbMI) block. Comprising Local-\u03bb and Interactive-\u03bb modules, it elegantly summarizes spatial contexts and global semantic priors into fixed-size linear matrices, preserving complex latent interactions while drastically shedding parameters. Furthermore, to unlock the full representational capacity of this highly compact architecture, we synergistically pair it with an adaptive multi-granularity distillation strategy. Operating strictly within the latent space to avoid expensive pixel-space decoding, this strategy dynamically balances multiple gradient-based losses to achieve high-fidelity alignment. Extensive experiments across natural and portrait benchmarks demonstrate that this optimal synergy enables Moebius to rival or even surpass the generation quality of the 10B-level industrial generalist FLUX.1-Fill-Dev. Remarkably, Moebius achieves this using less than 2\\% of the parameters (0.22B vs. 11.9B) while delivering a >15times acceleration in total inference time, setting a new efficiency standard for high-fidelity inpainting. Project page at https://hustvl.github.io/Moebius.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.19195.png", "numComments": 4, "submittedBy": {"_id": "633d4630e1aec4b8b33ad5b8", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/633d4630e1aec4b8b33ad5b8/owFqnyCMW8yuo9VcjA1hx.jpeg", "fullname": "Ziyang Xu", "name": "Uyoung", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 7, "isUserFollowing": false}, "isAuthorParticipating": true}]
};
